/**
 * Centralized mock factories for Firebase Functions unit tests.
 *
 * Usage:
 *   import { createMockFirestore, createMockRequest, mockFetch } from "./mocks";
 */

/* ---------- Firestore Mock ---------- */

export interface MockDocSnap {
  exists: boolean;
  id: string;
  ref: { parent: { parent: { id: string } | null }; delete: jest.Mock };
  data: () => Record<string, unknown> | undefined;
}

export interface MockQuerySnap {
  empty: boolean;
  size: number;
  docs: MockDocSnap[];
  forEach: (cb: (doc: MockDocSnap) => void) => void;
}

export function createDocSnap(
  id: string,
  data: Record<string, unknown> | undefined,
  parentUserId?: string,
): MockDocSnap {
  return {
    exists: data !== undefined,
    id,
    ref: {
      parent: { parent: parentUserId ? { id: parentUserId } : null },
      delete: jest.fn(),
    },
    data: () => data,
  };
}

export function createQuerySnap(docs: MockDocSnap[]): MockQuerySnap {
  return {
    empty: docs.length === 0,
    size: docs.length,
    docs,
    forEach: (cb: (doc: MockDocSnap) => void) => docs.forEach(cb),
  };
}

export interface MockFirestore {
  collection: jest.Mock;
  collectionGroup: jest.Mock;
  batch: jest.Mock;
  runTransaction: jest.Mock;
  // Internal tracking helpers
  _docs: Map<string, MockDocSnap>;
  _setDoc: (path: string, snap: MockDocSnap) => void;
}

/**
 * Creates a mock Firestore instance.
 *
 * `docResults` maps "collection/docId" → data object (or undefined for non-existent).
 * `queryResults` maps "collection" → array of doc snapshots for `.get()` on queries.
 */
export function createMockFirestore(
  docResults: Record<string, Record<string, unknown> | undefined> = {},
  queryResults: Record<string, MockDocSnap[]> = {},
): MockFirestore {
  const _docs = new Map<string, MockDocSnap>();

  // Populate _docs
  for (const [path, data] of Object.entries(docResults)) {
    const parts = path.split("/");
    const id = parts[parts.length - 1];
    _docs.set(path, createDocSnap(id, data));
  }

  const mockUpdate = jest.fn().mockResolvedValue(undefined);
  const mockSet = jest.fn().mockResolvedValue(undefined);
  const mockAdd = jest.fn().mockImplementation(() =>
    Promise.resolve({ id: "generated-id-" + Math.random().toString(36).slice(2, 8) }),
  );
  const mockDelete = jest.fn();

  const mockDoc = jest.fn().mockImplementation((docId: string) => {
    // Try to find a matching doc from any collection path
    const matchingKey = Array.from(_docs.keys()).find((k) => k.endsWith("/" + docId));
    const snap = matchingKey ? _docs.get(matchingKey) : createDocSnap(docId, undefined);

    return {
      id: docId,
      get: jest.fn().mockResolvedValue(snap),
      set: mockSet,
      update: mockUpdate,
      delete: mockDelete,
      collection: (subCol: string) => ({
        doc: (subDocId?: string) => {
          const subPath = subCol + "/" + (subDocId || "auto-id");
          const subSnap = _docs.get(subPath) || createDocSnap(subDocId || "auto-id", undefined);
          return {
            id: subDocId || "auto-id",
            get: jest.fn().mockResolvedValue(subSnap),
            set: mockSet,
            update: mockUpdate,
            delete: mockDelete,
          };
        },
        get: jest.fn().mockResolvedValue(
          createQuerySnap(queryResults[subCol] || []),
        ),
        add: mockAdd,
      }),
    };
  });

  const mockWhere = jest.fn().mockReturnThis();
  const mockLimit = jest.fn().mockReturnThis();

  const mockCollection = jest.fn().mockImplementation((_colName: string) => ({
    doc: mockDoc,
    add: mockAdd,
    where: mockWhere,
    limit: mockLimit,
    get: jest.fn().mockResolvedValue(
      createQuerySnap(queryResults[_colName] || []),
    ),
  }));

  const mockCollectionGroup = jest.fn().mockImplementation((_groupName: string) => ({
    where: mockWhere,
    get: jest.fn().mockResolvedValue(
      createQuerySnap(queryResults[_groupName] || []),
    ),
  }));

  const mockBatchUpdate = jest.fn();
  const mockBatchSet = jest.fn();
  const mockBatchDelete = jest.fn();
  const mockBatchCommit = jest.fn().mockResolvedValue(undefined);
  const mockBatch = jest.fn().mockReturnValue({
    update: mockBatchUpdate,
    set: mockBatchSet,
    delete: mockBatchDelete,
    commit: mockBatchCommit,
  });

  const mockTransaction = {
    get: jest.fn().mockImplementation((ref: { id: string }) => {
      const matchingKey = Array.from(_docs.keys()).find((k) => k.endsWith("/" + ref.id));
      return Promise.resolve(
        matchingKey ? _docs.get(matchingKey) : createDocSnap(ref.id, undefined),
      );
    }),
    set: jest.fn(),
    update: jest.fn(),
    delete: jest.fn(),
  };

  const mockRunTransaction = jest.fn().mockImplementation(
    (fn: (t: typeof mockTransaction) => Promise<unknown>) => fn(mockTransaction),
  );

  const db: MockFirestore = {
    collection: mockCollection,
    collectionGroup: mockCollectionGroup,
    batch: mockBatch,
    runTransaction: mockRunTransaction,
    _docs,
    _setDoc: (path: string, snap: MockDocSnap) => _docs.set(path, snap),
  };

  return db;
}

/* ---------- Auth Mock ---------- */

export function createMockAuth() {
  return {
    setCustomUserClaims: jest.fn().mockResolvedValue(undefined),
    deleteUser: jest.fn().mockResolvedValue(undefined),
    updateUser: jest.fn().mockResolvedValue(undefined),
  };
}

/* ---------- Request Mock ---------- */

export interface MockCallableRequest {
  auth?: {
    uid: string;
    token: Record<string, unknown>;
  };
  data: Record<string, unknown>;
}

export function createMockRequest(
  data: Record<string, unknown>,
  uid?: string,
  tokenOverrides: Record<string, unknown> = {},
): MockCallableRequest {
  if (!uid) {
    return { data };
  }
  return {
    auth: {
      uid,
      token: { email: `${uid}@test.com`, ...tokenOverrides },
    },
    data,
  };
}

/* ---------- Fetch Mock ---------- */

export function mockFetch(responseData: unknown = { data: [] }, ok = true) {
  const fn = jest.fn().mockResolvedValue({
    ok,
    json: () => Promise.resolve(responseData),
    text: () => Promise.resolve(JSON.stringify(responseData)),
  });
  global.fetch = fn as unknown as typeof fetch;
  return fn;
}

/* ---------- FieldValue Stubs ---------- */

export const mockFieldValue = {
  serverTimestamp: jest.fn().mockReturnValue("SERVER_TIMESTAMP"),
  increment: jest.fn().mockImplementation((n: number) => `INCREMENT(${n})`),
  delete: jest.fn().mockReturnValue("DELETE"),
};

export const mockTimestamp = {
  now: jest.fn().mockReturnValue({
    seconds: Math.floor(Date.now() / 1000),
    nanoseconds: 0,
    toDate: () => new Date(),
  }),
  fromDate: jest.fn().mockImplementation((d: Date) => ({
    seconds: Math.floor(d.getTime() / 1000),
    nanoseconds: 0,
    toDate: () => d,
  })),
};

/* eslint-disable @typescript-eslint/no-explicit-any */
import {
  createMockAuth,
  createMockFirestore,
  createMockRequest,
  mockFieldValue,
  MockFirestore,
} from "./mocks";

// ── Module mocks ───────────────────────────────────────────────────
const mockDb: { current: MockFirestore } = { current: null as any };
const mockAuth = createMockAuth();

jest.mock("firebase-admin/firestore", () => ({
  getFirestore: () => mockDb.current,
  FieldValue: {
    serverTimestamp: () => mockFieldValue.serverTimestamp(),
    increment: (n: number) => mockFieldValue.increment(n),
  },
}));

jest.mock("firebase-admin", () => ({
  auth: () => mockAuth,
  firestore: {
    FieldValue: {
      serverTimestamp: () => mockFieldValue.serverTimestamp(),
    },
  },
}));

jest.mock("firebase-functions/v2", () => ({
  https: {
    onCall: (_opts: any, handler: any) => handler,
    HttpsError: class HttpsError extends Error {
      code: string;
      constructor(code: string, message: string) {
        super(message);
        this.code = code;
        this.name = "HttpsError";
      }
    },
  },
}));

jest.mock("../helpers", () => {
  const actual = jest.requireActual("../helpers");
  return {
    ...actual,
    mergeGuestData: jest.fn().mockResolvedValue(undefined),
  };
});

import { onboardUser } from "../callable/onboardUser";
import * as helpers from "../helpers";

// ── Tests ──────────────────────────────────────────────────────────
describe("onboardUser", () => {
  beforeEach(() => {
    jest.clearAllMocks();
    mockDb.current = createMockFirestore();
  });

  it("rejects unauthenticated calls", async () => {
    const req = createMockRequest({ role: "customer" });
    await expect((onboardUser as any)(req)).rejects.toThrow("authenticated");
  });

  it("rejects invalid role", async () => {
    const req = createMockRequest({ role: "admin" }, "user-001");
    await expect((onboardUser as any)(req)).rejects.toThrow("merchant");
  });

  it("sets custom claims for customer role", async () => {
    const req = createMockRequest(
      { role: "customer", firstName: "John", lastName: "Doe" },
      "user-001",
    );
    const result = await (onboardUser as any)(req);
    expect(result.success).toBe(true);
    expect(result.role).toBe("customer");
    expect(mockAuth.setCustomUserClaims).toHaveBeenCalledWith("user-001", { role: "customer" });
  });

  it("sets custom claims for merchant role", async () => {
    const req = createMockRequest(
      { role: "merchant", businessName: "Test Shop" },
      "user-002",
    );
    const result = await (onboardUser as any)(req);
    expect(result.success).toBe(true);
    expect(result.role).toBe("merchant");
    expect(mockAuth.setCustomUserClaims).toHaveBeenCalledWith("user-002", { role: "merchant" });
  });

  it("creates Firestore user document", async () => {
    const req = createMockRequest(
      { role: "customer", firstName: "John", lastName: "Doe" },
      "user-001",
    );
    await (onboardUser as any)(req);

    // Verify collection("users").doc("user-001").set was called
    const collection = mockDb.current.collection;
    expect(collection).toHaveBeenCalledWith("users");
  });

  it("calls mergeGuestData when phone number is provided", async () => {
    const req = createMockRequest(
      { role: "customer", firstName: "Jane", lastName: "Smith", phoneNumber: "0821234567" },
      "user-003",
    );
    await (onboardUser as any)(req);
    expect(helpers.mergeGuestData).toHaveBeenCalledWith(
      expect.anything(),
      "user-003",
      "0821234567",
    );
  });

  it("does not call mergeGuestData when phone number is missing", async () => {
    const req = createMockRequest(
      { role: "customer", firstName: "Jane", lastName: "Smith" },
      "user-003",
    );
    await (onboardUser as any)(req);
    expect(helpers.mergeGuestData).not.toHaveBeenCalled();
  });

  it("preserves existing role when user already exists", async () => {
    // Seed Firestore with an existing customer user
    mockDb.current = createMockFirestore({
      "users/user-existing": { role: "customer", email: "user-existing@test.com" },
    });

    // Attempt to onboard as merchant with the same uid
    const req = createMockRequest(
      { role: "merchant", businessName: "New Shop" },
      "user-existing",
    );
    const result = await (onboardUser as any)(req);

    // Should return the EXISTING role, not the requested one
    expect(result.success).toBe(true);
    expect(result.role).toBe("customer");

    // Claims should be set to the existing role
    expect(mockAuth.setCustomUserClaims).toHaveBeenCalledWith("user-existing", { role: "customer" });

    // Firestore set() should NOT have been called (no doc overwrite)
    const docMock = mockDb.current.collection("users").doc("user-existing");
    expect(docMock.set).not.toHaveBeenCalled();
  });
});

/* eslint-disable @typescript-eslint/no-explicit-any */
import {
  createDocSnap,
  createMockRequest,
  mockFieldValue,
  mockTimestamp,
  mockFetch,
} from "./mocks";

// ── Module mocks (must be before imports) ──────────────────────────
jest.mock("firebase-admin/firestore", () => ({
  getFirestore: jest.fn(),
  FieldValue: {
    serverTimestamp: () => mockFieldValue.serverTimestamp(),
    increment: (n: number) => mockFieldValue.increment(n),
    delete: () => mockFieldValue.delete(),
  },
}));

jest.mock("firebase-admin", () => ({
  firestore: {
    Timestamp: {
      now: () => mockTimestamp.now(),
    },
    FieldValue: {
      serverTimestamp: () => mockFieldValue.serverTimestamp(),
      increment: (n: number) => mockFieldValue.increment(n),
    },
  },
}));

jest.mock("firebase-functions/v2", () => ({
  https: {
    onCall: (_opts: any, handler: any) => handler,
    HttpsError: class HttpsError extends Error {
      code: string;
      constructor(code: string, message: string) {
        super(message);
        this.code = code;
        this.name = "HttpsError";
      }
    },
  },
}));

jest.mock("../helpers", () => ({
  sendSystemNotification: jest.fn().mockResolvedValue(undefined),
}));

import { getFirestore } from "firebase-admin/firestore";
import { addStamp } from "../callable/addStamp";
import * as helpers from "../helpers";

// ── Test Data ──────────────────────────────────────────────────────
const MERCHANT_UID = "merchant-001";
const CUSTOMER_UID = "customer-001";
const PROGRAM_ID = "program-001";

const baseProgramData = {
  merchantId: MERCHANT_UID,
  storeName: "Test Coffee",
  stampsToComplete: 5,
  rewardDescription: "Free Coffee",
  selectedAccent: "#00E676",
  useLightOverlay: false,
  logoUrl: null,
  rewardExpiryDays: 90,
};

/**
 * Creates a mock Firestore that the addStamp transaction logic can navigate.
 * The key challenge: addStamp uses `transaction.get(programRef)` and `transaction.get(cardRef)`
 * and differentiates by the ref object. We track which refs are created and map them.
 */
function setupDb(overrides: {
  programData?: Record<string, any> | undefined;
  cardData?: Record<string, any> | undefined;
  trialExpired?: boolean;
  subscriptionExpired?: boolean;
} = {}) {
  const now = new Date();
  const programData = "programData" in overrides
    ? overrides.programData
    : { ...baseProgramData };

  if (programData && overrides.trialExpired) {
    const pastDate = new Date(now.getTime() - 31 * 24 * 60 * 60 * 1000);
    programData.trialStartedAt = { toDate: () => pastDate };
    programData.subscriptionStatus = "trial";
  }

  if (programData && overrides.subscriptionExpired) {
    const pastDate = new Date(now.getTime() - 1 * 24 * 60 * 60 * 1000);
    programData.subscriptionStatus = "active";
    programData.subscriptionExpiry = { toDate: () => pastDate };
    // Must include trialStartedAt, otherwise addStamp resets status to 'trial'
    programData.trialStartedAt = { toDate: () => new Date(now.getTime() - 60 * 24 * 60 * 60 * 1000) };
  }

  const cardData = overrides.cardData;

  const programSnap = createDocSnap(PROGRAM_ID, programData ?? undefined);
  const cardSnap = createDocSnap(PROGRAM_ID, cardData);

  // Track refs to distinguish program vs card in transaction.get()
  const programRef = {
    id: PROGRAM_ID,
    _type: "program",
    get: jest.fn().mockResolvedValue(programSnap),
  };
  const cardRef = { id: PROGRAM_ID, _type: "card" }; // same id, different ref object

  const txSet = jest.fn();
  const txUpdate = jest.fn();
  const txDelete = jest.fn();

  const txGet = jest.fn().mockImplementation((ref: any) => {
    if (ref._type === "program") return Promise.resolve(programSnap);
    if (ref._type === "card") return Promise.resolve(cardSnap);
    return Promise.resolve(createDocSnap(ref.id, undefined));
  });

  const mockRunTransaction = jest.fn().mockImplementation(
    (fn: (t: any) => Promise<any>) => fn({ get: txGet, set: txSet, update: txUpdate, delete: txDelete }),
  );

  const mockCollection = jest.fn().mockImplementation((colName: string) => {
    if (colName === "programs") {
      return {
        doc: jest.fn().mockReturnValue(programRef),
        add: jest.fn().mockResolvedValue({ id: "new-id" }),
      };
    }
    if (colName === "users") {
      return {
        doc: jest.fn().mockImplementation((userId: string) => ({
          id: userId,
          get: jest.fn().mockResolvedValue(createDocSnap(userId, {})),
          collection: jest.fn().mockImplementation((subCol: string) => {
            if (subCol === "cards") {
              return { doc: jest.fn().mockReturnValue(cardRef) };
            }
            if (subCol === "rewards") {
              return { doc: jest.fn().mockReturnValue({ id: "reward-auto" }) };
            }
            return {};
          }),
        })),
      };
    }
    return {
      doc: jest.fn().mockImplementation((docId: string) => ({
        id: docId,
        get: jest.fn().mockResolvedValue(createDocSnap(docId, programData ?? undefined)),
      })),
      add: jest.fn().mockResolvedValue({ id: "notif-id" }),
    };
  });

  const db = {
    collection: mockCollection,
    collectionGroup: jest.fn(),
    batch: jest.fn(),
    runTransaction: mockRunTransaction,
  };

  (getFirestore as jest.Mock).mockReturnValue(db);

  return { db, txSet, txUpdate };
}

// ── Tests ──────────────────────────────────────────────────────────
describe("addStamp", () => {
  beforeEach(() => {
    jest.clearAllMocks();
    mockFetch();
  });

  it("rejects unauthenticated calls", async () => {
    setupDb();
    const req = createMockRequest({ programId: PROGRAM_ID, customerId: CUSTOMER_UID });
    await expect((addStamp as any)(req)).rejects.toThrow("authenticated");
  });

  it("rejects missing programId", async () => {
    setupDb();
    const req = createMockRequest({ customerId: CUSTOMER_UID }, MERCHANT_UID);
    await expect((addStamp as any)(req)).rejects.toThrow("Missing required");
  });

  it("rejects missing customerId", async () => {
    setupDb();
    const req = createMockRequest({ programId: PROGRAM_ID }, MERCHANT_UID);
    await expect((addStamp as any)(req)).rejects.toThrow("Missing required");
  });

  it("rejects when program not found", async () => {
    setupDb({ programData: undefined });
    const req = createMockRequest(
      { programId: PROGRAM_ID, customerId: CUSTOMER_UID },
      MERCHANT_UID,
    );
    await expect((addStamp as any)(req)).rejects.toThrow("not found");
  });

  it("rejects non-owner / non-store callers", async () => {
    setupDb();
    const req = createMockRequest(
      { programId: PROGRAM_ID, customerId: CUSTOMER_UID },
      "stranger-uid",
    );
    await expect((addStamp as any)(req)).rejects.toThrow("do not own");
  });

  it("adds 1 stamp to a new card (creates card)", async () => {
    const { txSet } = setupDb({ cardData: undefined }); // card doesn't exist
    const req = createMockRequest(
      { programId: PROGRAM_ID, customerId: CUSTOMER_UID },
      MERCHANT_UID,
    );
    const result = await (addStamp as any)(req);
    expect(result.success).toBe(true);
    expect(result.newStamps).toBe(1);
    expect(result.rewardsEarned).toBe(0);
    expect(txSet).toHaveBeenCalled(); // uses set for new card
  });

  it("adds stamps to existing card", async () => {
