    mockGetFirestore.mockReturnValue({
      collection: jest.fn().mockReturnValue({
        where: jest.fn().mockReturnThis(),
        get: jest.fn().mockResolvedValue(createQuerySnap([nonBirthdayUser])),
      }),
    });

    await (notifyBirthdays as any)();
    expect(helpers.sendSystemNotification).not.toHaveBeenCalled();
