// ── Test Data ──────────────────────────────────────────────────────
const MERCHANT_UID = "merchant-001";
const CUSTOMER_UID = "customer-001";
const REWARD_ID = "reward-001";
const PROGRAM_ID = "program-001";

const baseRewardData = {
  programId: PROGRAM_ID,
  merchantId: MERCHANT_UID,
  storeName: "Test Coffee",
  rewardDescription: "Free Coffee",
  status: "active",
  expiryDate: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString(),
};

const baseProgramData = {
  merchantId: MERCHANT_UID,
  storeName: "Test Coffee",
  stampsToComplete: 5,
};

const baseUserData = {
  firstName: "John",
  lastName: "Doe",
  role: "customer",
};

/**
 * Creates mock DB for redeemReward.
 * redeemReward does:
 *   1. transaction.get(userRef) — users/{customerId}
 *   2. transaction.get(rewardRef) — users/{customerId}/rewards/{rewardId}
 *   3. transaction.get(programRef) — programs/{programId}
 *
 * We track refs by _type to route to correct data.
 */
function setupDb(overrides: {
  userData?: Record<string, any> | undefined;
  rewardData?: Record<string, any> | undefined;
  programData?: Record<string, any> | undefined;
} = {}) {
  const userData = "userData" in overrides ? overrides.userData : { ...baseUserData };
  const rewardData = "rewardData" in overrides ? overrides.rewardData : { ...baseRewardData };
  const programData = "programData" in overrides ? overrides.programData : { ...baseProgramData };

  const userRef = { id: CUSTOMER_UID, _type: "user" };
  const rewardRef = { id: REWARD_ID, _type: "reward" };
  const programRef = { id: PROGRAM_ID, _type: "program" };
  const cardRef = { id: PROGRAM_ID, _type: "card" };

  const userSnap = createDocSnap(CUSTOMER_UID, userData);
  const rewardSnap = createDocSnap(REWARD_ID, rewardData);
  const programSnap = createDocSnap(PROGRAM_ID, programData);

  const txGet = jest.fn().mockImplementation((ref: any) => {
    if (ref._type === "user") return Promise.resolve(userSnap);
    if (ref._type === "reward") return Promise.resolve(rewardSnap);
    if (ref._type === "program") return Promise.resolve(programSnap);
    return Promise.resolve(createDocSnap(ref.id, undefined));
  });

  const txUpdate = jest.fn();

  const mockRunTransaction = jest.fn().mockImplementation(
    (fn: (t: any) => Promise<any>) => fn({ get: txGet, set: jest.fn(), update: txUpdate }),
  );

  const db = {
    collection: jest.fn().mockImplementation((col: string) => {
      if (col === "users") {
        return {
          doc: jest.fn().mockImplementation((_userId: string) => ({
            ...userRef,
            collection: jest.fn().mockImplementation((subCol: string) => {
              if (subCol === "rewards") {
                return {
                  doc: jest.fn().mockReturnValue(rewardRef),
                };
              }
              if (subCol === "cards") {
                return {
                  doc: jest.fn().mockReturnValue(cardRef),
                };
              }
              return {};
            }),
          })),
        };
      }
      if (col === "programs") {
        return {
          doc: jest.fn().mockReturnValue(programRef),
        };
      }
      return {};
    }),
    runTransaction: mockRunTransaction,
  };

  mockGetFirestore.mockReturnValue(db);
  return { txUpdate };
}

// ── Tests ──────────────────────────────────────────────────────────
describe("redeemReward", () => {
  beforeEach(() => jest.clearAllMocks());

  it("rejects unauthenticated calls", async () => {
    setupDb();
    const req = createMockRequest({ rewardId: REWARD_ID, customerId: CUSTOMER_UID });
    await expect((redeemReward as any)(req)).rejects.toThrow("authenticated");
  });

  it("rejects missing rewardId", async () => {
    setupDb();
    const req = createMockRequest({ customerId: CUSTOMER_UID }, MERCHANT_UID);
    await expect((redeemReward as any)(req)).rejects.toThrow("Missing required");
  });

  it("rejects missing customerId", async () => {
    setupDb();
    const req = createMockRequest({ rewardId: REWARD_ID }, MERCHANT_UID);
    await expect((redeemReward as any)(req)).rejects.toThrow("Missing required");
  });

  it("rejects when customer not found", async () => {
    setupDb({ userData: undefined });
    const req = createMockRequest(
      { rewardId: REWARD_ID, customerId: CUSTOMER_UID },
      MERCHANT_UID,
    );
    await expect((redeemReward as any)(req)).rejects.toThrow("not found");
  });

  it("rejects guest account redemption", async () => {
    setupDb({ userData: { ...baseUserData, isGuest: true } });
    const req = createMockRequest(
      { rewardId: REWARD_ID, customerId: CUSTOMER_UID },
      MERCHANT_UID,
    );
    await expect((redeemReward as any)(req)).rejects.toThrow("Guest");
  });

  it("rejects already redeemed reward", async () => {
    setupDb({ rewardData: { ...baseRewardData, status: "redeemed" } });
    const req = createMockRequest(
      { rewardId: REWARD_ID, customerId: CUSTOMER_UID },
      MERCHANT_UID,
    );
    await expect((redeemReward as any)(req)).rejects.toThrow("already been redeemed");
  });

  it("returns failure for expired reward", async () => {
    const pastExpiry = new Date(Date.now() - 1000).toISOString();
    setupDb({ rewardData: { ...baseRewardData, expiryDate: pastExpiry } });
    const req = createMockRequest(
      { rewardId: REWARD_ID, customerId: CUSTOMER_UID },
      MERCHANT_UID,
    );
    const result = await (redeemReward as any)(req);
    expect(result.success).toBe(false);
    expect(result.message).toContain("expired");
  });

  it("rejects non-owner merchant", async () => {
    setupDb();
    const req = createMockRequest(
      { rewardId: REWARD_ID, customerId: CUSTOMER_UID },
      "stranger-uid",
    );
    await expect((redeemReward as any)(req)).rejects.toThrow("do not own");
  });

  it("successfully redeems a valid reward", async () => {
    const { txUpdate } = setupDb();
    const req = createMockRequest(
      { rewardId: REWARD_ID, customerId: CUSTOMER_UID },
      MERCHANT_UID,
    );
    const result = await (redeemReward as any)(req);
    expect(result.success).toBe(true);
    expect(result.message).toContain("successfully");
    expect(txUpdate).toHaveBeenCalled(); // reward status updated + card stats updated
  });

  it("allows store account to redeem", async () => {
    setupDb();
    const req = createMockRequest(
      { rewardId: REWARD_ID, customerId: CUSTOMER_UID },
      "store-uid",
      { merchantId: MERCHANT_UID },
    );
    const result = await (redeemReward as any)(req);
    expect(result.success).toBe(true);
  });
});

