import * as admin from "firebase-admin";

export function getPhoneNumberVariations(phone: string): string[] {
    if (!phone) return [];

    const clean = phone.replace(/\D/g, '');
    const normalizedInput = phone.replace(/[\s\-\(\)]/g, '');
    let variations = [normalizedInput];

    if (clean.length > 0) {
        let baseDigits = clean;
        if (clean.startsWith('27') && clean.length > 9) {
            baseDigits = clean.slice(2);
        } else if (clean.startsWith('0') && clean.length > 9) {
            baseDigits = clean.slice(1);
        }
        if (baseDigits.length >= 9) {
            variations.push(`+27${baseDigits}`);
            variations.push(`27${baseDigits}`);
            variations.push(`0${baseDigits}`);
        } else {
            variations.push(clean);
            variations.push(`+${clean}`);
        }
    }

    return [...new Set(variations)];
}

export function normalizePhoneNumber(phone: string): string {
    if (!phone) return "";
    return phone.replace(/[\s\-\(\)]/g, '');
}

export async function sendPushBatch(messages: Record<string, unknown>[]) {
  if (messages.length === 0) return;
  try {
    const response = await fetch("https://exp.host/--/api/v2/push/send", {
      method: "POST",
      headers: {
        Accept: "application/json",
        "Accept-encoding": "gzip, deflate",
        "Content-Type": "application/json",
      },
      body: JSON.stringify(messages),
    });

    if (!response.ok) {
      console.error("Expo push notification failed:", await response.text());
    }
  } catch (err) {
    console.error("sendPushBatch Error:", err);
  }
}

export async function notifyExpiry(
  db: FirebaseFirestore.Firestore,
  merchantId: string,
  customerId: string,
  programId: string,
  storeName: string,
  rewardDescription: string,
) {
  try {
    // 1. Get Push Tokens
    const merchantSnap = await db.collection("users").doc(merchantId).get();
    const customerSnap = await db.collection("users").doc(customerId).get();

    const merchantToken = merchantSnap.data()?.expoPushToken;
    const customerToken = customerSnap.data()?.expoPushToken;

    const title = "Reward Expired";
    const body = `The reward "${rewardDescription}" at ${storeName} has expired and the card has been reset.`;

    const messages: Record<string, unknown>[] = [];
    if (merchantToken)
      messages.push({
        to: merchantToken,
        sound: "default",
        title,
        body: `A customer's reward at your store has expired.`,
        channelId: "default",
        priority: "high",
      });
    if (customerToken)
      messages.push({
        to: customerToken,
        sound: "default",
        title,
        body,
        channelId: "default",
        priority: "high",
      });

    await sendPushBatch(messages);

    // 2. Add to Inbox for Customer
    await db.collection("notifications").add({
      merchantId,
      merchantName: storeName,
      title,
      body,
      timestamp: admin.firestore.FieldValue.serverTimestamp(),
      targetUsers: [customerId],
    });
  } catch (err) {
    console.error("notifyExpiry Error:", err);
  }
}

export async function sendSystemNotification(
  db: FirebaseFirestore.Firestore,
  targetUserId: string,
  title: string,
  body: string,
) {
  try {
    // 1. Get user's push token
    const userSnap = await db.collection("users").doc(targetUserId).get();
    const userData = userSnap.data();

    // 2. Send push notification if token exists
    if (userData?.expoPushToken) {
      await sendPushBatch([
        {
          to: userData.expoPushToken,
          sound: "default",
          title,
          body,
          channelId: "default",
          priority: "high",
          data: { type: "system" },
        },
      ]);
    }

    // 3. Increment unread counter
    await db.collection("users").doc(targetUserId).update({
      unreadNotifications: admin.firestore.FieldValue.increment(1),
    });

    // 4. Save to Inbox
    await db.collection("notifications").add({
      merchantId: "SYSTEM",
      merchantName: "LekkerLoyal",
      title,
      body,
      timestamp: admin.firestore.FieldValue.serverTimestamp(),
      targetUsers: [targetUserId],
    });
  } catch (err) {
    console.error("sendSystemNotification Error:", err);
  }
}

export async function mergeGuestData(
  db: FirebaseFirestore.Firestore,
  newUid: string,
  phoneNumber: string,
) {
  try {
    const variations = getPhoneNumberVariations(phoneNumber);
    if (variations.length === 0) return;

    // chunk variations into batches of 10 for Firestore 'in' queries
    let allGuestDocs: FirebaseFirestore.QueryDocumentSnapshot<FirebaseFirestore.DocumentData>[] = [];

    for (let i = 0; i < variations.length; i += 10) {
      const chunk = variations.slice(i, i + 10);
      const guestsSnap = await db
        .collection("users")
        .where("phoneNumber", "in", chunk)
        .where("isGuest", "==", true)
        .get();
      allGuestDocs = allGuestDocs.concat(guestsSnap.docs);
    }

    if (allGuestDocs.length === 0) return;

    console.log(
      `Found ${allGuestDocs.length} guest profiles for ${phoneNumber}. Merging into ${newUid}...`,
    );

    for (const guestDoc of allGuestDocs) {
      const guestUid = guestDoc.id;

      // 1. Copy Cards
      const cardsSnap = await db
        .collection("users")
        .doc(guestUid)
        .collection("cards")
        .get();
      if (!cardsSnap.empty) {
        const batch = db.batch();
        for (const cardDoc of cardsSnap.docs) {
          const cardData = cardDoc.data();
          const newCardRef = db
            .collection("users")
            .doc(newUid)
            .collection("cards")
            .doc(cardDoc.id);
          batch.set(newCardRef, cardData, { merge: true });
        }
        await batch.commit();
      }

      // 1.5 Copy Rewards
      const rewardsSnap = await db
        .collection("users")
        .doc(guestUid)
        .collection("rewards")
        .get();
      if (!rewardsSnap.empty) {
        const batch = db.batch();
        for (const rewardDoc of rewardsSnap.docs) {
          const rewardData = rewardDoc.data();
          const newRewardRef = db
            .collection("users")
            .doc(newUid)
            .collection("rewards")
            .doc(rewardDoc.id);
          batch.set(newRewardRef, rewardData, { merge: true });
        }
        await batch.commit();
      }

      // 2. Update Notifications
      const notificationsSnap = await db
        .collection("notifications")
        .where("targetUsers", "array-contains", guestUid)
        .get();

      if (!notificationsSnap.empty) {
        const batch = db.batch();
        for (const notifDoc of notificationsSnap.docs) {
          const notifData = notifDoc.data();
          const targetUsers = (notifData.targetUsers || []).filter(
            (id: string) => id !== guestUid,
          );
          if (!targetUsers.includes(newUid)) {
            targetUsers.push(newUid);
          }
          batch.update(notifDoc.ref, { targetUsers });
        }
        await batch.commit();
      }

      // 3. Cleanup Guest
      const cleanupBatch = db.batch();
      cardsSnap.forEach((card) => cleanupBatch.delete(card.ref));
      rewardsSnap.forEach((reward) => cleanupBatch.delete(reward.ref));
      cleanupBatch.delete(guestDoc.ref);
      await cleanupBatch.commit();

      console.log(`Successfully merged and deleted guest ${guestUid}`);
    }
  } catch (err) {
    console.error("Error in mergeGuestData:", err);
    // We don't throw here to avoid failing the main onboarding/profile update process
  }
}

