import { onSchedule } from "firebase-functions/v2/scheduler";
import { getFirestore } from "firebase-admin/firestore";
import * as helpers from "../helpers";

const MS_PER_DAY = 24 * 60 * 60 * 1000;
const WARN_DAYS_REMAINING = 2;

export const notifyStreakExpiry = onSchedule(
  {
    schedule: "every day 07:30",
    region: "europe-west1",
    timeZone: "UTC",
  },
  async () => {
    const db = getFirestore("lekkerloyal-sa");
    const now = new Date();

    console.log("[STREAK-EXPIRY] Running streak-expiry check.");

    try {
      const cardsSnap = await db
        .collectionGroup("cards")
        .where("streakEnabled", "==", true)
        .get();

      if (cardsSnap.empty) {
        console.log("[STREAK-EXPIRY] No streak-enabled cards found.");
        return;
      }

      let notified = 0;

      for (const cardDoc of cardsSnap.docs) {
        const cardData = cardDoc.data();
        const userId = cardDoc.ref.parent.parent?.id;

        if (!userId) continue;

        const currentStreakVisits = cardData.currentStreakVisits as number | undefined;
        const streakTargetVisits = cardData.streakTargetVisits as number | undefined;
        const streakTimeframeDays = cardData.streakTimeframeDays as number | undefined;
        const streakStartDateRaw = cardData.streakStartDate;

        // Skip if streak not in progress
        if (!currentStreakVisits || currentStreakVisits <= 0) continue;
        if (!streakTargetVisits || !streakTimeframeDays) continue;
        if (!streakStartDateRaw) continue;

        let streakStartDate: Date;
        if (typeof streakStartDateRaw === "object" && "toDate" in streakStartDateRaw) {
          streakStartDate = streakStartDateRaw.toDate();
        } else if (typeof streakStartDateRaw === "number") {
          streakStartDate = new Date(streakStartDateRaw);
        } else if (typeof streakStartDateRaw === "string") {
          streakStartDate = new Date(streakStartDateRaw);
        } else {
          continue;
        }

        const streakEndDate = new Date(streakStartDate.getTime() + streakTimeframeDays * MS_PER_DAY);
        const daysRemaining = Math.round((streakEndDate.getTime() - now.getTime()) / MS_PER_DAY);

        if (daysRemaining !== WARN_DAYS_REMAINING) continue;

        const storeName = cardData.storeName || "a store";

        await helpers.sendSystemNotification(
          db,
          userId,
          `Your ${storeName} streak expires in 2 days! ⚡`,
          `You're ${currentStreakVisits}/${streakTargetVisits} visits in. Pop in before it resets!`,
        );
        notified++;
      }

      console.log(`[STREAK-EXPIRY] Sent ${notified} streak-expiry notifications.`);
    } catch (error) {
      console.error("[STREAK-EXPIRY] Error:", error);
    }
  },
);

import { scheduler } from "firebase-functions/v2";
const onSchedule = scheduler.onSchedule;
import { getFirestore, FieldValue } from "firebase-admin/firestore";

/**
 * processSubscriptionRenewals
 * Daily scheduled function to handle trial expirations and auto-subscriptions.
 */
export const processSubscriptionRenewals = onSchedule({
    schedule: "every 24 hours",
    region: "europe-west1",
    timeoutSeconds: 300,
    memory: "256MiB"
}, async (_event: unknown) => {
    const db = getFirestore("lekkerloyal-sa");
    const programsRef = db.collection("programs");

    // 1. Find all programs in 'trial' status
    const trialQuery = programsRef.where("subscriptionStatus", "==", "trial");
    const snapshot = await trialQuery.get();

    console.log(`[RENEWAL] Checking ${snapshot.size} trial programs...`);

    const now = new Date();
    const batch = db.batch();
    let updatesCount = 0;

    for (const doc of snapshot.docs) {
        const data = doc.data();
        const trialStartedAt = data.trialStartedAt?.toDate() || data.createdAt?.toDate();

        if (!trialStartedAt) continue;

        // Calculate if 30 days have passed
        const trialEndDate = new Date(trialStartedAt.getTime() + (30 * 24 * 60 * 60 * 1000));

        if (now >= trialEndDate) {
            console.log(`[RENEWAL] Trial expired for program ${doc.id}`);

            // If user has NOT added banking details, mark as expired
            // If they HAVE, Paystack should have already billed them or will bill them
            // We only need to catch the ones who didn't add a card
            if (!data.bankingDetails || !data.bankingDetails.accountNumber) {
                batch.update(doc.ref, {
                    subscriptionStatus: 'expired',
                    updatedAt: FieldValue.serverTimestamp()
                });
                updatesCount++;
            }
        }
    }

    if (updatesCount > 0) {
        await batch.commit();
    }

    console.log(`[RENEWAL] Processed ${updatesCount} renewals/expirations.`);
});

import { https } from "firebase-functions/v2";
const onRequest = https.onRequest;
import { getFirestore, FieldValue, Timestamp } from "firebase-admin/firestore";
import { defineSecret } from "firebase-functions/params";
import * as crypto from "crypto";

const PAYSTACK_SECRET = defineSecret("PAYSTACK_SECRET");
const PAYSTACK_SECRET_TEST = defineSecret("PAYSTACK_SECRET_TEST");

interface PaystackEvent {
    event: string;
    data?: {
        reference?: string;
        customer?: { customer_code?: string };
    };
}

/**
 * Verify the Paystack signature against the given secret and apply the event
 * to Firestore. Shared by the live and test webhook endpoints.
 */
async function processPaystackEvent(
    rawBody: Buffer,
    signature: string | undefined,
    body: unknown,
    secret: string,
    mode: "LIVE" | "TEST"
): Promise<{ status: number; message?: string }> {
    const hash = crypto.createHmac("sha512", secret).update(rawBody).digest("hex");

    if (hash !== signature) {
        console.error(`Invalid Paystack webhook signature (${mode}).`);
        return { status: 400, message: "Invalid signature" };
    }

    const event = body as PaystackEvent;
    console.log(`Paystack Webhook Event (${mode}):`, event.event, event.data?.reference);

    const db = getFirestore("lekkerloyal-sa");

    if (event.event === "charge.success") {
        const reference = event.data?.reference;
        const customerCode = event.data?.customer?.customer_code;

        if (customerCode) {
            console.log(`Processing subscription payment for customer code ${customerCode}`);

            const programsQuery = db.collection("programs").where("paystackCustomerCode", "==", customerCode);
            const programsSnap = await programsQuery.get();

            if (!programsSnap.empty) {
                const now = new Date();
                const nextExpiry = new Date(now.getTime() + (30 * 24 * 60 * 60 * 1000));

                const batch = db.batch();
                programsSnap.forEach((doc) => {
                    batch.update(doc.ref, {
                        subscriptionStatus: "active",
                        subscriptionExpiry: Timestamp.fromDate(nextExpiry),
                        updatedAt: FieldValue.serverTimestamp(),
                        lastPaymentRef: reference,
                    });
                });
                await batch.commit();
                console.log(`Successfully extended subscription for ${programsSnap.size} program(s).`);
            } else {
                console.warn(`No programs found matching customer code ${customerCode}`);
            }
        } else {
            console.warn("Missing customer_code in webhook data");
        }
    } else if (event.event === "invoice.payment_failed") {
        const customerCode = event.data?.customer?.customer_code;
        if (customerCode) {
            const programsQuery = db.collection("programs").where("paystackCustomerCode", "==", customerCode);
            const snap = await programsQuery.get();
            const batch = db.batch();
            snap.forEach((doc) => {
                batch.update(doc.ref, { subscriptionStatus: "past_due", updatedAt: FieldValue.serverTimestamp() });
            });
            await batch.commit();
            console.log(`Updated ${snap.size} programs to past_due via webhook`);
        }
    } else if (event.event === "subscription.disable") {
        const customerCode = event.data?.customer?.customer_code;
        if (customerCode) {
            const programsQuery = db.collection("programs").where("paystackCustomerCode", "==", customerCode);
            const snap = await programsQuery.get();
            const batch = db.batch();
            snap.forEach((doc) => {
                batch.update(doc.ref, { subscriptionStatus: "cancelled", updatedAt: FieldValue.serverTimestamp() });
            });
            await batch.commit();
            console.log(`Updated ${snap.size} programs to cancelled via webhook`);
        }
    }

    return { status: 200 };
}

/**
 * paystackWebhook (LIVE)
 * Receives production webhooks from Paystack. Verifies only against the live
 * secret. Configure this URL in your Paystack live dashboard.
 */
export const paystackWebhook = onRequest(
    { region: "africa-south1", timeoutSeconds: 60, secrets: [PAYSTACK_SECRET] },
    async (req, res) => {
        try {
            const signature = req.headers["x-paystack-signature"];
            const sig = Array.isArray(signature) ? signature[0] : signature;
            const result = await processPaystackEvent(req.rawBody, sig, req.body, PAYSTACK_SECRET.value(), "LIVE");
            if (result.message) {
                res.status(result.status).send(result.message);
            } else {
                res.sendStatus(result.status);
            }
        } catch (error) {
            console.error("Webhook Error (LIVE):", error);
            res.status(500).send("Internal Server Error");
        }
    }
);

/**
 * paystackWebhookTest (TEST)
 * Receives test-mode webhooks from Paystack. Verifies only against the test
 * secret. Configure this URL in your Paystack test dashboard.
 */
export const paystackWebhookTest = onRequest(
    { region: "africa-south1", timeoutSeconds: 60, secrets: [PAYSTACK_SECRET_TEST] },
    async (req, res) => {
