        }
    }
);

import { onSchedule } from "firebase-functions/v2/scheduler";
import { getFirestore } from "firebase-admin/firestore";
import * as helpers from "../helpers";

const MS_PER_DAY = 24 * 60 * 60 * 1000;
const LAPSE_DAYS = 21;

export const notifyLapsedVisits = onSchedule(
  {
    schedule: "every day 07:00",
    region: "europe-west1",
    timeZone: "UTC",
  },
  async () => {
    const db = getFirestore("lekkerloyal-sa");
    const now = new Date();

    console.log(`[LAPSED-VISITS] Running lapsed-visit check. Target: ${LAPSE_DAYS} days ago.`);

    try {
      const cardsSnap = await db.collectionGroup("cards").get();

      if (cardsSnap.empty) {
        console.log("[LAPSED-VISITS] No cards found.");
        return;
      }

      let notified = 0;

      for (const cardDoc of cardsSnap.docs) {
        const cardData = cardDoc.data();
        const userId = cardDoc.ref.parent.parent?.id;

        if (!userId) continue;

        const lastVisitRaw = cardData.lastVisit;
        if (!lastVisitRaw) continue;

        let lastVisitDate: Date;
        if (typeof lastVisitRaw === "object" && "toDate" in lastVisitRaw) {
          lastVisitDate = lastVisitRaw.toDate();
        } else if (typeof lastVisitRaw === "number") {
          lastVisitDate = new Date(lastVisitRaw);
        } else if (typeof lastVisitRaw === "string") {
          lastVisitDate = new Date(lastVisitRaw);
        } else {
          continue;
        }

        const daysAgo = Math.round((now.getTime() - lastVisitDate.getTime()) / MS_PER_DAY);

        if (daysAgo !== LAPSE_DAYS) continue;

        const storeName = cardData.storeName || "a store";

        await helpers.sendSystemNotification(
          db,
          userId,
          `We miss you at ${storeName}! 👋`,
          `It's been 3 weeks since your last visit. Pop in and keep your loyalty card going!`,
        );
        notified++;
      }

      console.log(`[LAPSED-VISITS] Sent ${notified} lapsed-visit notifications.`);
    } catch (error) {
      console.error("[LAPSED-VISITS] Error:", error);
    }
  },
);

import { https } from "firebase-functions/v2";
const onCall = https.onCall;
const HttpsError = https.HttpsError;
import { getFirestore, FieldValue, Timestamp } from "firebase-admin/firestore";
import { defineSecret } from "firebase-functions/params";
import * as types from "../types";

const PAYSTACK_SECRET = defineSecret("PAYSTACK_SECRET");
const PAYSTACK_SECRET_TEST = defineSecret("PAYSTACK_SECRET_TEST");

const TEST_PLAN_CODE = "PLN_pnei7dyejj7145i";
const LIVE_PLAN_CODE = "PLN_8erqsednwqkq2c2";

const PAYSTACK_API_URL = process.env.PAYSTACK_API_URL || "https://api.paystack.co";

interface PaystackSub {
    status: string;
    subscription_code: string;
    email_token: string;
    next_payment_date?: string;
    plan?: {
        plan_code?: string;
    };
}

// Fetches all subscriptions (any status) for a customer+plan combination.
// Paystack's list API omits "pending" (future-start-date) subscriptions by default,
// so we also try a direct customer subscription listing to catch them.
async function fetchExistingSubs(secret: string, customerId: string | number, planCode: string): Promise<PaystackSub[]> {
    const res = await fetch(
        `${PAYSTACK_API_URL}/subscription?customer=${customerId}&perPage=20`,
        { headers: { Authorization: `Bearer ${secret}` } }
    );
    const data = await res.json();
    const subs = (data.status && Array.isArray(data.data)) ? (data.data as PaystackSub[]) : [];
    return subs.filter(sub => sub.plan?.plan_code === planCode);
}

export const setupSubscription = onCall({ region: "africa-south1", timeoutSeconds: 60, secrets: [PAYSTACK_SECRET, PAYSTACK_SECRET_TEST] }, async (request) => {
    if (!request.auth) {
        throw new HttpsError('unauthenticated', 'Authenticated users only.');
    }

    const { programId, reference, programData, isTestMode } = request.data as types.SetupSubscriptionData;
    const { uid } = request.auth;

    if (!reference) {
        throw new HttpsError('invalid-argument', 'Missing Paystack reference.');
    }
    if (typeof isTestMode !== 'boolean') {
        throw new HttpsError('invalid-argument', 'Missing isTestMode flag.');
    }

    const db = getFirestore("lekkerloyal-sa");
    const secretToUse = isTestMode ? PAYSTACK_SECRET_TEST.value() : PAYSTACK_SECRET.value();
    const planCode = isTestMode ? TEST_PLAN_CODE : LIVE_PLAN_CODE;

    try {
        // 1. Verify the Paystack transaction.
        const paystackRes = await fetch(`${PAYSTACK_API_URL}/transaction/verify/${reference}`, {
            headers: { Authorization: `Bearer ${secretToUse}` }
        });
        const paystackData = await paystackRes.json();

        if (!paystackData.status || paystackData.data?.status !== 'success') {
            console.error(`Paystack verification failed (${isTestMode ? 'TEST' : 'LIVE'}):`, paystackData);
            throw new HttpsError('failed-precondition', 'Transaction verification failed.');
        }

        const { authorization, customer } = paystackData.data;
        const customerCode = customer?.customer_code;
        const customerId = customer?.id;
        const authorizationCode = authorization?.authorization_code;

        if (!customerCode || !authorizationCode || !customerId) {
            throw new HttpsError('failed-precondition', 'Paystack response missing customer or authorization details.');
        }

        // 2. Update the user profile with Paystack codes and a card placeholder.
        const bankingDetailsPlaceholder = {
            accountHolder: authorization?.account_name || 'Cardholder',
            accountNumber: `****${authorization?.last4 || '1234'}`,
            bankName: authorization?.bank || 'Paystack',
            bankCode: 'PAYSTACK'
        };

        const userRef = db.collection("users").doc(uid);
        await userRef.set({
            paystackCustomerCode: customerCode,
            paystackAuthorizationCode: authorizationCode,
            bankingDetails: bankingDetailsPlaceholder,
            updatedAt: FieldValue.serverTimestamp()
        }, { merge: true });

        // 3. Disable any existing subscriptions for this customer+plan.
        //    We do NOT pass start_date to Paystack (see step 4), so all subscriptions
        //    created here are immediately active and visible to the list API.
        //    Any "pending" phantom subscriptions from previous attempts (created with
        //    a future start_date) are invisible to the list API — disabling active ones
        //    is sufficient; Paystack clears pending ones when a new sub is created
        //    once the active ones are gone.
        let nextExpiry = new Date(Date.now() + (30 * 24 * 60 * 60 * 1000));

        const existingSubs = await fetchExistingSubs(secretToUse, customerId, planCode);
        for (const sub of existingSubs) {
            if (sub.status === 'active' || sub.status === 'non-renewing') {
                console.log(`Disabling existing subscription ${sub.subscription_code}...`);
                await fetch(`${PAYSTACK_API_URL}/subscription/disable`, {
                    method: 'POST',
                    headers: { Authorization: `Bearer ${secretToUse}`, 'Content-Type': 'application/json' },
                    body: JSON.stringify({ code: sub.subscription_code, token: sub.email_token })
                });
            }
        }

        // 4. Create a new Paystack subscription WITHOUT a start_date.
        //
        //    Root cause of the previous "subscription already in place" bug:
        //    passing start_date 30 days in the future causes Paystack to create a
        //    "pending" subscription that is invisible to the list API (so our cleanup
        //    above cannot find and disable it) but still blocks new subscription
        //    creation. Omitting start_date creates the subscription in "active" state
        //    immediately. For monthly plans Paystack issues the first invoice at the
        //    end of the first billing interval (~30 days), so the merchant still gets
        //    a free first month — we just can't rely on start_date to enforce that.
        console.log(`Creating Paystack subscription for ${customerCode} (${isTestMode ? 'TEST' : 'LIVE'}, plan ${planCode})`);

        let subscriptionCode: string;

        const subRes = await fetch(`${PAYSTACK_API_URL}/subscription`, {
            method: 'POST',
            headers: {
                Authorization: `Bearer ${secretToUse}`,
                'Content-Type': 'application/json'
            },
            body: JSON.stringify({
                customer: customerCode,
                plan: planCode,
                authorization: authorizationCode
                // No start_date — avoids phantom pending subscriptions
            })
        });

        const subData = await subRes.json();

        if (!subData.status) {
            // Graceful fallback: if Paystack says it's "already in place", the subscription
            // exists (possibly in a state we can't list). Fetch it by customer+plan and
            // reuse its code so we can complete the Firestore write.
            if (typeof subData.message === 'string' && subData.message.toLowerCase().includes('already in place')) {
                console.warn('Subscription already in place — fetching existing code as fallback...');
                const fallbackSubs = await fetchExistingSubs(secretToUse, customerId, planCode);
                // Look for any subscription that isn't completely dead (active, non-renewing, attention, or even pending/cancelled if that's all we have)
                const existing = fallbackSubs.find(s => ['active', 'non-renewing', 'attention'].includes(s.status)) || fallbackSubs[0];

                if (existing) {
                    subscriptionCode = existing.subscription_code;
                    if (existing.next_payment_date) {
                        nextExpiry = new Date(existing.next_payment_date);
                    }
                    console.log(`Reusing existing subscription ${subscriptionCode}`);
                } else {
                    console.error('Paystack subscription creation failed and no existing sub found:', subData);
                    throw new HttpsError('internal', `Failed to create Paystack subscription: ${subData.message}`);
                }
            } else {
                console.error('Paystack subscription creation failed:', subData);
                throw new HttpsError('internal', `Failed to create Paystack subscription: ${subData.message}`);
            }
        } else {
            subscriptionCode = subData.data.subscription_code;
            if (subData.data.next_payment_date) {
                nextExpiry = new Date(subData.data.next_payment_date);
            }
            console.log(`Subscription created: ${subscriptionCode}`);
        }

        // 5. Write to Firestore — only reached after subscription is confirmed.
        let currentProgramId = programId;

        if (currentProgramId) {
            const programRef = db.collection("programs").doc(currentProgramId);
            const programSnap = await programRef.get();
            if (programSnap.exists && programSnap.data()?.merchantId === uid) {
                await programRef.update({
                    subscriptionStatus: 'active',
                    subscriptionExpiry: Timestamp.fromDate(nextExpiry),
                    lastPaymentRef: reference,
                    paystackCustomerCode: customerCode,
                    paystackSubscriptionCode: subscriptionCode,
                    bankingDetails: bankingDetailsPlaceholder,
                    updatedAt: FieldValue.serverTimestamp()
                });
            }
        } else if (programData) {
            console.log("Creating program with active subscription...");
            const programRef = db.collection("programs").doc();
            await programRef.set({
                ...programData,
                merchantId: uid,
                activeUsers: 0,
                subscriptionStatus: 'active',
                subscriptionExpiry: Timestamp.fromDate(nextExpiry),
                lastPaymentRef: reference,
                paystackCustomerCode: customerCode,
                paystackSubscriptionCode: subscriptionCode,
                bankingDetails: bankingDetailsPlaceholder,
                createdAt: FieldValue.serverTimestamp(),
                updatedAt: FieldValue.serverTimestamp()
            });
            currentProgramId = programRef.id;
        }

        return { success: true, programId: currentProgramId };

    } catch (error) {
        console.error("Error setting up subscription:", error);
        if (error instanceof HttpsError) throw error;
        throw new HttpsError('internal', 'An error occurred while setting up subscription.');
    }
});

