185	      const guestUid = guestDoc.id;
186	
187	      // 1. Copy Cards
188	      const cardsSnap = await db
189	        .collection("users")
190	        .doc(guestUid)
191	        .collection("cards")
192	        .get();
193	      if (!cardsSnap.empty) {
194	        const batch = db.batch();
195	        for (const cardDoc of cardsSnap.docs) {
196	          const cardData = cardDoc.data();
197	          const newCardRef = db
198	            .collection("users")
199	            .doc(newUid)
200	            .collection("cards")
201	            .doc(cardDoc.id);
202	          batch.set(newCardRef, cardData, { merge: true });
203	        }
204	        await batch.commit();
205	      }
206	
207	      // 1.5 Copy Rewards
208	      const rewardsSnap = await db
209	        .collection("users")
210	        .doc(guestUid)
211	        .collection("rewards")
212	        .get();
213	      if (!rewardsSnap.empty) {
214	        const batch = db.batch();
215	        for (const rewardDoc of rewardsSnap.docs) {
216	          const rewardData = rewardDoc.data();
217	          const newRewardRef = db
218	            .collection("users")
219	            .doc(newUid)
220	            .collection("rewards")
221	            .doc(rewardDoc.id);
222	          batch.set(newRewardRef, rewardData, { merge: true });
223	        }
224	        await batch.commit();
225	      }
226	
227	      // 2. Update Notifications
228	      const notificationsSnap = await db
229	        .collection("notifications")
230	        .where("targetUsers", "array-contains", guestUid)
231	        .get();
232	
233	      if (!notificationsSnap.empty) {
234	        const batch = db.batch();
235	        for (const notifDoc of notificationsSnap.docs) {
236	          const notifData = notifDoc.data();
237	          const targetUsers = (notifData.targetUsers || []).filter(
238	            (id: string) => id !== guestUid,
239	          );
240	          if (!targetUsers.includes(newUid)) {
241	            targetUsers.push(newUid);
242	          }
243	          batch.update(notifDoc.ref, { targetUsers });
244	        }
245	        await batch.commit();
246	      }
247	
248	      // 3. Cleanup Guest
249	      const cleanupBatch = db.batch();
250	      cardsSnap.forEach((card) => cleanupBatch.delete(card.ref));
251	      rewardsSnap.forEach((reward) => cleanupBatch.delete(reward.ref));
252	      cleanupBatch.delete(guestDoc.ref);
253	      await cleanupBatch.commit();
254	
255	      console.log(`Successfully merged and deleted guest ${guestUid}`);
256	    }
257	  } catch (err) {
258	    console.error("Error in mergeGuestData:", err);
259	    // We don't throw here to avoid failing the main onboarding/profile update process
260	  }
261	}
