1	import { https } from "firebase-functions/v2";
2	const onCall = https.onCall;
3	const HttpsError = https.HttpsError;
4	import { getFirestore, FieldValue, Timestamp } from "firebase-admin/firestore";
5	import { defineSecret } from "firebase-functions/params";
6	import * as types from "../types";
7	
8	const PAYSTACK_SECRET = defineSecret("PAYSTACK_SECRET");
9	const PAYSTACK_SECRET_TEST = defineSecret("PAYSTACK_SECRET_TEST");
10	
11	const TEST_PLAN_CODE = "PLN_pnei7dyejj7145i";
12	const LIVE_PLAN_CODE = "PLN_8erqsednwqkq2c2";
13	
14	const PAYSTACK_API_URL = process.env.PAYSTACK_API_URL || "https://api.paystack.co";
15	
16	interface PaystackSub {
17	    status: string;
18	    subscription_code: string;
19	    email_token: string;
20	    next_payment_date?: string;
21	    plan?: {
22	        plan_code?: string;
23	    };
24	}
25	
26	// Fetches all subscriptions (any status) for a customer+plan combination.
27	// Paystack's list API omits "pending" (future-start-date) subscriptions by default,
28	// so we also try a direct customer subscription listing to catch them.
29	async function fetchExistingSubs(secret: string, customerId: string | number, planCode: string): Promise<PaystackSub[]> {
30	    const res = await fetch(
31	        `${PAYSTACK_API_URL}/subscription?customer=${customerId}&perPage=20`,
32	        { headers: { Authorization: `Bearer ${secret}` } }
33	    );
34	    const data = await res.json();
35	    const subs = (data.status && Array.isArray(data.data)) ? (data.data as PaystackSub[]) : [];
36	    return subs.filter(sub => sub.plan?.plan_code === planCode);
37	}
38	
39	export const setupSubscription = onCall({ region: "africa-south1", timeoutSeconds: 60, secrets: [PAYSTACK_SECRET, PAYSTACK_SECRET_TEST] }, async (request) => {
40	    if (!request.auth) {
41	        throw new HttpsError('unauthenticated', 'Authenticated users only.');
42	    }
43	
44	    const { programId, reference, programData, isTestMode } = request.data as types.SetupSubscriptionData;
45	    const { uid } = request.auth;
46	
47	    if (!reference) {
48	        throw new HttpsError('invalid-argument', 'Missing Paystack reference.');
49	    }
50	    if (typeof isTestMode !== 'boolean') {
51	        throw new HttpsError('invalid-argument', 'Missing isTestMode flag.');
52	    }
53	
54	    const db = getFirestore("lekkerloyal-sa");
55	    const secretToUse = isTestMode ? PAYSTACK_SECRET_TEST.value() : PAYSTACK_SECRET.value();
56	    const planCode = isTestMode ? TEST_PLAN_CODE : LIVE_PLAN_CODE;
57	
58	    try {
59	        // 1. Verify the Paystack transaction.
60	        const paystackRes = await fetch(`${PAYSTACK_API_URL}/transaction/verify/${reference}`, {
61	            headers: { Authorization: `Bearer ${secretToUse}` }
62	        });
63	        const paystackData = await paystackRes.json();
64	
65	        if (!paystackData.status || paystackData.data?.status !== 'success') {
66	            console.error(`Paystack verification failed (${isTestMode ? 'TEST' : 'LIVE'}):`, paystackData);
67	            throw new HttpsError('failed-precondition', 'Transaction verification failed.');
68	        }
69	
70	        const { authorization, customer } = paystackData.data;
71	        const customerCode = customer?.customer_code;
72	        const customerId = customer?.id;
73	        const authorizationCode = authorization?.authorization_code;
74	
75	        if (!customerCode || !authorizationCode || !customerId) {
76	            throw new HttpsError('failed-precondition', 'Paystack response missing customer or authorization details.');
77	        }
78	
79	        // 2. Update the user profile with Paystack codes and a card placeholder.
80	        const bankingDetailsPlaceholder = {
81	            accountHolder: authorization?.account_name || 'Cardholder',
82	            accountNumber: `****${authorization?.last4 || '1234'}`,
83	            bankName: authorization?.bank || 'Paystack',
84	            bankCode: 'PAYSTACK'
85	        };
86	
87	        const userRef = db.collection("users").doc(uid);
88	        await userRef.set({
89	            paystackCustomerCode: customerCode,
90	            paystackAuthorizationCode: authorizationCode,
91	            bankingDetails: bankingDetailsPlaceholder,
92	            updatedAt: FieldValue.serverTimestamp()
93	        }, { merge: true });
94	
95	        // 3. Disable any existing subscriptions for this customer+plan.
96	        //    We do NOT pass start_date to Paystack (see step 4), so all subscriptions
97	        //    created here are immediately active and visible to the list API.
98	        //    Any "pending" phantom subscriptions from previous attempts (created with
99	        //    a future start_date) are invisible to the list API — disabling active ones
100	        //    is sufficient; Paystack clears pending ones when a new sub is created
101	        //    once the active ones are gone.
102	        let nextExpiry = new Date(Date.now() + (30 * 24 * 60 * 60 * 1000));
103	
104	        const existingSubs = await fetchExistingSubs(secretToUse, customerId, planCode);
105	        for (const sub of existingSubs) {
106	            if (sub.status === 'active' || sub.status === 'non-renewing') {
107	                console.log(`Disabling existing subscription ${sub.subscription_code}...`);
108	                await fetch(`${PAYSTACK_API_URL}/subscription/disable`, {
109	                    method: 'POST',
110	                    headers: { Authorization: `Bearer ${secretToUse}`, 'Content-Type': 'application/json' },
111	                    body: JSON.stringify({ code: sub.subscription_code, token: sub.email_token })
112	                });
113	            }
114	        }
115	
116	        // 4. Create a new Paystack subscription WITHOUT a start_date.
117	        //
118	        //    Root cause of the previous "subscription already in place" bug:
119	        //    passing start_date 30 days in the future causes Paystack to create a
120	        //    "pending" subscription that is invisible to the list API (so our cleanup
121	        //    above cannot find and disable it) but still blocks new subscription
122	        //    creation. Omitting start_date creates the subscription in "active" state
123	        //    immediately. For monthly plans Paystack issues the first invoice at the
124	        //    end of the first billing interval (~30 days), so the merchant still gets
125	        //    a free first month — we just can't rely on start_date to enforce that.
126	        console.log(`Creating Paystack subscription for ${customerCode} (${isTestMode ? 'TEST' : 'LIVE'}, plan ${planCode})`);
127	
128	        let subscriptionCode: string;
129	
130	        const subRes = await fetch(`${PAYSTACK_API_URL}/subscription`, {
131	            method: 'POST',
132	            headers: {
133	                Authorization: `Bearer ${secretToUse}`,
134	                'Content-Type': 'application/json'
135	            },
136	            body: JSON.stringify({
137	                customer: customerCode,
138	                plan: planCode,
139	                authorization: authorizationCode
140	                // No start_date — avoids phantom pending subscriptions
141	            })
142	        });
143	
144	        const subData = await subRes.json();
145	
146	        if (!subData.status) {
147	            // Graceful fallback: if Paystack says it's "already in place", the subscription
148	            // exists (possibly in a state we can't list). Fetch it by customer+plan and
149	            // reuse its code so we can complete the Firestore write.
150	            if (typeof subData.message === 'string' && subData.message.toLowerCase().includes('already in place')) {
151	                console.warn('Subscription already in place — fetching existing code as fallback...');
152	                const fallbackSubs = await fetchExistingSubs(secretToUse, customerId, planCode);
153	                // Look for any subscription that isn't completely dead (active, non-renewing, attention, or even pending/cancelled if that's all we have)
154	                const existing = fallbackSubs.find(s => ['active', 'non-renewing', 'attention'].includes(s.status)) || fallbackSubs[0];
155	                
156	                if (existing) {
157	                    subscriptionCode = existing.subscription_code;
158	                    if (existing.next_payment_date) {
159	                        nextExpiry = new Date(existing.next_payment_date);
160	                    }
161	                    console.log(`Reusing existing subscription ${subscriptionCode}`);
162	                } else {
163	                    console.error('Paystack subscription creation failed and no existing sub found:', subData);
164	                    throw new HttpsError('internal', `Failed to create Paystack subscription: ${subData.message}`);
165	                }
166	            } else {
167	                console.error('Paystack subscription creation failed:', subData);
168	                throw new HttpsError('internal', `Failed to create Paystack subscription: ${subData.message}`);
169	            }
170	        } else {
171	            subscriptionCode = subData.data.subscription_code;
172	            if (subData.data.next_payment_date) {
173	                nextExpiry = new Date(subData.data.next_payment_date);
174	            }
175	            console.log(`Subscription created: ${subscriptionCode}`);
176	        }
177	
178	        // 5. Write to Firestore — only reached after subscription is confirmed.
179	        let currentProgramId = programId;
180	
181	        if (currentProgramId) {
182	            const programRef = db.collection("programs").doc(currentProgramId);
183	            const programSnap = await programRef.get();
184	            if (programSnap.exists && programSnap.data()?.merchantId === uid) {
185	                await programRef.update({
186	                    subscriptionStatus: 'active',
187	                    subscriptionExpiry: Timestamp.fromDate(nextExpiry),
188	                    lastPaymentRef: reference,
189	                    paystackCustomerCode: customerCode,
190	                    paystackSubscriptionCode: subscriptionCode,
191	                    bankingDetails: bankingDetailsPlaceholder,
192	                    updatedAt: FieldValue.serverTimestamp()
193	                });
194	            }
195	        } else if (programData) {
196	            console.log("Creating program with active subscription...");
197	            const programRef = db.collection("programs").doc();
198	            await programRef.set({
199	                ...programData,
200	                merchantId: uid,
201	                activeUsers: 0,
202	                subscriptionStatus: 'active',
203	                subscriptionExpiry: Timestamp.fromDate(nextExpiry),
204	                lastPaymentRef: reference,
205	                paystackCustomerCode: customerCode,
206	                paystackSubscriptionCode: subscriptionCode,
207	                bankingDetails: bankingDetailsPlaceholder,
208	                createdAt: FieldValue.serverTimestamp(),
