import { https } from "firebase-functions/v2";
const onCall = https.onCall;
const HttpsError = https.HttpsError;
import * as admin from "firebase-admin";
import { getFirestore, FieldValue } from "firebase-admin/firestore";
import { defineSecret } from "firebase-functions/params";

const PAYSTACK_SECRET = defineSecret("PAYSTACK_SECRET");
const PAYSTACK_SECRET_TEST = defineSecret("PAYSTACK_SECRET_TEST");

const PAYSTACK_API_URL = process.env.PAYSTACK_API_URL || "https://api.paystack.co";

/**
 * deleteAccount
 * Callable function to securely delete a user's account and associated data (Cascading Delete).
 * - Merchant: Deletes Programs, Stores (sub-accounts), User Doc, Auth User.
 * - Store: Deletes User Doc, Auth User.
 * - Customer: Deletes User Doc, Auth User.
 */

async function disableAllCustomerSubscriptions(secret: string, customerCode: string) {
    try {
        // Look up customer by code to get their numeric ID
        const customerRes = await fetch(`${PAYSTACK_API_URL}/customer/${customerCode}`, {
            headers: { Authorization: `Bearer ${secret}` }
        });
        const customerData = await customerRes.json();
        const customerId = customerData.data?.id;

        if (!customerId) {
            console.warn(`Customer ID not found for code ${customerCode}. Skipping subscription cleanup.`);
            return;
        }

        const res = await fetch(
            `${PAYSTACK_API_URL}/subscription?customer=${customerId}&perPage=20`,
            { headers: { Authorization: `Bearer ${secret}` } }
        );
        const data = await res.json();
        if (data.status && Array.isArray(data.data)) {
            for (const sub of data.data) {
                if (['active', 'non-renewing', 'attention'].includes(sub.status)) {
                    console.log(`Disabling orphan subscription ${sub.subscription_code} for customer ${customerCode}...`);
                    await fetch(`${PAYSTACK_API_URL}/subscription/disable`, {
                        method: 'POST',
                        headers: { Authorization: `Bearer ${secret}`, 'Content-Type': 'application/json' },
                        body: JSON.stringify({ code: sub.subscription_code, token: sub.email_token })
                    });
                }
            }
        }
    } catch (err) {
        console.error(`Failed to cleanup global Paystack subscriptions for ${customerCode}:`, err);
    }
}

export const deleteAccount = onCall({ region: "africa-south1", timeoutSeconds: 120, secrets: [PAYSTACK_SECRET, PAYSTACK_SECRET_TEST] }, async (request) => {
    if (!request.auth) {
        throw new HttpsError('unauthenticated', 'The function must be called while authenticated.');
    }

    const { uid, token } = request.auth;
    const db = getFirestore("lekkerloyal-sa");

    try {
        console.log(`Initiating account deletion for user ${uid} (Role: ${token.role || 'unknown'})`);

        // 0. IMPORTANT: Delete Auth User First
        // This prevents the frontend from detecting a missing user doc while still authenticated,
        // which would otherwise trigger the ProfileRestorer to erroneously re-onboard the user.
        try {
            await admin.auth().deleteUser(uid);
            console.log(`Auth user ${uid} deleted. Proceeding with data cleanup.`);
        } catch (e: unknown) {
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            if ((e as any).code !== 'auth/user-not-found') {
                throw e; // Fail early if Auth deletion fails for unexpected reason
            }
        }

        // 1. Handle Merchant Logic (Cascading deletes)
        if (token.role === 'merchant') {
            // A. Delete Programs and Cascade to Cards
            const programsQuery = db.collection("programs").where("merchantId", "==", uid);
            const programsSnap = await programsQuery.get();
            const programDeletes: Promise<FirebaseFirestore.WriteResult>[] = [];
            const cardDeletes: Promise<FirebaseFirestore.WriteResult>[] = [];

            for (const programDoc of programsSnap.docs) {
                const programData = programDoc.data();
                const subCode = programData.paystackSubscriptionCode;

                // Paystack Cancellation Logic
                if (subCode) {
                    try {
                        console.log(`Attempting to cancel Paystack subscription: ${subCode}`);
                        const liveSecret = PAYSTACK_SECRET.value();
                        const testSecret = PAYSTACK_SECRET_TEST.value();
                        let secret = liveSecret;

                        // 1. Fetch subscription to retrieve the required email_token (Try Live first)
                        let subFetchResponse = await fetch(`${PAYSTACK_API_URL}/subscription/${subCode}`, {
                            headers: { Authorization: `Bearer ${liveSecret}` }
                        });
                        let subDetail = await subFetchResponse.json();

                        if (!subDetail.status) {
                            // Try test secret
                            subFetchResponse = await fetch(`${PAYSTACK_API_URL}/subscription/${subCode}`, {
                                headers: { Authorization: `Bearer ${testSecret}` }
                            });
                            subDetail = await subFetchResponse.json();
                            if (subDetail.status) {
                                secret = testSecret;
                            }
                        }

                        if (subDetail.status && subDetail.data.email_token) {
                            const emailToken = subDetail.data.email_token;

                            // 2. Disable the subscription on Paystack
                            const disableResponse = await fetch(`${PAYSTACK_API_URL}/subscription/disable`, {
                                method: 'POST',
                                headers: {
                                    Authorization: `Bearer ${secret}`,
                                    'Content-Type': 'application/json'
                                },
                                body: JSON.stringify({
                                    code: subCode,
                                    token: emailToken
                                })
                            });
                            const disableResult = await disableResponse.json();
                            console.log(`Paystack Disable Status [${subCode}]:`, disableResult.message || disableResult.status);
                        } else {
                            console.warn(`Could not retrieve email_token for subscription ${subCode}. Response:`, JSON.stringify(subDetail));
                        }
                    } catch (paystackError) {
                        console.error(`Paystack cancellation error for ${subCode}:`, paystackError);
                    }
                }

                programDeletes.push(programDoc.ref.delete());

                // Cascade Delete: Remove this card from all users' wallets
                const cardsQuery = db.collectionGroup('cards').where('programId', '==', programDoc.id);
                const cardsSnap = await cardsQuery.get();
                cardsSnap.forEach(cardDoc => {
                    cardDeletes.push(cardDoc.ref.delete());
                });
            }
            await Promise.all([...programDeletes, ...cardDeletes]);
            console.log(`Deleted ${programDeletes.length} programs and ${cardDeletes.length} associated user cards.`);

            // B. Delete Stores (Sub-accounts)
            const storesQuery = db.collection("users").where("linkedMerchantId", "==", uid);
            const storesSnap = await storesQuery.get();

            // We need to delete their Auth accounts too!
            for (const storeDoc of storesSnap.docs) {
                try {
                    await admin.auth().deleteUser(storeDoc.id);
                    await storeDoc.ref.delete();
                } catch (e) {
                    console.error(`Failed to delete store sub-account ${storeDoc.id}:`, e);
                }
            }
            console.log(`Deleted ${storesSnap.size} store accounts.`);
        }

        // 2. Global Paystack Cleanup & Delete User Document (All roles)
        const userRef = db.collection("users").doc(uid);
        const userSnap = await userRef.get();
        const userData = userSnap.data();

        if (userData?.paystackCustomerCode) {
            console.log(`Performing global Paystack cleanup for customer ${userData.paystackCustomerCode}`);
            const liveSecret = PAYSTACK_SECRET.value();
            const testSecret = PAYSTACK_SECRET_TEST.value();
            await disableAllCustomerSubscriptions(liveSecret, userData.paystackCustomerCode);
            await disableAllCustomerSubscriptions(testSecret, userData.paystackCustomerCode);
        }

        // Delete subcollections (cards) - manual recursion needed
        const cardsSnap = await userRef.collection("cards").get();
        const cardDeletes: Promise<FirebaseFirestore.WriteResult>[] = [];
        const programDecrementUpdates: Promise<unknown>[] = [];

        cardsSnap.forEach(doc => {
            cardDeletes.push(doc.ref.delete());

            // If this card belongs to a program, decrement that program's activeUsers count
            const cardData = doc.data();
            if (cardData.programId) {
                const programRef = db.collection("programs").doc(cardData.programId);
                programDecrementUpdates.push(
                    programRef.update({
                        activeUsers: FieldValue.increment(-1)
                    }).catch(err => console.warn(`Failed to decrement activeUser for program ${cardData.programId}`, err))
                );
            }
        });

        await Promise.all([...cardDeletes, ...programDecrementUpdates]);

        // Delete the main doc
        await userRef.delete();

        console.log(`Account ${uid} deleted successfully.`);
        return { success: true };

    } catch (error) {
        console.error("Error deleting account:", error);
        throw new HttpsError('internal', 'Unable to delete account.');
    }
});

import { https } from "firebase-functions/v2";
const onCall = https.onCall;
const HttpsError = https.HttpsError;
import { getFirestore } from "firebase-admin/firestore";

interface GetCustomerProgramDataArgs {
    customerId: string;
    programId: string;
}

export const getCustomerProgramData = onCall(
    { region: "africa-south1", timeoutSeconds: 60 },
    async (request) => {
        if (!request.auth) {
            throw new HttpsError('unauthenticated', 'Sign in to lookup customer details.');
        }

        const { customerId, programId } = request.data as GetCustomerProgramDataArgs;
        if (!customerId || !programId) {
            throw new HttpsError('invalid-argument', 'Missing customerId or programId.');
        }

        const db = getFirestore("lekkerloyal-sa");

        try {
            // Fetch card progress
            const cardRef = db.collection("users").doc(customerId).collection("cards").doc(programId);
            const cardSnap = await cardRef.get();
            const stamps = cardSnap.exists ? (cardSnap.data()?.stamps || 0) : 0;

            // Fetch active rewards
            const rewardsRef = db.collection("users").doc(customerId).collection("rewards");
            const rewardsQuery = rewardsRef
                .where("programId", "==", programId)
                .where("status", "==", "active");
            const rewardsSnap = await rewardsQuery.get();

            const activeRewards = rewardsSnap.docs.map(doc => {
                const data = doc.data();
                return {
                    id: doc.id,
                    ...data,
                    earnedAt: data.earnedAt?.toDate?.()?.toISOString() || data.earnedAt || null,
                };
            });

            return {
                success: true,
                isEnrolled: cardSnap.exists,
                stamps,
                activeRewards,
            };
        } catch (error: any) {
            console.error("Error in getCustomerProgramData:", error);
            throw new HttpsError('internal', error.message || 'Failed to fetch customer program data.');
        }
    }
);

