import { https } from "firebase-functions/v2";
const onCall = https.onCall;
const HttpsError = https.HttpsError;
import { getFirestore } from "firebase-admin/firestore";

/**
 * getMyNotifications
 * Securely fetches notifications for the currently authenticated user.
 * This bypasses complex client-side rules allowing reliable Inbox access.
 */
export const getMyNotifications = onCall({ region: "africa-south1", timeoutSeconds: 60 }, async (request) => {
    if (!request.auth) {
        throw new HttpsError('unauthenticated', 'The function must be called while authenticated.');
    }

    const { uid } = request.auth;
    const db = getFirestore("lekkerloyal-sa");

    try {
        const notificationsRef = db.collection("notifications");
        // We only fetch notifications targeted at this specific user
        // We remove the orderBy and limit clauses here to avoid needing a composite index
        // Since a user won't have millions of notifications, we can sort and limit in memory.
        const snapshot = await notificationsRef
            .where('targetUsers', 'array-contains', uid)
            .get();

        const notifications = snapshot.docs.map(doc => {
            const data = doc.data();
            return {
                id: doc.id,
                ...data,
                // Convert Firestore timestamp to serialized timestamp for client
                timestamp: data.timestamp ? {
                    seconds: data.timestamp.seconds,
                    nanoseconds: data.timestamp.nanoseconds
                } : null
            };
        });

        // Sort in memory by timestamp descending
        notifications.sort((a, b) => {
            const timeA = a.timestamp ? a.timestamp.seconds : 0;
            const timeB = b.timestamp ? b.timestamp.seconds : 0;
            return timeB - timeA;
        });

        // Limit to 50
        const limitedNotifications = notifications.slice(0, 50);

        // Clear the unread notifications badge securely
        await db.collection("users").doc(uid).update({
            unreadNotifications: 0
        });

        return { success: true, notifications: limitedNotifications };
    } catch (error) {
        console.error("Error fetching notifications:", error);
        throw new HttpsError('internal', 'Unable to fetch notifications.');
    }
});

import { https } from "firebase-functions/v2";
const onRequest = https.onRequest;
import { getFirestore, FieldValue, Timestamp } from "firebase-admin/firestore";
import { defineSecret } from "firebase-functions/params";
import * as crypto from "crypto";

const PAYSTACK_SECRET = defineSecret("PAYSTACK_SECRET");
const PAYSTACK_SECRET_TEST = defineSecret("PAYSTACK_SECRET_TEST");

interface PaystackEvent {
    event: string;
    data?: {
        reference?: string;
        customer?: { customer_code?: string };
    };
}

/**
 * Verify the Paystack signature against the given secret and apply the event
 * to Firestore. Shared by the live and test webhook endpoints.
 */
async function processPaystackEvent(
    rawBody: Buffer,
    signature: string | undefined,
    body: unknown,
    secret: string,
    mode: "LIVE" | "TEST"
): Promise<{ status: number; message?: string }> {
    const hash = crypto.createHmac("sha512", secret).update(rawBody).digest("hex");

    if (hash !== signature) {
        console.error(`Invalid Paystack webhook signature (${mode}).`);
        return { status: 400, message: "Invalid signature" };
    }

    const event = body as PaystackEvent;
    console.log(`Paystack Webhook Event (${mode}):`, event.event, event.data?.reference);

    const db = getFirestore("lekkerloyal-sa");

    if (event.event === "charge.success") {
        const reference = event.data?.reference;
        const customerCode = event.data?.customer?.customer_code;

        if (customerCode) {
            console.log(`Processing subscription payment for customer code ${customerCode}`);

            const programsQuery = db.collection("programs").where("paystackCustomerCode", "==", customerCode);
            const programsSnap = await programsQuery.get();

            if (!programsSnap.empty) {
                const now = new Date();
                const nextExpiry = new Date(now.getTime() + (30 * 24 * 60 * 60 * 1000));

                const batch = db.batch();
                programsSnap.forEach((doc) => {
                    batch.update(doc.ref, {
                        subscriptionStatus: "active",
                        subscriptionExpiry: Timestamp.fromDate(nextExpiry),
                        updatedAt: FieldValue.serverTimestamp(),
                        lastPaymentRef: reference,
                    });
                });
                await batch.commit();
                console.log(`Successfully extended subscription for ${programsSnap.size} program(s).`);
            } else {
                console.warn(`No programs found matching customer code ${customerCode}`);
            }
        } else {
            console.warn("Missing customer_code in webhook data");
        }
    } else if (event.event === "invoice.payment_failed") {
        const customerCode = event.data?.customer?.customer_code;
        if (customerCode) {
            const programsQuery = db.collection("programs").where("paystackCustomerCode", "==", customerCode);
            const snap = await programsQuery.get();
            const batch = db.batch();
            snap.forEach((doc) => {
                batch.update(doc.ref, { subscriptionStatus: "past_due", updatedAt: FieldValue.serverTimestamp() });
            });
            await batch.commit();
            console.log(`Updated ${snap.size} programs to past_due via webhook`);
        }
    } else if (event.event === "subscription.disable") {
        const customerCode = event.data?.customer?.customer_code;
        if (customerCode) {
            const programsQuery = db.collection("programs").where("paystackCustomerCode", "==", customerCode);
            const snap = await programsQuery.get();
            const batch = db.batch();
            snap.forEach((doc) => {
                batch.update(doc.ref, { subscriptionStatus: "cancelled", updatedAt: FieldValue.serverTimestamp() });
            });
            await batch.commit();
            console.log(`Updated ${snap.size} programs to cancelled via webhook`);
        }
    }

    return { status: 200 };
}

/**
 * paystackWebhook (LIVE)
 * Receives production webhooks from Paystack. Verifies only against the live
 * secret. Configure this URL in your Paystack live dashboard.
 */
export const paystackWebhook = onRequest(
    { region: "africa-south1", timeoutSeconds: 60, secrets: [PAYSTACK_SECRET] },
    async (req, res) => {
        try {
            const signature = req.headers["x-paystack-signature"];
            const sig = Array.isArray(signature) ? signature[0] : signature;
            const result = await processPaystackEvent(req.rawBody, sig, req.body, PAYSTACK_SECRET.value(), "LIVE");
            if (result.message) {
                res.status(result.status).send(result.message);
            } else {
                res.sendStatus(result.status);
            }
        } catch (error) {
            console.error("Webhook Error (LIVE):", error);
            res.status(500).send("Internal Server Error");
        }
    }
);

/**
 * paystackWebhookTest (TEST)
 * Receives test-mode webhooks from Paystack. Verifies only against the test
 * secret. Configure this URL in your Paystack test dashboard.
 */
export const paystackWebhookTest = onRequest(
    { region: "africa-south1", timeoutSeconds: 60, secrets: [PAYSTACK_SECRET_TEST] },
    async (req, res) => {
        try {
            const signature = req.headers["x-paystack-signature"];
            const sig = Array.isArray(signature) ? signature[0] : signature;
            const result = await processPaystackEvent(req.rawBody, sig, req.body, PAYSTACK_SECRET_TEST.value(), "TEST");
            if (result.message) {
                res.status(result.status).send(result.message);
            } else {
                res.sendStatus(result.status);
            }
        } catch (error) {
            console.error("Webhook Error (TEST):", error);
            res.status(500).send("Internal Server Error");
        }
    }
);

import { https } from "firebase-functions/v2";
const onCall = https.onCall;
const HttpsError = https.HttpsError;
import { getFirestore } from "firebase-admin/firestore";
import * as types from "../types";

/**
 * getProgramClients
 * Callable function to retrieve all clients involved in a specific program.
 * Performs a collectionGroup query for 'cards' where programId matches.
 */
export const getProgramClients = onCall({ region: "africa-south1", timeoutSeconds: 60 }, async (request) => {
    if (!request.auth) {
        throw new HttpsError('unauthenticated', 'The function must be called while authenticated.');
    }

    const { programId } = request.data as types.GetProgramClientsData;
    const { uid } = request.auth;

    if (!programId) {
        throw new HttpsError('invalid-argument', 'Missing programId.');
    }

    const db = getFirestore("lekkerloyal-sa");

    try {
        // First confirm this merchant owns the program (security check)
        // Check if user is the Owner OR a Store Account linked to the owner
        const programRef = db.collection("programs").doc(programId);
        const programSnap = await programRef.get();

        if (!programSnap.exists) {
            throw new HttpsError('not-found', 'Program not found.');
        }

        const programData = programSnap.data();

        // Check permissions
        const isOwner = programData?.merchantId === uid;
        const isStore = (request.auth.token as { merchantId?: string }).merchantId === programData?.merchantId;

        if (!isOwner && !isStore) {
            throw new HttpsError('permission-denied', 'You do not own this program.');
        }

        // Query all cards with this programId
        const cardsQuery = db.collectionGroup('cards').where('programId', '==', programId);
        const querySnapshot = await cardsQuery.get();

        const clients: unknown[] = [];
        const promises: Promise<void>[] = [];

        querySnapshot.forEach((cardDoc) => {
            // The parent of a card is users/{userId}/cards
            // So ref.parent.parent.id gives us the userId
            const userId = cardDoc.ref.parent.parent?.id;
            if (userId) {
                const p = db.collection("users").doc(userId).get().then(userSnap => {
                    const userData = userSnap.data();
                    const cardData = cardDoc.data();

                    // Fix for "1/?" issue: Use card's total or fall back to program's stampsToComplete
                    const totalTarget = cardData.total || programData?.stampsToComplete || 10;

                    clients.push({
                        uid: userId,
                        firstName: userData?.firstName || "",
                        lastName: userData?.lastName || "",
                        // Return DOB for display
                        dob: userData?.dob || null,
                        ...cardData,
                        // Ensure total is populated
                        total: totalTarget,
                        // Ensure redeemedCount is present for Loyalty Score calculation
                        redeemedCount: cardData.redeemedCount || 0,
                        pendingRewards: cardData.pendingRewardsCount || 0,
                        email: userData?.email || "", // Be careful with PII, but merchant needs identification
                        phoneNumber: userData?.phoneNumber || ""
                    });
                });
                promises.push(p);
            }
        });

        await Promise.all(promises);

        console.log(`Fetched ${clients.length} clients for program ${programId}`);
        return { clients };

    } catch (error) {
        console.error("Error fetching program clients:", error);
        throw new HttpsError('internal', 'Unable to fetch clients.');
    }
});

import { https } from "firebase-functions/v2";
const onCall = https.onCall;
const HttpsError = https.HttpsError;
import { getFirestore, FieldValue } from "firebase-admin/firestore";
import * as types from "../types";

/**
 * markCelebrationSeen
 * Securely marks a loyalty card's celebration as seen.
 * Required because users do not have write access to their own card subcollections directly.
 */
export const markCelebrationSeen = onCall({ region: "africa-south1", timeoutSeconds: 60 }, async (request) => {
    if (!request.auth) {
        throw new HttpsError('unauthenticated', 'The function must be called while authenticated.');
    }

    const { programId } = request.data as types.MarkCelebrationSeenData;
    const { uid } = request.auth;
    const db = getFirestore("lekkerloyal-sa");

    if (!programId) {
        throw new HttpsError('invalid-argument', 'programId is required.');
    }

    try {
        await db.collection("users").doc(uid).collection("cards").doc(programId).update({
            celebrationSeen: true,
            updatedAt: FieldValue.serverTimestamp()
        });
        return { success: true };
    } catch (error) {
        console.error("Error marking celebration as seen:", error);
        throw new HttpsError('internal', 'Unable to mark celebration as seen.');
    }
});

import { https } from "firebase-functions/v2";
const onCall = https.onCall;
const HttpsError = https.HttpsError;
import { getFirestore, FieldValue } from "firebase-admin/firestore";
import * as types from "../types";

export const joinProgram = onCall(
    { region: "africa-south1", timeoutSeconds: 60 },
    async (request): Promise<types.JoinProgramResponse> => {
        if (!request.auth) {
            throw new HttpsError('unauthenticated', 'Sign in to join a loyalty program.');
        }

        const { programId } = request.data as types.JoinProgramData;
        const { uid } = request.auth;

        if (!programId) {
            throw new HttpsError('invalid-argument', 'Missing programId.');
        }

        const db = getFirestore("lekkerloyal-sa");

        return await db.runTransaction(async (transaction) => {
            const programRef = db.collection("programs").doc(programId);
            const cardRef = db.collection("users").doc(uid).collection("cards").doc(programId);

            const [programSnap, cardSnap] = await Promise.all([
                transaction.get(programRef),
                transaction.get(cardRef),
            ]);

            if (!programSnap.exists) {
                throw new HttpsError('not-found', 'Loyalty program not found.');
            }

            const programData = programSnap.data() as types.ProgramData;

            if (programData.subscriptionStatus === 'cancelled' || programData.subscriptionStatus === 'expired') {
                throw new HttpsError('failed-precondition', 'This loyalty program is no longer active.');
            }

            if (cardSnap.exists) {
                return { success: true, alreadyJoined: true };
            }

            const cardPayload: Record<string, unknown> = {
                programId,
                merchantId: programData.merchantId,
                storeName: programData.storeName,
                rewardDescription: programData.rewardDescription || "",
                programType: programData.programType || 'loyalty',
                selectedAccent: programData.selectedAccent || "#000000",
                logoUrl: programData.logoUrl || null,
                useLightOverlay: programData.useLightOverlay ?? false,
                termsConditions: programData.termsConditions || null,
                stamps: 0,
                total: programData.stampsToComplete || 10,
                updatedAt: FieldValue.serverTimestamp(),
                ...(programData.streakEnabled ? {
                    streakEnabled: true,
                    streakTargetVisits: programData.streakTargetVisits,
                    streakTimeframeDays: programData.streakTimeframeDays,
                    currentStreakVisits: 0,
                } : {}),
            };

            transaction.set(cardRef, cardPayload);
            transaction.update(programRef, {
                activeUsers: FieldValue.increment(1),
            });

            return { success: true, alreadyJoined: false };
        });
    },
);

import { https } from "firebase-functions/v2";
const onCall = https.onCall;
const HttpsError = https.HttpsError;
import { getFirestore } from "firebase-admin/firestore";

const ADMIN_UID = 'vi87NYSfdSZ8nZwEWN6GCqITJ8h1';
const ADMIN_EMAIL = 'lekkerloyal@gmail.com';

export const getAdminMerchants = onCall({ region: "africa-south1", timeoutSeconds: 60 }, async (request) => {
    // 1. Authenticate Request
    if (!request.auth) {
        throw new HttpsError('unauthenticated', 'Must be logged in.');
    }

    const uid = request.auth.uid;
    const email = request.auth.token.email;

    // 2. Authorize Admin
    if (uid !== ADMIN_UID && email !== ADMIN_EMAIL) {
        throw new HttpsError('permission-denied', 'Only admins can view the merchant directory.');
    }

    try {
        const db = getFirestore("lekkerloyal-sa");

        // 3. Fetch all merchants and stores
        const usersRef = db.collection('users');
        const [merchantSnap, storeSnap] = await Promise.all([
            usersRef.where('role', '==', 'merchant').get(),
            usersRef.where('role', '==', 'store').get()
        ]);

        const loaded: any[] = [];

        merchantSnap.forEach(doc => {
            const data = doc.data();
            loaded.push({ id: doc.id, email: data.email || 'No email', businessName: data.businessName || 'Unknown Business', role: 'merchant' });
        });

        storeSnap.forEach(doc => {
            const data = doc.data();
            loaded.push({ id: doc.id, email: data.email || 'No email', businessName: data.businessName || 'Unknown Business', role: 'store' });
        });

        // 4. Check if they have programs
        const programsSnap = await db.collection('programs').get();
        const merchantsWithPrograms = new Set();
        programsSnap.forEach(p => {
            merchantsWithPrograms.add(p.data().merchantId);
        });

        const enriched = loaded.map(m => ({
            ...m,
            hasProgram: merchantsWithPrograms.has(m.id)
        }));

        return { merchants: enriched };

    } catch (error) {
        console.error("Error fetching admin merchants:", error);
        throw new HttpsError('internal', 'An error occurred while fetching the merchant directory.');
    }
});

