export const adminConfigureProgram = onCall({ region: "africa-south1", timeoutSeconds: 60 }, async (request) => {
    // 1. Authenticate Request
    if (!request.auth) {
        throw new HttpsError('unauthenticated', 'Must be logged in.');
    }

    const uid = request.auth.uid;
    const email = request.auth.token.email;

    // 2. Authorize Admin
    if (uid !== ADMIN_UID && email !== ADMIN_EMAIL) {
        throw new HttpsError('permission-denied', 'Only admins can configure programs remotely.');
    }

    const { programId, programData } = request.data;
    if (!programData || !programData.merchantId) {
        throw new HttpsError('invalid-argument', 'Missing program data or merchantId.');
    }

    try {
        const db = getFirestore("lekkerloyal-sa");

