import { https } from "firebase-functions/v2";
const onCall = https.onCall;
const HttpsError = https.HttpsError;
import { getFirestore } from "firebase-admin/firestore";
import * as types from "../types";

/**
 * deleteLoyaltyProgram
 * Callable function to delete a program and cascade to user cards.
 */
export const deleteLoyaltyProgram = onCall({ region: "africa-south1", timeoutSeconds: 120 }, async (request) => {
    if (!request.auth) {
        throw new HttpsError('unauthenticated', 'The function must be called while authenticated.');
    }

    const { programId } = request.data as types.GetProgramClientsData;
    const { uid } = request.auth;

    if (!programId) {
        throw new HttpsError('invalid-argument', 'Missing programId.');
    }

    const db = getFirestore("lekkerloyal-sa");

    try {
        // 1. Verify Ownership
        const programRef = db.collection("programs").doc(programId);
        const programSnap = await programRef.get();

        if (!programSnap.exists) {
            throw new HttpsError('not-found', 'Program not found.');
        }

        const programData = programSnap.data();
        if (programData?.merchantId !== uid) {
            throw new HttpsError('permission-denied', 'You do not own this program.');
        }

        if ((programData?.activeUsers || 0) > 0) {
            throw new HttpsError(
                'failed-precondition',
                'Cannot delete a program with active customers. Please contact support if you need to remove this program.'
            );
        }

        // 2. Cascade Delete: Remove this card from all users' wallets
        // Note: For very large apps, this should be a background batch job.
        const cardsQuery = db.collectionGroup('cards').where('programId', '==', programId);
        const cardsSnap = await cardsQuery.get();

        const cardDeletes: Promise<FirebaseFirestore.WriteResult>[] = [];
        cardsSnap.forEach(doc => {
            cardDeletes.push(doc.ref.delete());
        });

        await Promise.all(cardDeletes);
        console.log(`Program ${programId} deleted. Removed ${cardDeletes.length} user cards.`);

        // 3. Delete the Program Document
        await programRef.delete();

        return { success: true };

    } catch (error) {
        console.error("Error deleting program:", error);
        if (error instanceof HttpsError) throw error;
        throw new HttpsError('internal', 'Unable to delete program.');
    }
});

