7	/**
8	 * getProgramClients
9	 * Callable function to retrieve all clients involved in a specific program.
10	 * Performs a collectionGroup query for 'cards' where programId matches.
11	 */
12	export const getProgramClients = onCall({ region: "africa-south1", timeoutSeconds: 60 }, async (request) => {
13	    if (!request.auth) {
14	        throw new HttpsError('unauthenticated', 'The function must be called while authenticated.');
15	    }
16	
17	    const { programId } = request.data as types.GetProgramClientsData;
18	    const { uid } = request.auth;
19	
20	    if (!programId) {
21	        throw new HttpsError('invalid-argument', 'Missing programId.');
22	    }
23	
24	    const db = getFirestore("lekkerloyal-sa");
25	
26	    try {
27	        // First confirm this merchant owns the program (security check)
28	        // Check if user is the Owner OR a Store Account linked to the owner
29	        const programRef = db.collection("programs").doc(programId);
30	        const programSnap = await programRef.get();
31	
32	        if (!programSnap.exists) {
33	            throw new HttpsError('not-found', 'Program not found.');
34	        }
35	
36	        const programData = programSnap.data();
37	
38	        // Check permissions
39	        const isOwner = programData?.merchantId === uid;
40	        const isStore = (request.auth.token as { merchantId?: string }).merchantId === programData?.merchantId;
41	
42	        if (!isOwner && !isStore) {
43	            throw new HttpsError('permission-denied', 'You do not own this program.');
44	        }
45	
46	        // Query all cards with this programId
47	        const cardsQuery = db.collectionGroup('cards').where('programId', '==', programId);
48	        const querySnapshot = await cardsQuery.get();
49	
50	        const clients: unknown[] = [];
51	        const promises: Promise<void>[] = [];
52	
53	        querySnapshot.forEach((cardDoc) => {
54	            // The parent of a card is users/{userId}/cards
55	            // So ref.parent.parent.id gives us the userId
56	            const userId = cardDoc.ref.parent.parent?.id;
57	            if (userId) {
58	                const p = db.collection("users").doc(userId).get().then(userSnap => {
59	                    const userData = userSnap.data();
60	                    const cardData = cardDoc.data();
61	
62	                    // Fix for "1/?" issue: Use card's total or fall back to program's stampsToComplete
63	                    const totalTarget = cardData.total || programData?.stampsToComplete || 10;
64	
65	                    clients.push({
66	                        uid: userId,
67	                        firstName: userData?.firstName || "",
68	                        lastName: userData?.lastName || "",
69	                        // Return DOB for display
70	                        dob: userData?.dob || null,
71	                        ...cardData,
72	                        // Ensure total is populated
73	                        total: totalTarget,
