77	                        email: userData?.email || "", // Be careful with PII, but merchant needs identification
78	                        phoneNumber: userData?.phoneNumber || ""
79	                    });
80	                });
81	                promises.push(p);
82	            }
83	        });
84	
85	        await Promise.all(promises);
