import * as admin from "firebase-admin";

export interface BankingDetails {
    bankName: string;
    bankCode: string;
    accountNumber: string;
    accountHolder: string;
}

export interface OnboardUserData {
    role: 'merchant' | 'customer';
    firstName?: string;
    lastName?: string;
    businessName?: string;
    dob?: string;
    phoneNumber?: string;
}

export interface UpdateProfileData {
    firstName?: string;
    lastName?: string;
    businessName?: string;
    dob?: string;
    phoneNumber?: string;
}

export interface CreateLoyaltyProgramData {
    storeName: string;
    rewardDescription: string;
    programType?: 'loyalty' | 'service_package';
    stampsToComplete: number;
    selectedAccent?: string;
    useLightOverlay?: boolean;
    logoUrl?: string;
    rewardExpiryDays?: number | null;
    termsConditions?: string | null;
    streakEnabled?: boolean;
    streakTargetVisits?: number;
    streakTimeframeDays?: number;
}

export interface AddStampData {
    programId: string;
    customerId: string;
    stampCount?: number;
}

export interface RedeemRewardData {
    rewardId: string;
    customerId: string;
}

export interface RewardData {
    programId: string;
    merchantId: string;
    storeName: string;
    rewardDescription: string;
    programType?: 'loyalty' | 'service_package';
    earnedAt: admin.firestore.FieldValue;
    expiryDate: string; // ISO string
    status: 'active' | 'redeemed' | 'expired';
    redeemedAt?: admin.firestore.FieldValue;
    logoUrl?: string | null;
    selectedAccent?: string;
    useLightOverlay?: boolean;
}

export interface GetProgramClientsData {
    programId: string;
}

export interface SendNotificationData {
    merchantId: string;
    title: string;
    body: string;
}



export interface MarkCelebrationSeenData {
    programId: string;
}

export interface UpdateLoyaltyProgramData extends Partial<CreateLoyaltyProgramData> {
    programId: string;
}

export interface UserData {
    email: string;
    role: string;
    onboardedAt: admin.firestore.FieldValue;
    updatedAt: admin.firestore.FieldValue;
    firstName?: string;
    lastName?: string;
    businessName?: string;
    dob?: string | null;
