/* eslint-disable @typescript-eslint/no-explicit-any */
import {
  createDocSnap,
  createQuerySnap,
  mockFieldValue,
  mockTimestamp,
  mockFetch,
} from "./mocks";

jest.mock("firebase-admin", () => ({
  firestore: {
    FieldValue: {
      serverTimestamp: () => mockFieldValue.serverTimestamp(),
      increment: (n: number) => mockFieldValue.increment(n),
    },
    Timestamp: {
      now: () => mockTimestamp.now(),
    },
  },
}));

import { sendPushBatch, sendSystemNotification, mergeGuestData } from "../helpers";

describe("helpers", () => {
  beforeEach(() => jest.clearAllMocks());

  describe("sendPushBatch", () => {
    it("does nothing for empty message array", async () => {
      const fetchMock = mockFetch();
      await sendPushBatch([]);
      expect(fetchMock).not.toHaveBeenCalled();
    });

    it("calls Expo Push API with correct payload", async () => {
      const fetchMock = mockFetch();
      const messages = [
        { to: "ExponentPushToken[xxx]", title: "Test", body: "Hello" },
      ];
      await sendPushBatch(messages);
      expect(fetchMock).toHaveBeenCalledWith(
        "https://exp.host/--/api/v2/push/send",
        expect.objectContaining({
          method: "POST",
          body: JSON.stringify(messages),
        }),
      );
    });

    it("logs error on failed response", async () => {
      mockFetch({}, false);
      const consoleSpy = jest.spyOn(console, "error").mockImplementation();
      await sendPushBatch([{ to: "token", title: "T", body: "B" }]);
      expect(consoleSpy).toHaveBeenCalled();
    });
  });

  describe("sendSystemNotification", () => {
    it("sends push and creates inbox record", async () => {
      const fetchMock = mockFetch();
      const mockUpdate = jest.fn().mockResolvedValue(undefined);
      const mockAdd = jest.fn().mockResolvedValue({ id: "notif-id" });

      const db = {
        collection: jest.fn().mockImplementation((col: string) => {
          if (col === "users") {
            return {
              doc: jest.fn().mockReturnValue({
                get: jest.fn().mockResolvedValue(
                  createDocSnap("user-1", { expoPushToken: "ExponentPushToken[abc]" }),
                ),
                update: mockUpdate,
              }),
            };
          }
          return { add: mockAdd };
        }),
      } as any;

      await sendSystemNotification(db, "user-1", "Test Title", "Test Body");

      expect(fetchMock).toHaveBeenCalled();
      expect(mockUpdate).toHaveBeenCalled();
      expect(mockAdd).toHaveBeenCalledWith(
        expect.objectContaining({
          merchantId: "SYSTEM",
          merchantName: "LekkerLoyal",
          title: "Test Title",
          body: "Test Body",
          targetUsers: ["user-1"],
        }),
      );
    });

    it("still creates inbox even without push token", async () => {
      const fetchMock = mockFetch();
      const mockUpdate = jest.fn().mockResolvedValue(undefined);
      const mockAdd = jest.fn().mockResolvedValue({ id: "notif-id" });

      const db = {
        collection: jest.fn().mockImplementation((col: string) => {
          if (col === "users") {
            return {
              doc: jest.fn().mockReturnValue({
                get: jest.fn().mockResolvedValue(
                  createDocSnap("user-1", {}),
                ),
                update: mockUpdate,
              }),
            };
          }
          return { add: mockAdd };
        }),
      } as any;

      await sendSystemNotification(db, "user-1", "Title", "Body");

      expect(fetchMock).not.toHaveBeenCalled();
      expect(mockAdd).toHaveBeenCalled();
    });
  });

  describe("mergeGuestData", () => {
    it("does nothing when no guest profiles found", async () => {
      const db = {
        collection: jest.fn().mockReturnValue({
          where: jest.fn().mockReturnThis(),
          get: jest.fn().mockResolvedValue(createQuerySnap([])),
        }),
      } as any;

      await mergeGuestData(db, "new-uid", "+27821234567");
    });

    it("copies cards from guest to new user and cleans up", async () => {
      const guestDoc = createDocSnap("guest-uid", { phoneNumber: "+27821234567", isGuest: true });
      const cardDoc = createDocSnap("card-1", { programId: "p1", stamps: 3 });

      const mockBatchSet = jest.fn();
      const mockBatchDelete = jest.fn();
      const mockBatchUpdate = jest.fn();
      const mockBatchCommit = jest.fn().mockResolvedValue(undefined);

      const cardsSnap = createQuerySnap([cardDoc]);
