import * as helpers from "../helpers";

// ── Test Data ──────────────────────────────────────────────────────
const MERCHANT_UID = "merchant-001";
const CUSTOMER_UID = "customer-001";
const PROGRAM_ID = "program-001";

const baseProgramData = {
  merchantId: MERCHANT_UID,
  storeName: "Test Coffee",
  stampsToComplete: 5,
  rewardDescription: "Free Coffee",
  selectedAccent: "#00E676",
  useLightOverlay: false,
  logoUrl: null,
  rewardExpiryDays: 90,
};

/**
 * Creates a mock Firestore that the addStamp transaction logic can navigate.
 * The key challenge: addStamp uses `transaction.get(programRef)` and `transaction.get(cardRef)`
 * and differentiates by the ref object. We track which refs are created and map them.
 */
function setupDb(overrides: {
  programData?: Record<string, any> | undefined;
  cardData?: Record<string, any> | undefined;
  trialExpired?: boolean;
  subscriptionExpired?: boolean;
} = {}) {
  const now = new Date();
  const programData = "programData" in overrides
    ? overrides.programData
    : { ...baseProgramData };

  if (programData && overrides.trialExpired) {
    const pastDate = new Date(now.getTime() - 31 * 24 * 60 * 60 * 1000);
    programData.trialStartedAt = { toDate: () => pastDate };
    programData.subscriptionStatus = "trial";
  }

  if (programData && overrides.subscriptionExpired) {
    const pastDate = new Date(now.getTime() - 1 * 24 * 60 * 60 * 1000);
    programData.subscriptionStatus = "active";
    programData.subscriptionExpiry = { toDate: () => pastDate };
    // Must include trialStartedAt, otherwise addStamp resets status to 'trial'
    programData.trialStartedAt = { toDate: () => new Date(now.getTime() - 60 * 24 * 60 * 60 * 1000) };
  }

  const cardData = overrides.cardData;

  const programSnap = createDocSnap(PROGRAM_ID, programData ?? undefined);
  const cardSnap = createDocSnap(PROGRAM_ID, cardData);

  // Track refs to distinguish program vs card in transaction.get()
  const programRef = {
    id: PROGRAM_ID,
    _type: "program",
    get: jest.fn().mockResolvedValue(programSnap),
  };
  const cardRef = { id: PROGRAM_ID, _type: "card" }; // same id, different ref object

  const txSet = jest.fn();
  const txUpdate = jest.fn();
  const txDelete = jest.fn();

  const txGet = jest.fn().mockImplementation((ref: any) => {
    if (ref._type === "program") return Promise.resolve(programSnap);
    if (ref._type === "card") return Promise.resolve(cardSnap);
    return Promise.resolve(createDocSnap(ref.id, undefined));
  });

  const mockRunTransaction = jest.fn().mockImplementation(
    (fn: (t: any) => Promise<any>) => fn({ get: txGet, set: txSet, update: txUpdate, delete: txDelete }),
  );

  const mockCollection = jest.fn().mockImplementation((colName: string) => {
    if (colName === "programs") {
      return {
        doc: jest.fn().mockReturnValue(programRef),
        add: jest.fn().mockResolvedValue({ id: "new-id" }),
      };
    }
    if (colName === "users") {
      return {
        doc: jest.fn().mockImplementation((userId: string) => ({
          id: userId,
          get: jest.fn().mockResolvedValue(createDocSnap(userId, {})),
          collection: jest.fn().mockImplementation((subCol: string) => {
            if (subCol === "cards") {
              return { doc: jest.fn().mockReturnValue(cardRef) };
            }
            if (subCol === "rewards") {
              return { doc: jest.fn().mockReturnValue({ id: "reward-auto" }) };
            }
            return {};
          }),
        })),
      };
    }
    return {
      doc: jest.fn().mockImplementation((docId: string) => ({
        id: docId,
        get: jest.fn().mockResolvedValue(createDocSnap(docId, programData ?? undefined)),
      })),
      add: jest.fn().mockResolvedValue({ id: "notif-id" }),
    };
  });

  const db = {
    collection: mockCollection,
    collectionGroup: jest.fn(),
    batch: jest.fn(),
    runTransaction: mockRunTransaction,
  };

  (getFirestore as jest.Mock).mockReturnValue(db);

  return { db, txSet, txUpdate };
}

// ── Tests ──────────────────────────────────────────────────────────
describe("addStamp", () => {
  beforeEach(() => {
    jest.clearAllMocks();
    mockFetch();
  });

  it("rejects unauthenticated calls", async () => {
    setupDb();
    const req = createMockRequest({ programId: PROGRAM_ID, customerId: CUSTOMER_UID });
    await expect((addStamp as any)(req)).rejects.toThrow("authenticated");
  });

  it("rejects missing programId", async () => {
    setupDb();
    const req = createMockRequest({ customerId: CUSTOMER_UID }, MERCHANT_UID);
    await expect((addStamp as any)(req)).rejects.toThrow("Missing required");
  });

  it("rejects missing customerId", async () => {
    setupDb();
    const req = createMockRequest({ programId: PROGRAM_ID }, MERCHANT_UID);
    await expect((addStamp as any)(req)).rejects.toThrow("Missing required");
  });

  it("rejects when program not found", async () => {
    setupDb({ programData: undefined });
    const req = createMockRequest(
      { programId: PROGRAM_ID, customerId: CUSTOMER_UID },
      MERCHANT_UID,
    );
    await expect((addStamp as any)(req)).rejects.toThrow("not found");
  });

  it("rejects non-owner / non-store callers", async () => {
    setupDb();
    const req = createMockRequest(
      { programId: PROGRAM_ID, customerId: CUSTOMER_UID },
      "stranger-uid",
    );
    await expect((addStamp as any)(req)).rejects.toThrow("do not own");
  });

  it("adds 1 stamp to a new card (creates card)", async () => {
    const { txSet } = setupDb({ cardData: undefined }); // card doesn't exist
    const req = createMockRequest(
      { programId: PROGRAM_ID, customerId: CUSTOMER_UID },
      MERCHANT_UID,
    );
    const result = await (addStamp as any)(req);
    expect(result.success).toBe(true);
    expect(result.newStamps).toBe(1);
    expect(result.rewardsEarned).toBe(0);
    expect(txSet).toHaveBeenCalled(); // uses set for new card
  });

  it("adds stamps to existing card", async () => {
    const { txUpdate } = setupDb({ cardData: { stamps: 2 } });
    const req = createMockRequest(
      { programId: PROGRAM_ID, customerId: CUSTOMER_UID },
      MERCHANT_UID,
    );
    const result = await (addStamp as any)(req);
    expect(result.success).toBe(true);
    expect(result.newStamps).toBe(3); // 2 + 1
    expect(result.rewardsEarned).toBe(0);
    expect(txUpdate).toHaveBeenCalled(); // uses update for existing card
  });

  it("earns a reward when stamp threshold is met", async () => {
    setupDb({ cardData: { stamps: 4 } }); // 4 + 1 = 5 = stampsToComplete
    const req = createMockRequest(
      { programId: PROGRAM_ID, customerId: CUSTOMER_UID },
      MERCHANT_UID,
    );
    const result = await (addStamp as any)(req);
    expect(result.success).toBe(true);
    expect(result.rewardsEarned).toBe(1);
    expect(result.newStamps).toBe(0);
  });

  it("handles multi-stamp (stampCount > 1)", async () => {
    setupDb({ cardData: { stamps: 0 } });
    const req = createMockRequest(
      { programId: PROGRAM_ID, customerId: CUSTOMER_UID, stampCount: 3 },
      MERCHANT_UID,
    );
    const result = await (addStamp as any)(req);
    expect(result.success).toBe(true);
    expect(result.newStamps).toBe(3);
  });

  it("earns multiple rewards with multi-stamp overflow", async () => {
    setupDb({ cardData: { stamps: 3 } }); // 3 + 8 = 11, 11/5 = 2 rewards, remainder 1
    const req = createMockRequest(
      { programId: PROGRAM_ID, customerId: CUSTOMER_UID, stampCount: 8 },
      MERCHANT_UID,
    );
    const result = await (addStamp as any)(req);
    expect(result.rewardsEarned).toBe(2);
    expect(result.newStamps).toBe(1);
  });

  it("blocks when trial has expired", async () => {
    setupDb({ trialExpired: true, cardData: { stamps: 0 } });
    const req = createMockRequest(
      { programId: PROGRAM_ID, customerId: CUSTOMER_UID },
      MERCHANT_UID,
    );
    await expect((addStamp as any)(req)).rejects.toThrow("trial has ended");
  });

  it("blocks when subscription has expired", async () => {
    setupDb({ subscriptionExpired: true, cardData: { stamps: 0 } });
    const req = createMockRequest(
      { programId: PROGRAM_ID, customerId: CUSTOMER_UID },
      MERCHANT_UID,
    );
    await expect((addStamp as any)(req)).rejects.toThrow("Subscription expired");
  });

  it("sends system notification when reward is earned", async () => {
    setupDb({ cardData: { stamps: 4 } }); // 4+1=5 → reward
    const req = createMockRequest(
      { programId: PROGRAM_ID, customerId: CUSTOMER_UID },
      MERCHANT_UID,
    );
    await (addStamp as any)(req);
    expect(helpers.sendSystemNotification).toHaveBeenCalledWith(
      expect.anything(),
      CUSTOMER_UID,
      "Reward Unlocked! 🎉",
      expect.stringContaining("Test Coffee"),
