    });
    const req = createMockRequest({ programId: PROGRAM_ID, customerId: CUSTOMER_UID }, MERCHANT_UID);
    const result = await (addStamp as any)(req);
    // 1 current + 1 added + 1 bonus = 3 total stamps
    expect(result.newStamps).toBe(3);
    expect(result.message).toContain("1 Bonus Streak Stamp added");
    expect(txUpdate).toHaveBeenCalledWith(
      expect.anything(),
      expect.objectContaining({
        currentStreakVisits: 0,
        streakStartDate: null,
      })
    );
  });

  it("breaks streak and restarts if visited outside timeframe", async () => {
    const now = new Date();
    const streakStart = new Date(now.getTime() - (10 * 24 * 60 * 60 * 1000)); // 10 days ago (outside 7 days)
    const { txUpdate } = setupDb({
      programData: {
        ...baseProgramData,
        streakEnabled: true,
        streakTargetVisits: 3,
        streakTimeframeDays: 7,
      },
      cardData: {
        stamps: 1,
        currentStreakVisits: 2,
        streakStartDate: { toDate: () => streakStart },
      },
    });
    const req = createMockRequest({ programId: PROGRAM_ID, customerId: CUSTOMER_UID }, MERCHANT_UID);
    const result = await (addStamp as any)(req);
    expect(result.newStamps).toBe(2); // Just the normal +1
    expect(txUpdate).toHaveBeenCalledWith(
      expect.anything(),
      expect.objectContaining({
        currentStreakVisits: 1, // Reset to 1 for this new visit
      })
    );
  });

  it("sends progress notification when one visit away from bonus stamp", async () => {
    const now = new Date();
    const streakStart = new Date(now.getTime() - (2 * 24 * 60 * 60 * 1000));
    setupDb({
      programData: {
