        streakStartDate: { toDate: () => streakStart },
      },
    });
    const req = createMockRequest({ programId: PROGRAM_ID, customerId: CUSTOMER_UID }, MERCHANT_UID);
    await (addStamp as any)(req);
    expect(helpers.sendSystemNotification).toHaveBeenCalledWith(
      expect.anything(),
      CUSTOMER_UID,
      "Streak Active! 🔥",
      expect.stringContaining("Only 1 more visit needed")
    );
  });

  it("sends completion notification when streak target is met", async () => {
    const now = new Date();
    const streakStart = new Date(now.getTime() - (2 * 24 * 60 * 60 * 1000));
