/**
 * Integration test: Scheduled functions
 *
 * Tests sweepExpiredRewards against the emulator by creating
 * expired reward documents and verifying they get swept.
 *
 * Note: The pubsub emulator is not running, so we can't trigger
 * scheduled functions directly. Instead we test the Firestore
 * state that sweepExpiredRewards would act on.
 */
import {
  onboardMerchant,
  onboardCustomer,
  createProgram,
  addStamps,
  joinProgram,
  getRewards,
  getDb,
  cleanupTestData,
} from "./helpers";

const MERCHANT_UID = "integ-scheduled-m";
const MERCHANT_EMAIL = "scheduled-m@test.com";
const CUSTOMER_UID = "integ-scheduled-c";
const CUSTOMER_EMAIL = "scheduled-c@test.com";

let programId: string;

beforeAll(async () => {
  await onboardMerchant(MERCHANT_UID, MERCHANT_EMAIL, {
    businessName: "Scheduled Test Cafe",
  });
  programId = await createProgram(MERCHANT_UID, {
    storeName: "Scheduled Test Cafe",
    stampsToComplete: 2,
  });
  await onboardCustomer(CUSTOMER_UID, CUSTOMER_EMAIL, {
    firstName: "Scheduled",
    lastName: "Tester",
  });
  await joinProgram(CUSTOMER_UID, CUSTOMER_EMAIL, programId);
});

afterAll(async () => {
  try {
    await cleanupTestData();
  } catch { /* best effort */ }
});

describe("Scheduled functions — reward expiry state", () => {
  it("creates rewards with expiry dates that can be swept", async () => {
    const r1 = await addStamps(MERCHANT_UID, programId, CUSTOMER_UID, 1);
    expect(r1.rewardsEarned).toBe(0);

    const r2 = await addStamps(MERCHANT_UID, programId, CUSTOMER_UID, 1);
    expect(r2.rewardsEarned).toBe(1);

    const rewards = await getRewards(CUSTOMER_UID, programId);
    expect(rewards.length).toBe(1);
    expect(rewards[0].status).toBe("active");
    expect(rewards[0].expiryDate).toBeTruthy();
  });

  it("simulates expired reward by writing past-date reward directly", async () => {
    const db = getDb();
    const pastDate = new Date(Date.now() - 86400000).toISOString();
    await db.collection("users").doc(CUSTOMER_UID).collection("rewards").add({
      programId,
      merchantId: MERCHANT_UID,
      storeName: "Scheduled Test Cafe",
      rewardDescription: "Expired Test Reward",
      earnedAt: new Date(Date.now() - 200 * 86400000),
      expiryDate: pastDate,
      status: "active",
    });

    const rewards = await getRewards(CUSTOMER_UID, programId);
    const activeRewards = rewards.filter((r) => r.status === "active");
    const expiredCandidate = activeRewards.find((r) => {
      return r.expiryDate && new Date(r.expiryDate) < new Date();
    });
    expect(expiredCandidate).toBeDefined();
  });
});

/**
 * Integration tests for Paystack integrations: setupSubscription, deleteAccount, and paystackWebhook.
 *
 * Runs against the local Firebase Emulator Suite with a built-in HTTP mock server.
 */
import * as http from "http";
import * as crypto from "crypto";
import {
  onboardMerchant,
  createProgram,
  getProgramDoc,
  cleanupTestData,
  callFunction,
  getDb,
} from "./helpers";

const PORT = 9090;
let server: http.Server;

const transactionVerifyResponse = {
  status: true,
  data: {
    status: "success",
    reference: "test-ref-success",
    customer: {
      customer_code: "CUST_mock123",
      id: 111222
    },
    authorization: {
      authorization_code: "AUTH_mock123",
      account_name: "Mock Holder",
      last4: "9999",
      bank: "Mock Bank"
    }
  }
};

const existingSubsResponse = {
  status: true,
  data: [
    {
      status: "active",
      subscription_code: "SUB_mock123",
      email_token: "TOKEN_mock123",
      plan: {
        plan_code: "PLN_pnei7dyejj7145i"
      }
    }
  ]
};

const disableSubResponse = {
  status: true,
  message: "Subscription disabled successfully"
};

const createSubResponse = {
  status: true,
  data: {
    subscription_code: "SUB_new123",
    next_payment_date: "2026-07-28T00:00:00.000Z"
  }
};

const getCustomerResponse = {
  status: true,
  data: {
    id: 111222
  }
};

const getSubResponse = {
  status: true,
  data: {
    email_token: "TOKEN_mock123"
  }
};

beforeAll(async () => {
  // Start the mock Paystack HTTP server
  server = http.createServer((req, res) => {
    const url = req.url || "";
    const method = req.method || "GET";

    res.writeHead(200, { "Content-Type": "application/json" });

    if (method === "GET" && url.startsWith("/transaction/verify/")) {
      res.end(JSON.stringify(transactionVerifyResponse));
    } else if (method === "GET" && url.startsWith("/subscription?customer=")) {
      res.end(JSON.stringify(existingSubsResponse));
    } else if (method === "POST" && url === "/subscription/disable") {
      res.end(JSON.stringify(disableSubResponse));
    } else if (method === "POST" && url === "/subscription") {
      res.end(JSON.stringify(createSubResponse));
    } else if (method === "GET" && url.startsWith("/customer/")) {
      res.end(JSON.stringify(getCustomerResponse));
    } else if (method === "GET" && url.startsWith("/subscription/")) {
      res.end(JSON.stringify(getSubResponse));
    } else {
      res.writeHead(404);
      res.end();
    }
  });

  await new Promise<void>((resolve) => server.listen(PORT, resolve));
});

afterAll(async () => {
  await new Promise<void>((resolve) => server.close(() => resolve()));
  await cleanupTestData();
});

describe("Paystack Integration tests", () => {
  const MERCHANT_UID = "integ-paystack-m";
  const MERCHANT_EMAIL = "paystack-m@test.com";

  it("sets up subscription successfully", async () => {
    // 1. Onboard Merchant
    await onboardMerchant(MERCHANT_UID, MERCHANT_EMAIL, {
      businessName: "Paystack Merchant Store",
    });

    // 2. Call setupSubscription (which will call our mock server)
    const result = await callFunction<{ success: boolean; programId: string }>(
      "setupSubscription",
      {
        reference: "test-ref-success",
        isTestMode: true,
        programData: {
          storeName: "Mock Store",
          rewardDescription: "Free Drink",
          stampsToComplete: 8,
          programType: "loyalty"
        }
      },
      { uid: MERCHANT_UID, token: { email: MERCHANT_EMAIL } }
    );

    expect(result.success).toBe(true);
    expect(result.programId).toBeDefined();

    // 3. Assert Firestore Program Doc is set to active and has codes
    const program = await getProgramDoc(result.programId);
    expect(program).not.toBeNull();
    expect(program!.subscriptionStatus).toBe("active");
    expect(program!.paystackCustomerCode).toBe("CUST_mock123");
    expect(program!.paystackSubscriptionCode).toBe("SUB_new123");
  });

  it("deletes account and cancels Paystack subscriptions", async () => {
    const result = await callFunction<{ success: boolean }>(
      "deleteAccount",
      {},
      { uid: MERCHANT_UID, token: { role: "merchant", email: MERCHANT_EMAIL } }
    );

    expect(result.success).toBe(true);
  });

  it("processes paystack webhook event", async () => {
    const db = getDb();
    const pid = "prog-webhook-test";
    await db.collection("programs").doc(pid).set({
      merchantId: "test-webhook-m",
      storeName: "Webhook Store",
      paystackCustomerCode: "CUST_webhook123",
      subscriptionStatus: "past_due"
    });

    // Mock incoming webhook event
    const webhookPayload = {
      event: "charge.success",
      data: {
        reference: "ref-webhook-success",
        customer: {
          customer_code: "CUST_webhook123"
        }
      }
    };
    const rawBody = JSON.stringify(webhookPayload);
    const testSecret = "mock-secret-test";
    const signature = crypto.createHmac("sha512", testSecret).update(rawBody).digest("hex");

    // Call the test webhook HTTP endpoint
    const response = await fetch("http://127.0.0.1:5001/lekkerloyal-app/africa-south1/paystackWebhookTest", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "x-paystack-signature": signature
      },
      body: rawBody
    });

    expect(response.status).toBe(200);

    // Verify program status was updated to active
    const snap = await db.collection("programs").doc(pid).get();
    expect(snap.data()?.subscriptionStatus).toBe("active");
    expect(snap.data()?.lastPaymentRef).toBe("ref-webhook-success");

    // Clean up
    await db.collection("programs").doc(pid).delete();
  });
});

