73	 * and differentiates by the ref object. We track which refs are created and map them.
74	 */
75	function setupDb(overrides: {
76	  programData?: Record<string, any> | undefined;
77	  cardData?: Record<string, any> | undefined;
78	  trialExpired?: boolean;
79	  subscriptionExpired?: boolean;
