/**
 * Centralized mock factories for Firebase Functions unit tests.
 *
 * Usage:
 *   import { createMockFirestore, createMockRequest, mockFetch } from "./mocks";
 */

/* ---------- Firestore Mock ---------- */

export interface MockDocSnap {
  exists: boolean;
  id: string;
  ref: { parent: { parent: { id: string } | null }; delete: jest.Mock };
  data: () => Record<string, unknown> | undefined;
}

export interface MockQuerySnap {
  empty: boolean;
  size: number;
  docs: MockDocSnap[];
  forEach: (cb: (doc: MockDocSnap) => void) => void;
}

export function createDocSnap(
  id: string,
  data: Record<string, unknown> | undefined,
  parentUserId?: string,
): MockDocSnap {
  return {
    exists: data !== undefined,
    id,
    ref: {
      parent: { parent: parentUserId ? { id: parentUserId } : null },
      delete: jest.fn(),
    },
    data: () => data,
  };
}

export function createQuerySnap(docs: MockDocSnap[]): MockQuerySnap {
  return {
    empty: docs.length === 0,
    size: docs.length,
    docs,
    forEach: (cb: (doc: MockDocSnap) => void) => docs.forEach(cb),
  };
}

export interface MockFirestore {
  collection: jest.Mock;
  collectionGroup: jest.Mock;
  batch: jest.Mock;
  runTransaction: jest.Mock;
  // Internal tracking helpers
  _docs: Map<string, MockDocSnap>;
  _setDoc: (path: string, snap: MockDocSnap) => void;
}

/**
 * Creates a mock Firestore instance.
 *
 * `docResults` maps "collection/docId" → data object (or undefined for non-existent).
 * `queryResults` maps "collection" → array of doc snapshots for `.get()` on queries.
 */
export function createMockFirestore(
  docResults: Record<string, Record<string, unknown> | undefined> = {},
  queryResults: Record<string, MockDocSnap[]> = {},
): MockFirestore {
  const _docs = new Map<string, MockDocSnap>();

  // Populate _docs
  for (const [path, data] of Object.entries(docResults)) {
    const parts = path.split("/");
    const id = parts[parts.length - 1];
    _docs.set(path, createDocSnap(id, data));
  }

  const mockUpdate = jest.fn().mockResolvedValue(undefined);
  const mockSet = jest.fn().mockResolvedValue(undefined);
  const mockAdd = jest.fn().mockImplementation(() =>
    Promise.resolve({ id: "generated-id-" + Math.random().toString(36).slice(2, 8) }),
  );
  const mockDelete = jest.fn();

  const mockDoc = jest.fn().mockImplementation((docId: string) => {
    // Try to find a matching doc from any collection path
    const matchingKey = Array.from(_docs.keys()).find((k) => k.endsWith("/" + docId));
    const snap = matchingKey ? _docs.get(matchingKey) : createDocSnap(docId, undefined);

    return {
      id: docId,
      get: jest.fn().mockResolvedValue(snap),
      set: mockSet,
      update: mockUpdate,
      delete: mockDelete,
      collection: (subCol: string) => ({
        doc: (subDocId?: string) => {
          const subPath = subCol + "/" + (subDocId || "auto-id");
          const subSnap = _docs.get(subPath) || createDocSnap(subDocId || "auto-id", undefined);
          return {
            id: subDocId || "auto-id",
            get: jest.fn().mockResolvedValue(subSnap),
            set: mockSet,
            update: mockUpdate,
            delete: mockDelete,
          };
        },
        get: jest.fn().mockResolvedValue(
          createQuerySnap(queryResults[subCol] || []),
        ),
        add: mockAdd,
      }),
    };
  });

  const mockWhere = jest.fn().mockReturnThis();
  const mockLimit = jest.fn().mockReturnThis();

  const mockCollection = jest.fn().mockImplementation((_colName: string) => ({
    doc: mockDoc,
    add: mockAdd,
    where: mockWhere,
    limit: mockLimit,
    get: jest.fn().mockResolvedValue(
      createQuerySnap(queryResults[_colName] || []),
    ),
  }));

  const mockCollectionGroup = jest.fn().mockImplementation((_groupName: string) => ({
    where: mockWhere,
    get: jest.fn().mockResolvedValue(
      createQuerySnap(queryResults[_groupName] || []),
    ),
  }));

  const mockBatchUpdate = jest.fn();
  const mockBatchSet = jest.fn();
  const mockBatchDelete = jest.fn();
  const mockBatchCommit = jest.fn().mockResolvedValue(undefined);
  const mockBatch = jest.fn().mockReturnValue({
    update: mockBatchUpdate,
    set: mockBatchSet,
    delete: mockBatchDelete,
    commit: mockBatchCommit,
  });

  const mockTransaction = {
    get: jest.fn().mockImplementation((ref: { id: string }) => {
      const matchingKey = Array.from(_docs.keys()).find((k) => k.endsWith("/" + ref.id));
      return Promise.resolve(
        matchingKey ? _docs.get(matchingKey) : createDocSnap(ref.id, undefined),
      );
    }),
    set: jest.fn(),
    update: jest.fn(),
    delete: jest.fn(),
  };

  const mockRunTransaction = jest.fn().mockImplementation(
    (fn: (t: typeof mockTransaction) => Promise<unknown>) => fn(mockTransaction),
  );

  const db: MockFirestore = {
    collection: mockCollection,
    collectionGroup: mockCollectionGroup,
    batch: mockBatch,
    runTransaction: mockRunTransaction,
    _docs,
    _setDoc: (path: string, snap: MockDocSnap) => _docs.set(path, snap),
  };

  return db;
}

/* ---------- Auth Mock ---------- */

export function createMockAuth() {
  return {
    setCustomUserClaims: jest.fn().mockResolvedValue(undefined),
    deleteUser: jest.fn().mockResolvedValue(undefined),
    updateUser: jest.fn().mockResolvedValue(undefined),
  };
}

/* ---------- Request Mock ---------- */

export interface MockCallableRequest {
  auth?: {
    uid: string;
    token: Record<string, unknown>;
  };
  data: Record<string, unknown>;
}

export function createMockRequest(
  data: Record<string, unknown>,
  uid?: string,
  tokenOverrides: Record<string, unknown> = {},
): MockCallableRequest {
  if (!uid) {
    return { data };
  }
  return {
    auth: {
      uid,
      token: { email: `${uid}@test.com`, ...tokenOverrides },
    },
    data,
  };
}

/* ---------- Fetch Mock ---------- */

export function mockFetch(responseData: unknown = { data: [] }, ok = true) {
  const fn = jest.fn().mockResolvedValue({
    ok,
    json: () => Promise.resolve(responseData),
    text: () => Promise.resolve(JSON.stringify(responseData)),
  });
  global.fetch = fn as unknown as typeof fetch;
  return fn;
}

/* ---------- FieldValue Stubs ---------- */

export const mockFieldValue = {
  serverTimestamp: jest.fn().mockReturnValue("SERVER_TIMESTAMP"),
  increment: jest.fn().mockImplementation((n: number) => `INCREMENT(${n})`),
  delete: jest.fn().mockReturnValue("DELETE"),
};

export const mockTimestamp = {
  now: jest.fn().mockReturnValue({
    seconds: Math.floor(Date.now() / 1000),
    nanoseconds: 0,
    toDate: () => new Date(),
  }),
  fromDate: jest.fn().mockImplementation((d: Date) => ({
    seconds: Math.floor(d.getTime() / 1000),
    nanoseconds: 0,
    toDate: () => d,
  })),
};

