/**
 * Integration test: Streak lifecycle
 *
 * Tests streak-enabled programs: streak tracking, bonus stamp on completion,
 * and streak reset after timeframe expiry.
 */
import {
  onboardMerchant,
  onboardCustomer,
  createProgram,
  addStamps,
  joinProgram,
  getCardDoc,
  getDb,
  cleanupTestData,
} from "./helpers";

const MERCHANT_UID = "integ-streak-m";
const MERCHANT_EMAIL = "streak-m@test.com";
const CUSTOMER_UID = "integ-streak-c";
const CUSTOMER_EMAIL = "streak-c@test.com";

let programId: string;

beforeAll(async () => {
  await onboardMerchant(MERCHANT_UID, MERCHANT_EMAIL, {
    businessName: "Streak Cafe",
  });
  programId = await createProgram(MERCHANT_UID, {
    storeName: "Streak Cafe",
    stampsToComplete: 5,
    streakEnabled: true,
    streakTargetVisits: 3,
    streakTimeframeDays: 7,
  });
  await onboardCustomer(CUSTOMER_UID, CUSTOMER_EMAIL, {
    firstName: "Streak",
    lastName: "Tester",
  });
  await joinProgram(CUSTOMER_UID, CUSTOMER_EMAIL, programId);
});

afterAll(async () => {
  try {
    await cleanupTestData();
  } catch { /* best effort */ }
});

describe("Streak lifecycle", () => {
  it("tracks streak visits and awards bonus stamp on completion", async () => {
    const r1 = await addStamps(MERCHANT_UID, programId, CUSTOMER_UID, 1);
    expect(r1.newStamps).toBe(1);
    expect(r1.bonusStamps).toBe(0);

    let card = await getCardDoc(CUSTOMER_UID, programId);
    expect(card!.currentStreakVisits).toBe(1);

    const r2 = await addStamps(MERCHANT_UID, programId, CUSTOMER_UID, 1);
    expect(r2.newStamps).toBe(2);
    expect(r2.bonusStamps).toBe(0);

    card = await getCardDoc(CUSTOMER_UID, programId);
    expect(card!.currentStreakVisits).toBe(2);

    const r3 = await addStamps(MERCHANT_UID, programId, CUSTOMER_UID, 1);
    expect(r3.bonusStamps).toBe(1);
    expect(r3.newStamps).toBe(4);

    card = await getCardDoc(CUSTOMER_UID, programId);
    expect(card!.currentStreakVisits).toBe(0);
    expect(card!.stamps).toBe(4);
  });
});

