import { https } from "firebase-functions/v2";
const onCall = https.onCall;
const HttpsError = https.HttpsError;
import { getFirestore, FieldValue } from "firebase-admin/firestore";
import * as types from "../types";

export const updatePushToken = onCall({ region: "africa-south1", timeoutSeconds: 60 }, async (request) => {
    if (!request.auth) {
        throw new HttpsError('unauthenticated', 'The function must be called while authenticated.');
    }

    const { token } = request.data as types.UpdatePushTokenData;
    const { uid } = request.auth;

    if (!token) {
        throw new HttpsError('invalid-argument', 'Missing push token.');
    }

    const db = getFirestore("lekkerloyal-sa");

    try {
        await db.collection("users").doc(uid).set({
            expoPushToken: token,
            updatedAt: FieldValue.serverTimestamp()
        }, { merge: true });
        return { success: true };
    } catch (error) {
        console.error("Error updating push token:", error);
        throw new HttpsError('internal', 'Unable to update push token.');
    }
});

import { https } from "firebase-functions/v2";
const onCall = https.onCall;
const HttpsError = https.HttpsError;
import { getFirestore, FieldValue } from "firebase-admin/firestore";
import * as types from "../types";

/**
 * markCelebrationSeen
 * Securely marks a loyalty card's celebration as seen.
 * Required because users do not have write access to their own card subcollections directly.
 */
export const markCelebrationSeen = onCall({ region: "africa-south1", timeoutSeconds: 60 }, async (request) => {
    if (!request.auth) {
        throw new HttpsError('unauthenticated', 'The function must be called while authenticated.');
    }

    const { programId } = request.data as types.MarkCelebrationSeenData;
    const { uid } = request.auth;
    const db = getFirestore("lekkerloyal-sa");

    if (!programId) {
        throw new HttpsError('invalid-argument', 'programId is required.');
    }

    try {
        await db.collection("users").doc(uid).collection("cards").doc(programId).update({
            celebrationSeen: true,
            updatedAt: FieldValue.serverTimestamp()
        });
        return { success: true };
    } catch (error) {
        console.error("Error marking celebration as seen:", error);
        throw new HttpsError('internal', 'Unable to mark celebration as seen.');
    }
});

import { https } from "firebase-functions/v2";
const onCall = https.onCall;
const HttpsError = https.HttpsError;
import { getFirestore, FieldValue } from "firebase-admin/firestore";
import * as types from "../types";

export const updateCardSettings = onCall({ region: "africa-south1", timeoutSeconds: 60 }, async (request) => {
    if (!request.auth) {
        throw new HttpsError('unauthenticated', 'The function must be called while authenticated.');
    }

    const { programId, notificationsEnabled } = request.data as types.UpdateCardSettingsData;
    const { uid } = request.auth;

    if (!programId) {
        throw new HttpsError('invalid-argument', 'Missing programId.');
    }

    const db = getFirestore("lekkerloyal-sa");

    try {
        const cardRef = db.collection("users").doc(uid).collection("cards").doc(programId);
        const cardSnap = await cardRef.get();

        if (!cardSnap.exists) {
            throw new HttpsError('not-found', 'Loyalty card not found in your wallet.');
        }

        const updates: Record<string, unknown> = {};
        if (notificationsEnabled !== undefined) {
            updates.notificationsEnabled = notificationsEnabled;
        }

        if (Object.keys(updates).length > 0) {
            updates.updatedAt = FieldValue.serverTimestamp();
            await cardRef.update(updates);
        }

        return { success: true };
    } catch (error) {
        console.error("Error updating card settings:", error);
        if (error instanceof HttpsError) throw error;
        throw new HttpsError('internal', 'Unable to update card settings.');
    }
});

