import { https } from "firebase-functions/v2";
const onCall = https.onCall;
const HttpsError = https.HttpsError;
import { getFirestore } from "firebase-admin/firestore";

const ADMIN_UID = 'vi87NYSfdSZ8nZwEWN6GCqITJ8h1';
const ADMIN_EMAIL = 'lekkerloyal@gmail.com';

export const getAdminMerchants = onCall({ region: "africa-south1", timeoutSeconds: 60 }, async (request) => {
    // 1. Authenticate Request
    if (!request.auth) {
        throw new HttpsError('unauthenticated', 'Must be logged in.');
    }

    const uid = request.auth.uid;
    const email = request.auth.token.email;

    // 2. Authorize Admin
    if (uid !== ADMIN_UID && email !== ADMIN_EMAIL) {
        throw new HttpsError('permission-denied', 'Only admins can view the merchant directory.');
    }

    try {
        const db = getFirestore("lekkerloyal-sa");

        // 3. Fetch all merchants and stores
        const usersRef = db.collection('users');
        const [merchantSnap, storeSnap] = await Promise.all([
            usersRef.where('role', '==', 'merchant').get(),
            usersRef.where('role', '==', 'store').get()
        ]);

        const loaded: any[] = [];

        merchantSnap.forEach(doc => {
            const data = doc.data();
            loaded.push({ id: doc.id, email: data.email || 'No email', businessName: data.businessName || 'Unknown Business', role: 'merchant' });
        });

        storeSnap.forEach(doc => {
            const data = doc.data();
            loaded.push({ id: doc.id, email: data.email || 'No email', businessName: data.businessName || 'Unknown Business', role: 'store' });
        });

        // 4. Check if they have programs
        const programsSnap = await db.collection('programs').get();
        const merchantsWithPrograms = new Set();
        programsSnap.forEach(p => {
            merchantsWithPrograms.add(p.data().merchantId);
        });

        const enriched = loaded.map(m => ({
            ...m,
            hasProgram: merchantsWithPrograms.has(m.id)
        }));

        return { merchants: enriched };

    } catch (error) {
        console.error("Error fetching admin merchants:", error);
        throw new HttpsError('internal', 'An error occurred while fetching the merchant directory.');
    }
});

import { https } from "firebase-functions/v2";
const onCall = https.onCall;
const HttpsError = https.HttpsError;
import { getFirestore, FieldValue } from "firebase-admin/firestore";
import * as types from "../types";

export const joinProgram = onCall(
    { region: "africa-south1", timeoutSeconds: 60 },
    async (request): Promise<types.JoinProgramResponse> => {
        if (!request.auth) {
            throw new HttpsError('unauthenticated', 'Sign in to join a loyalty program.');
        }

        const { programId } = request.data as types.JoinProgramData;
        const { uid } = request.auth;

        if (!programId) {
            throw new HttpsError('invalid-argument', 'Missing programId.');
        }

        const db = getFirestore("lekkerloyal-sa");

        return await db.runTransaction(async (transaction) => {
            const programRef = db.collection("programs").doc(programId);
            const cardRef = db.collection("users").doc(uid).collection("cards").doc(programId);

            const [programSnap, cardSnap] = await Promise.all([
                transaction.get(programRef),
                transaction.get(cardRef),
            ]);

            if (!programSnap.exists) {
                throw new HttpsError('not-found', 'Loyalty program not found.');
            }

            const programData = programSnap.data() as types.ProgramData;

            if (programData.subscriptionStatus === 'cancelled' || programData.subscriptionStatus === 'expired') {
                throw new HttpsError('failed-precondition', 'This loyalty program is no longer active.');
            }

            if (cardSnap.exists) {
                return { success: true, alreadyJoined: true };
            }

            const cardPayload: Record<string, unknown> = {
                programId,
                merchantId: programData.merchantId,
                storeName: programData.storeName,
                rewardDescription: programData.rewardDescription || "",
                programType: programData.programType || 'loyalty',
                selectedAccent: programData.selectedAccent || "#000000",
                logoUrl: programData.logoUrl || null,
                useLightOverlay: programData.useLightOverlay ?? false,
                termsConditions: programData.termsConditions || null,
                stamps: 0,
                total: programData.stampsToComplete || 10,
                updatedAt: FieldValue.serverTimestamp(),
                ...(programData.streakEnabled ? {
                    streakEnabled: true,
                    streakTargetVisits: programData.streakTargetVisits,
                    streakTimeframeDays: programData.streakTimeframeDays,
                    currentStreakVisits: 0,
                } : {}),
            };

            transaction.set(cardRef, cardPayload);
            transaction.update(programRef, {
                activeUsers: FieldValue.increment(1),
            });

            return { success: true, alreadyJoined: false };
        });
    },
);

import { https } from "firebase-functions/v2";
const onCall = https.onCall;
const HttpsError = https.HttpsError;
import { getFirestore } from "firebase-admin/firestore";

interface GetCustomerProgramDataArgs {
    customerId: string;
    programId: string;
}

export const getCustomerProgramData = onCall(
    { region: "africa-south1", timeoutSeconds: 60 },
    async (request) => {
        if (!request.auth) {
            throw new HttpsError('unauthenticated', 'Sign in to lookup customer details.');
        }

        const { customerId, programId } = request.data as GetCustomerProgramDataArgs;
        if (!customerId || !programId) {
            throw new HttpsError('invalid-argument', 'Missing customerId or programId.');
        }

        const db = getFirestore("lekkerloyal-sa");

        try {
            // Fetch card progress
            const cardRef = db.collection("users").doc(customerId).collection("cards").doc(programId);
            const cardSnap = await cardRef.get();
            const stamps = cardSnap.exists ? (cardSnap.data()?.stamps || 0) : 0;

            // Fetch active rewards
            const rewardsRef = db.collection("users").doc(customerId).collection("rewards");
            const rewardsQuery = rewardsRef
                .where("programId", "==", programId)
                .where("status", "==", "active");
            const rewardsSnap = await rewardsQuery.get();

            const activeRewards = rewardsSnap.docs.map(doc => {
                const data = doc.data();
                return {
                    id: doc.id,
                    ...data,
                    earnedAt: data.earnedAt?.toDate?.()?.toISOString() || data.earnedAt || null,
                };
            });

            return {
                success: true,
                isEnrolled: cardSnap.exists,
                stamps,
                activeRewards,
            };
        } catch (error: any) {
            console.error("Error in getCustomerProgramData:", error);
            throw new HttpsError('internal', error.message || 'Failed to fetch customer program data.');
        }
    }
);

