7	export const joinProgram = onCall(
8	    { region: "africa-south1", timeoutSeconds: 60 },
9	    async (request): Promise<types.JoinProgramResponse> => {
10	        if (!request.auth) {
11	            throw new HttpsError('unauthenticated', 'Sign in to join a loyalty program.');
12	        }
13	
14	        const { programId } = request.data as types.JoinProgramData;
15	        const { uid } = request.auth;
16	
17	        if (!programId) {
18	            throw new HttpsError('invalid-argument', 'Missing programId.');
19	        }
20	
21	        const db = getFirestore("lekkerloyal-sa");
22	
23	        return await db.runTransaction(async (transaction) => {
24	            const programRef = db.collection("programs").doc(programId);
25	            const cardRef = db.collection("users").doc(uid).collection("cards").doc(programId);
26	
27	            const [programSnap, cardSnap] = await Promise.all([
28	                transaction.get(programRef),
29	                transaction.get(cardRef),
30	            ]);
31	
32	            if (!programSnap.exists) {
33	                throw new HttpsError('not-found', 'Loyalty program not found.');
34	            }
35	
36	            const programData = programSnap.data() as types.ProgramData;
37	
38	            if (programData.subscriptionStatus === 'cancelled' || programData.subscriptionStatus === 'expired') {
39	                throw new HttpsError('failed-precondition', 'This loyalty program is no longer active.');
40	            }
41	
42	            if (cardSnap.exists) {
43	                return { success: true, alreadyJoined: true };
44	            }
45	
46	            const cardPayload: Record<string, unknown> = {
47	                programId,
48	                merchantId: programData.merchantId,
49	                storeName: programData.storeName,
50	                rewardDescription: programData.rewardDescription || "",
51	                programType: programData.programType || 'loyalty',
52	                selectedAccent: programData.selectedAccent || "#000000",
53	                logoUrl: programData.logoUrl || null,
54	                useLightOverlay: programData.useLightOverlay ?? false,
55	                termsConditions: programData.termsConditions || null,
56	                stamps: 0,
57	                total: programData.stampsToComplete || 10,
58	                updatedAt: FieldValue.serverTimestamp(),
59	                ...(programData.streakEnabled ? {
60	                    streakEnabled: true,
61	                    streakTargetVisits: programData.streakTargetVisits,
62	                    streakTimeframeDays: programData.streakTimeframeDays,
63	                    currentStreakVisits: 0,
64	                } : {}),
65	            };
66	
67	            transaction.set(cardRef, cardPayload);
68	            transaction.update(programRef, {
69	                activeUsers: FieldValue.increment(1),
70	            });
71	
72	            return { success: true, alreadyJoined: false };
73	        });
74	    },
75	);
