import { https } from "firebase-functions/v2";
const onCall = https.onCall;
const HttpsError = https.HttpsError;
import { getFirestore, FieldValue } from "firebase-admin/firestore";

const ADMIN_UID = 'vi87NYSfdSZ8nZwEWN6GCqITJ8h1';
const ADMIN_EMAIL = 'lekkerloyal@gmail.com';

export const adminConfigureProgram = onCall({ region: "africa-south1", timeoutSeconds: 60 }, async (request) => {
    // 1. Authenticate Request
    if (!request.auth) {
        throw new HttpsError('unauthenticated', 'Must be logged in.');
    }

    const uid = request.auth.uid;
    const email = request.auth.token.email;

    // 2. Authorize Admin
    if (uid !== ADMIN_UID && email !== ADMIN_EMAIL) {
        throw new HttpsError('permission-denied', 'Only admins can configure programs remotely.');
    }

    const { programId, programData } = request.data;
    if (!programData || !programData.merchantId) {
        throw new HttpsError('invalid-argument', 'Missing program data or merchantId.');
    }

    try {
        const db = getFirestore("lekkerloyal-sa");

        let docRef;
        if (programId) {
            // Update existing
            docRef = db.collection("programs").doc(programId);
            await docRef.set({
                ...programData,
                updatedAt: FieldValue.serverTimestamp(),
            }, { merge: true });
            console.log(`Admin updated program ${programId} for merchant ${programData.merchantId}`);
        } else {
            // Create new. Concierge merchants must subscribe before access, so we
            // intentionally do not set trialStartedAt — the client-side paywall fires
            // off the absence of paystackSubscriptionCode.
            const newProgramData = {
                ...programData,
                activeUsers: 0,
                status: 'active',
                subscriptionStatus: 'trial',
                createdAt: FieldValue.serverTimestamp(),
                updatedAt: FieldValue.serverTimestamp(),
            };
            docRef = await db.collection("programs").add(newProgramData);
            console.log(`Admin created new program ${docRef.id} for merchant ${programData.merchantId}`);
        }

        return { success: true, programId: docRef.id };

    } catch (error) {
        console.error("Error configuring admin program:", error);
        throw new HttpsError('internal', 'An error occurred while configuring the program.');
    }
});

