import { https } from "firebase-functions/v2";
const onCall = https.onCall;
const HttpsError = https.HttpsError;
import { getFirestore } from "firebase-admin/firestore";
import * as types from "../types";

/**
 * deleteLoyaltyProgram
 * Callable function to delete a program and cascade to user cards.
 */
export const deleteLoyaltyProgram = onCall({ region: "africa-south1", timeoutSeconds: 120 }, async (request) => {
    if (!request.auth) {
        throw new HttpsError('unauthenticated', 'The function must be called while authenticated.');
    }

    const { programId } = request.data as types.GetProgramClientsData;
    const { uid } = request.auth;

    if (!programId) {
        throw new HttpsError('invalid-argument', 'Missing programId.');
    }

    const db = getFirestore("lekkerloyal-sa");

    try {
        // 1. Verify Ownership
        const programRef = db.collection("programs").doc(programId);
        const programSnap = await programRef.get();

        if (!programSnap.exists) {
            throw new HttpsError('not-found', 'Program not found.');
        }

        const programData = programSnap.data();
        if (programData?.merchantId !== uid) {
            throw new HttpsError('permission-denied', 'You do not own this program.');
        }

        if ((programData?.activeUsers || 0) > 0) {
            throw new HttpsError(
                'failed-precondition',
                'Cannot delete a program with active customers. Please contact support if you need to remove this program.'
            );
        }

        // 2. Cascade Delete: Remove this card from all users' wallets
        // Note: For very large apps, this should be a background batch job.
        const cardsQuery = db.collectionGroup('cards').where('programId', '==', programId);
        const cardsSnap = await cardsQuery.get();

        const cardDeletes: Promise<FirebaseFirestore.WriteResult>[] = [];
        cardsSnap.forEach(doc => {
            cardDeletes.push(doc.ref.delete());
        });

        await Promise.all(cardDeletes);
        console.log(`Program ${programId} deleted. Removed ${cardDeletes.length} user cards.`);

        // 3. Delete the Program Document
        await programRef.delete();

        return { success: true };

    } catch (error) {
        console.error("Error deleting program:", error);
        if (error instanceof HttpsError) throw error;
        throw new HttpsError('internal', 'Unable to delete program.');
    }
});

import { https } from "firebase-functions/v2";
const onCall = https.onCall;
const HttpsError = https.HttpsError;
import * as admin from "firebase-admin";
import { getFirestore, FieldValue } from "firebase-admin/firestore";
import { defineSecret } from "firebase-functions/params";

const PAYSTACK_SECRET = defineSecret("PAYSTACK_SECRET");
const PAYSTACK_SECRET_TEST = defineSecret("PAYSTACK_SECRET_TEST");

const PAYSTACK_API_URL = process.env.PAYSTACK_API_URL || "https://api.paystack.co";

/**
 * deleteAccount
 * Callable function to securely delete a user's account and associated data (Cascading Delete).
 * - Merchant: Deletes Programs, Stores (sub-accounts), User Doc, Auth User.
 * - Store: Deletes User Doc, Auth User.
 * - Customer: Deletes User Doc, Auth User.
 */

async function disableAllCustomerSubscriptions(secret: string, customerCode: string) {
    try {
        // Look up customer by code to get their numeric ID
        const customerRes = await fetch(`${PAYSTACK_API_URL}/customer/${customerCode}`, {
            headers: { Authorization: `Bearer ${secret}` }
        });
        const customerData = await customerRes.json();
        const customerId = customerData.data?.id;

        if (!customerId) {
            console.warn(`Customer ID not found for code ${customerCode}. Skipping subscription cleanup.`);
            return;
        }

        const res = await fetch(
            `${PAYSTACK_API_URL}/subscription?customer=${customerId}&perPage=20`,
            { headers: { Authorization: `Bearer ${secret}` } }
        );
        const data = await res.json();
        if (data.status && Array.isArray(data.data)) {
            for (const sub of data.data) {
                if (['active', 'non-renewing', 'attention'].includes(sub.status)) {
                    console.log(`Disabling orphan subscription ${sub.subscription_code} for customer ${customerCode}...`);
                    await fetch(`${PAYSTACK_API_URL}/subscription/disable`, {
                        method: 'POST',
                        headers: { Authorization: `Bearer ${secret}`, 'Content-Type': 'application/json' },
                        body: JSON.stringify({ code: sub.subscription_code, token: sub.email_token })
                    });
                }
            }
        }
    } catch (err) {
        console.error(`Failed to cleanup global Paystack subscriptions for ${customerCode}:`, err);
    }
}

export const deleteAccount = onCall({ region: "africa-south1", timeoutSeconds: 120, secrets: [PAYSTACK_SECRET, PAYSTACK_SECRET_TEST] }, async (request) => {
    if (!request.auth) {
        throw new HttpsError('unauthenticated', 'The function must be called while authenticated.');
    }

    const { uid, token } = request.auth;
    const db = getFirestore("lekkerloyal-sa");

    try {
        console.log(`Initiating account deletion for user ${uid} (Role: ${token.role || 'unknown'})`);

        // 0. IMPORTANT: Delete Auth User First
        // This prevents the frontend from detecting a missing user doc while still authenticated,
        // which would otherwise trigger the ProfileRestorer to erroneously re-onboard the user.
        try {
            await admin.auth().deleteUser(uid);
            console.log(`Auth user ${uid} deleted. Proceeding with data cleanup.`);
        } catch (e: unknown) {
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            if ((e as any).code !== 'auth/user-not-found') {
                throw e; // Fail early if Auth deletion fails for unexpected reason
            }
        }

        // 1. Handle Merchant Logic (Cascading deletes)
        if (token.role === 'merchant') {
            // A. Delete Programs and Cascade to Cards
            const programsQuery = db.collection("programs").where("merchantId", "==", uid);
            const programsSnap = await programsQuery.get();
            const programDeletes: Promise<FirebaseFirestore.WriteResult>[] = [];
            const cardDeletes: Promise<FirebaseFirestore.WriteResult>[] = [];

            for (const programDoc of programsSnap.docs) {
                const programData = programDoc.data();
                const subCode = programData.paystackSubscriptionCode;

                // Paystack Cancellation Logic
                if (subCode) {
                    try {
                        console.log(`Attempting to cancel Paystack subscription: ${subCode}`);
                        const liveSecret = PAYSTACK_SECRET.value();
                        const testSecret = PAYSTACK_SECRET_TEST.value();
                        let secret = liveSecret;

                        // 1. Fetch subscription to retrieve the required email_token (Try Live first)
                        let subFetchResponse = await fetch(`${PAYSTACK_API_URL}/subscription/${subCode}`, {
                            headers: { Authorization: `Bearer ${liveSecret}` }
                        });
                        let subDetail = await subFetchResponse.json();

                        if (!subDetail.status) {
                            // Try test secret
                            subFetchResponse = await fetch(`${PAYSTACK_API_URL}/subscription/${subCode}`, {
                                headers: { Authorization: `Bearer ${testSecret}` }
                            });
                            subDetail = await subFetchResponse.json();
                            if (subDetail.status) {
                                secret = testSecret;
                            }
                        }

                        if (subDetail.status && subDetail.data.email_token) {
                            const emailToken = subDetail.data.email_token;

                            // 2. Disable the subscription on Paystack
                            const disableResponse = await fetch(`${PAYSTACK_API_URL}/subscription/disable`, {
                                method: 'POST',
                                headers: {
                                    Authorization: `Bearer ${secret}`,
                                    'Content-Type': 'application/json'
                                },
                                body: JSON.stringify({
                                    code: subCode,
                                    token: emailToken
                                })
                            });
                            const disableResult = await disableResponse.json();
                            console.log(`Paystack Disable Status [${subCode}]:`, disableResult.message || disableResult.status);
                        } else {
                            console.warn(`Could not retrieve email_token for subscription ${subCode}. Response:`, JSON.stringify(subDetail));
                        }
                    } catch (paystackError) {
                        console.error(`Paystack cancellation error for ${subCode}:`, paystackError);
                    }
                }

                programDeletes.push(programDoc.ref.delete());

                // Cascade Delete: Remove this card from all users' wallets
                const cardsQuery = db.collectionGroup('cards').where('programId', '==', programDoc.id);
                const cardsSnap = await cardsQuery.get();
                cardsSnap.forEach(cardDoc => {
                    cardDeletes.push(cardDoc.ref.delete());
                });
            }
            await Promise.all([...programDeletes, ...cardDeletes]);
            console.log(`Deleted ${programDeletes.length} programs and ${cardDeletes.length} associated user cards.`);

            // B. Delete Stores (Sub-accounts)
            const storesQuery = db.collection("users").where("linkedMerchantId", "==", uid);
            const storesSnap = await storesQuery.get();

            // We need to delete their Auth accounts too!
            for (const storeDoc of storesSnap.docs) {
                try {
                    await admin.auth().deleteUser(storeDoc.id);
                    await storeDoc.ref.delete();
                } catch (e) {
                    console.error(`Failed to delete store sub-account ${storeDoc.id}:`, e);
                }
            }
            console.log(`Deleted ${storesSnap.size} store accounts.`);
        }

        // 2. Global Paystack Cleanup & Delete User Document (All roles)
        const userRef = db.collection("users").doc(uid);
        const userSnap = await userRef.get();
        const userData = userSnap.data();

        if (userData?.paystackCustomerCode) {
            console.log(`Performing global Paystack cleanup for customer ${userData.paystackCustomerCode}`);
            const liveSecret = PAYSTACK_SECRET.value();
            const testSecret = PAYSTACK_SECRET_TEST.value();
            await disableAllCustomerSubscriptions(liveSecret, userData.paystackCustomerCode);
            await disableAllCustomerSubscriptions(testSecret, userData.paystackCustomerCode);
        }

        // Delete subcollections (cards) - manual recursion needed
        const cardsSnap = await userRef.collection("cards").get();
        const cardDeletes: Promise<FirebaseFirestore.WriteResult>[] = [];
        const programDecrementUpdates: Promise<unknown>[] = [];

        cardsSnap.forEach(doc => {
            cardDeletes.push(doc.ref.delete());

            // If this card belongs to a program, decrement that program's activeUsers count
            const cardData = doc.data();
            if (cardData.programId) {
                const programRef = db.collection("programs").doc(cardData.programId);
                programDecrementUpdates.push(
                    programRef.update({
                        activeUsers: FieldValue.increment(-1)
                    }).catch(err => console.warn(`Failed to decrement activeUser for program ${cardData.programId}`, err))
                );
            }
        });

        await Promise.all([...cardDeletes, ...programDecrementUpdates]);

        // Delete the main doc
        await userRef.delete();

        console.log(`Account ${uid} deleted successfully.`);
        return { success: true };

    } catch (error) {
        console.error("Error deleting account:", error);
        throw new HttpsError('internal', 'Unable to delete account.');
    }
});

import { https } from "firebase-functions/v2";
const onCall = https.onCall;
const HttpsError = https.HttpsError;
import { getFirestore } from "firebase-admin/firestore";
import * as types from "../types";

/**
 * getProgramClients
 * Callable function to retrieve all clients involved in a specific program.
 * Performs a collectionGroup query for 'cards' where programId matches.
 */
export const getProgramClients = onCall({ region: "africa-south1", timeoutSeconds: 60 }, async (request) => {
    if (!request.auth) {
        throw new HttpsError('unauthenticated', 'The function must be called while authenticated.');
    }

    const { programId } = request.data as types.GetProgramClientsData;
    const { uid } = request.auth;

    if (!programId) {
        throw new HttpsError('invalid-argument', 'Missing programId.');
    }

    const db = getFirestore("lekkerloyal-sa");

    try {
        // First confirm this merchant owns the program (security check)
        // Check if user is the Owner OR a Store Account linked to the owner
        const programRef = db.collection("programs").doc(programId);
        const programSnap = await programRef.get();

        if (!programSnap.exists) {
            throw new HttpsError('not-found', 'Program not found.');
        }

        const programData = programSnap.data();

        // Check permissions
        const isOwner = programData?.merchantId === uid;
        const isStore = (request.auth.token as { merchantId?: string }).merchantId === programData?.merchantId;

        if (!isOwner && !isStore) {
            throw new HttpsError('permission-denied', 'You do not own this program.');
        }

        // Query all cards with this programId
        const cardsQuery = db.collectionGroup('cards').where('programId', '==', programId);
        const querySnapshot = await cardsQuery.get();

        const clients: unknown[] = [];
        const promises: Promise<void>[] = [];

        querySnapshot.forEach((cardDoc) => {
            // The parent of a card is users/{userId}/cards
            // So ref.parent.parent.id gives us the userId
            const userId = cardDoc.ref.parent.parent?.id;
            if (userId) {
                const p = db.collection("users").doc(userId).get().then(userSnap => {
                    const userData = userSnap.data();
                    const cardData = cardDoc.data();

                    // Fix for "1/?" issue: Use card's total or fall back to program's stampsToComplete
                    const totalTarget = cardData.total || programData?.stampsToComplete || 10;

                    clients.push({
                        uid: userId,
                        firstName: userData?.firstName || "",
                        lastName: userData?.lastName || "",
                        // Return DOB for display
                        dob: userData?.dob || null,
                        ...cardData,
                        // Ensure total is populated
                        total: totalTarget,
                        // Ensure redeemedCount is present for Loyalty Score calculation
                        redeemedCount: cardData.redeemedCount || 0,
                        pendingRewards: cardData.pendingRewardsCount || 0,
                        email: userData?.email || "", // Be careful with PII, but merchant needs identification
                        phoneNumber: userData?.phoneNumber || ""
                    });
                });
                promises.push(p);
            }
        });

        await Promise.all(promises);

        console.log(`Fetched ${clients.length} clients for program ${programId}`);
        return { clients };

    } catch (error) {
        console.error("Error fetching program clients:", error);
        throw new HttpsError('internal', 'Unable to fetch clients.');
    }
});

import { https } from "firebase-functions/v2";
const onCall = https.onCall;
const HttpsError = https.HttpsError;
import { getFirestore, FieldValue, Timestamp } from "firebase-admin/firestore";
import { defineSecret } from "firebase-functions/params";
import * as types from "../types";

const PAYSTACK_SECRET = defineSecret("PAYSTACK_SECRET");
const PAYSTACK_SECRET_TEST = defineSecret("PAYSTACK_SECRET_TEST");

const TEST_PLAN_CODE = "PLN_pnei7dyejj7145i";
const LIVE_PLAN_CODE = "PLN_8erqsednwqkq2c2";

const PAYSTACK_API_URL = process.env.PAYSTACK_API_URL || "https://api.paystack.co";

interface PaystackSub {
    status: string;
    subscription_code: string;
    email_token: string;
    next_payment_date?: string;
    plan?: {
        plan_code?: string;
    };
}

// Fetches all subscriptions (any status) for a customer+plan combination.
// Paystack's list API omits "pending" (future-start-date) subscriptions by default,
// so we also try a direct customer subscription listing to catch them.
async function fetchExistingSubs(secret: string, customerId: string | number, planCode: string): Promise<PaystackSub[]> {
    const res = await fetch(
        `${PAYSTACK_API_URL}/subscription?customer=${customerId}&perPage=20`,
        { headers: { Authorization: `Bearer ${secret}` } }
    );
    const data = await res.json();
    const subs = (data.status && Array.isArray(data.data)) ? (data.data as PaystackSub[]) : [];
    return subs.filter(sub => sub.plan?.plan_code === planCode);
}

export const setupSubscription = onCall({ region: "africa-south1", timeoutSeconds: 60, secrets: [PAYSTACK_SECRET, PAYSTACK_SECRET_TEST] }, async (request) => {
    if (!request.auth) {
        throw new HttpsError('unauthenticated', 'Authenticated users only.');
    }

    const { programId, reference, programData, isTestMode } = request.data as types.SetupSubscriptionData;
    const { uid } = request.auth;

    if (!reference) {
        throw new HttpsError('invalid-argument', 'Missing Paystack reference.');
    }
    if (typeof isTestMode !== 'boolean') {
        throw new HttpsError('invalid-argument', 'Missing isTestMode flag.');
    }

    const db = getFirestore("lekkerloyal-sa");
    const secretToUse = isTestMode ? PAYSTACK_SECRET_TEST.value() : PAYSTACK_SECRET.value();
    const planCode = isTestMode ? TEST_PLAN_CODE : LIVE_PLAN_CODE;

    try {
        // 1. Verify the Paystack transaction.
        const paystackRes = await fetch(`${PAYSTACK_API_URL}/transaction/verify/${reference}`, {
            headers: { Authorization: `Bearer ${secretToUse}` }
        });
        const paystackData = await paystackRes.json();

        if (!paystackData.status || paystackData.data?.status !== 'success') {
            console.error(`Paystack verification failed (${isTestMode ? 'TEST' : 'LIVE'}):`, paystackData);
            throw new HttpsError('failed-precondition', 'Transaction verification failed.');
        }

        const { authorization, customer } = paystackData.data;
        const customerCode = customer?.customer_code;
        const customerId = customer?.id;
        const authorizationCode = authorization?.authorization_code;

        if (!customerCode || !authorizationCode || !customerId) {
            throw new HttpsError('failed-precondition', 'Paystack response missing customer or authorization details.');
        }

        // 2. Update the user profile with Paystack codes and a card placeholder.
        const bankingDetailsPlaceholder = {
            accountHolder: authorization?.account_name || 'Cardholder',
            accountNumber: `****${authorization?.last4 || '1234'}`,
            bankName: authorization?.bank || 'Paystack',
            bankCode: 'PAYSTACK'
        };

        const userRef = db.collection("users").doc(uid);
        await userRef.set({
            paystackCustomerCode: customerCode,
            paystackAuthorizationCode: authorizationCode,
            bankingDetails: bankingDetailsPlaceholder,
            updatedAt: FieldValue.serverTimestamp()
        }, { merge: true });

        // 3. Disable any existing subscriptions for this customer+plan.
        //    We do NOT pass start_date to Paystack (see step 4), so all subscriptions
        //    created here are immediately active and visible to the list API.
        //    Any "pending" phantom subscriptions from previous attempts (created with
        //    a future start_date) are invisible to the list API — disabling active ones
        //    is sufficient; Paystack clears pending ones when a new sub is created
        //    once the active ones are gone.
        let nextExpiry = new Date(Date.now() + (30 * 24 * 60 * 60 * 1000));

        const existingSubs = await fetchExistingSubs(secretToUse, customerId, planCode);
        for (const sub of existingSubs) {
            if (sub.status === 'active' || sub.status === 'non-renewing') {
                console.log(`Disabling existing subscription ${sub.subscription_code}...`);
                await fetch(`${PAYSTACK_API_URL}/subscription/disable`, {
                    method: 'POST',
                    headers: { Authorization: `Bearer ${secretToUse}`, 'Content-Type': 'application/json' },
                    body: JSON.stringify({ code: sub.subscription_code, token: sub.email_token })
                });
            }
        }

        // 4. Create a new Paystack subscription WITHOUT a start_date.
        //
        //    Root cause of the previous "subscription already in place" bug:
        //    passing start_date 30 days in the future causes Paystack to create a
        //    "pending" subscription that is invisible to the list API (so our cleanup
        //    above cannot find and disable it) but still blocks new subscription
        //    creation. Omitting start_date creates the subscription in "active" state
        //    immediately. For monthly plans Paystack issues the first invoice at the
        //    end of the first billing interval (~30 days), so the merchant still gets
        //    a free first month — we just can't rely on start_date to enforce that.
        console.log(`Creating Paystack subscription for ${customerCode} (${isTestMode ? 'TEST' : 'LIVE'}, plan ${planCode})`);

        let subscriptionCode: string;

        const subRes = await fetch(`${PAYSTACK_API_URL}/subscription`, {
            method: 'POST',
            headers: {
                Authorization: `Bearer ${secretToUse}`,
                'Content-Type': 'application/json'
            },
            body: JSON.stringify({
                customer: customerCode,
                plan: planCode,
                authorization: authorizationCode
                // No start_date — avoids phantom pending subscriptions
            })
        });

        const subData = await subRes.json();

        if (!subData.status) {
            // Graceful fallback: if Paystack says it's "already in place", the subscription
            // exists (possibly in a state we can't list). Fetch it by customer+plan and
            // reuse its code so we can complete the Firestore write.
            if (typeof subData.message === 'string' && subData.message.toLowerCase().includes('already in place')) {
                console.warn('Subscription already in place — fetching existing code as fallback...');
                const fallbackSubs = await fetchExistingSubs(secretToUse, customerId, planCode);
                // Look for any subscription that isn't completely dead (active, non-renewing, attention, or even pending/cancelled if that's all we have)
                const existing = fallbackSubs.find(s => ['active', 'non-renewing', 'attention'].includes(s.status)) || fallbackSubs[0];

                if (existing) {
                    subscriptionCode = existing.subscription_code;
                    if (existing.next_payment_date) {
                        nextExpiry = new Date(existing.next_payment_date);
                    }
                    console.log(`Reusing existing subscription ${subscriptionCode}`);
                } else {
                    console.error('Paystack subscription creation failed and no existing sub found:', subData);
                    throw new HttpsError('internal', `Failed to create Paystack subscription: ${subData.message}`);
                }
            } else {
                console.error('Paystack subscription creation failed:', subData);
                throw new HttpsError('internal', `Failed to create Paystack subscription: ${subData.message}`);
            }
        } else {
            subscriptionCode = subData.data.subscription_code;
            if (subData.data.next_payment_date) {
                nextExpiry = new Date(subData.data.next_payment_date);
            }
            console.log(`Subscription created: ${subscriptionCode}`);
        }

        // 5. Write to Firestore — only reached after subscription is confirmed.
        let currentProgramId = programId;

        if (currentProgramId) {
            const programRef = db.collection("programs").doc(currentProgramId);
            const programSnap = await programRef.get();
            if (programSnap.exists && programSnap.data()?.merchantId === uid) {
                await programRef.update({
                    subscriptionStatus: 'active',
                    subscriptionExpiry: Timestamp.fromDate(nextExpiry),
                    lastPaymentRef: reference,
                    paystackCustomerCode: customerCode,
                    paystackSubscriptionCode: subscriptionCode,
                    bankingDetails: bankingDetailsPlaceholder,
                    updatedAt: FieldValue.serverTimestamp()
                });
            }
        } else if (programData) {
            console.log("Creating program with active subscription...");
            const programRef = db.collection("programs").doc();
            await programRef.set({
                ...programData,
                merchantId: uid,
                activeUsers: 0,
                subscriptionStatus: 'active',
                subscriptionExpiry: Timestamp.fromDate(nextExpiry),
                lastPaymentRef: reference,
                paystackCustomerCode: customerCode,
                paystackSubscriptionCode: subscriptionCode,
                bankingDetails: bankingDetailsPlaceholder,
                createdAt: FieldValue.serverTimestamp(),
                updatedAt: FieldValue.serverTimestamp()
            });
            currentProgramId = programRef.id;
        }

        return { success: true, programId: currentProgramId };

    } catch (error) {
        console.error("Error setting up subscription:", error);
        if (error instanceof HttpsError) throw error;
        throw new HttpsError('internal', 'An error occurred while setting up subscription.');
    }
});

