4	import { defineSecret } from "firebase-functions/params";
5	import * as crypto from "crypto";
6	
7	const PAYSTACK_SECRET = defineSecret("PAYSTACK_SECRET");
8	const PAYSTACK_SECRET_TEST = defineSecret("PAYSTACK_SECRET_TEST");
9	
10	interface PaystackEvent {
11	    event: string;
12	    data?: {
13	        reference?: string;
14	        customer?: { customer_code?: string };
15	    };
16	}
17	
18	/**
19	 * Verify the Paystack signature against the given secret and apply the event
20	 * to Firestore. Shared by the live and test webhook endpoints.
21	 */
22	async function processPaystackEvent(
23	    rawBody: Buffer,
24	    signature: string | undefined,
25	    body: unknown,
26	    secret: string,
27	    mode: "LIVE" | "TEST"
28	): Promise<{ status: number; message?: string }> {
29	    const hash = crypto.createHmac("sha512", secret).update(rawBody).digest("hex");
30	
31	    if (hash !== signature) {
32	        console.error(`Invalid Paystack webhook signature (${mode}).`);
33	        return { status: 400, message: "Invalid signature" };
34	    }
35	
36	    const event = body as PaystackEvent;
37	    console.log(`Paystack Webhook Event (${mode}):`, event.event, event.data?.reference);
38	
39	    const db = getFirestore("lekkerloyal-sa");
40	
41	    if (event.event === "charge.success") {
42	        const reference = event.data?.reference;
43	        const customerCode = event.data?.customer?.customer_code;
44	
45	        if (customerCode) {
46	            console.log(`Processing subscription payment for customer code ${customerCode}`);
47	
48	            const programsQuery = db.collection("programs").where("paystackCustomerCode", "==", customerCode);
49	            const programsSnap = await programsQuery.get();
50	
51	            if (!programsSnap.empty) {
52	                const now = new Date();
53	                const nextExpiry = new Date(now.getTime() + (30 * 24 * 60 * 60 * 1000));
54	
55	                const batch = db.batch();
56	                programsSnap.forEach((doc) => {
57	                    batch.update(doc.ref, {
58	                        subscriptionStatus: "active",
59	                        subscriptionExpiry: Timestamp.fromDate(nextExpiry),
60	                        updatedAt: FieldValue.serverTimestamp(),
61	                        lastPaymentRef: reference,
62	                    });
63	                });
64	                await batch.commit();
65	                console.log(`Successfully extended subscription for ${programsSnap.size} program(s).`);
66	            } else {
67	                console.warn(`No programs found matching customer code ${customerCode}`);
68	            }
69	        } else {
70	            console.warn("Missing customer_code in webhook data");
71	        }
72	    } else if (event.event === "invoice.payment_failed") {
73	        const customerCode = event.data?.customer?.customer_code;
74	        if (customerCode) {
75	            const programsQuery = db.collection("programs").where("paystackCustomerCode", "==", customerCode);
76	            const snap = await programsQuery.get();
77	            const batch = db.batch();
78	            snap.forEach((doc) => {
79	                batch.update(doc.ref, { subscriptionStatus: "past_due", updatedAt: FieldValue.serverTimestamp() });
80	            });
81	            await batch.commit();
82	            console.log(`Updated ${snap.size} programs to past_due via webhook`);
83	        }
84	    } else if (event.event === "subscription.disable") {
85	        const customerCode = event.data?.customer?.customer_code;
86	        if (customerCode) {
87	            const programsQuery = db.collection("programs").where("paystackCustomerCode", "==", customerCode);
88	            const snap = await programsQuery.get();
89	            const batch = db.batch();
90	            snap.forEach((doc) => {
91	                batch.update(doc.ref, { subscriptionStatus: "cancelled", updatedAt: FieldValue.serverTimestamp() });
92	            });
