/* eslint-disable @typescript-eslint/no-explicit-any */
import {
  createMockAuth,
  createMockFirestore,
  createMockRequest,
  mockFieldValue,
  MockFirestore,
} from "./mocks";

// ── Module mocks ───────────────────────────────────────────────────
const mockDb: { current: MockFirestore } = { current: null as any };
const mockAuth = createMockAuth();

jest.mock("firebase-admin/firestore", () => ({
  getFirestore: () => mockDb.current,
  FieldValue: {
    serverTimestamp: () => mockFieldValue.serverTimestamp(),
    increment: (n: number) => mockFieldValue.increment(n),
  },
}));

jest.mock("firebase-admin", () => ({
  auth: () => mockAuth,
  firestore: {
    FieldValue: {
      serverTimestamp: () => mockFieldValue.serverTimestamp(),
    },
  },
}));

jest.mock("firebase-functions/v2", () => ({
  https: {
    onCall: (_opts: any, handler: any) => handler,
    HttpsError: class HttpsError extends Error {
      code: string;
      constructor(code: string, message: string) {
        super(message);
        this.code = code;
        this.name = "HttpsError";
      }
    },
  },
}));

jest.mock("../helpers", () => {
  const actual = jest.requireActual("../helpers");
  return {
    ...actual,
    mergeGuestData: jest.fn().mockResolvedValue(undefined),
  };
});

import { onboardUser } from "../callable/onboardUser";
import * as helpers from "../helpers";

// ── Tests ──────────────────────────────────────────────────────────
describe("onboardUser", () => {
  beforeEach(() => {
    jest.clearAllMocks();
    mockDb.current = createMockFirestore();
  });

  it("rejects unauthenticated calls", async () => {
    const req = createMockRequest({ role: "customer" });
    await expect((onboardUser as any)(req)).rejects.toThrow("authenticated");
  });

  it("rejects invalid role", async () => {
    const req = createMockRequest({ role: "admin" }, "user-001");
    await expect((onboardUser as any)(req)).rejects.toThrow("merchant");
  });

  it("sets custom claims for customer role", async () => {
    const req = createMockRequest(
      { role: "customer", firstName: "John", lastName: "Doe" },
      "user-001",
    );
    const result = await (onboardUser as any)(req);
    expect(result.success).toBe(true);
    expect(result.role).toBe("customer");
    expect(mockAuth.setCustomUserClaims).toHaveBeenCalledWith("user-001", { role: "customer" });
  });

  it("sets custom claims for merchant role", async () => {
    const req = createMockRequest(
      { role: "merchant", businessName: "Test Shop" },
      "user-002",
    );
    const result = await (onboardUser as any)(req);
    expect(result.success).toBe(true);
    expect(result.role).toBe("merchant");
    expect(mockAuth.setCustomUserClaims).toHaveBeenCalledWith("user-002", { role: "merchant" });
  });

  it("creates Firestore user document", async () => {
    const req = createMockRequest(
      { role: "customer", firstName: "John", lastName: "Doe" },
      "user-001",
    );
    await (onboardUser as any)(req);

    // Verify collection("users").doc("user-001").set was called
    const collection = mockDb.current.collection;
    expect(collection).toHaveBeenCalledWith("users");
  });

  it("calls mergeGuestData when phone number is provided", async () => {
    const req = createMockRequest(
      { role: "customer", firstName: "Jane", lastName: "Smith", phoneNumber: "0821234567" },
      "user-003",
    );
    await (onboardUser as any)(req);
    expect(helpers.mergeGuestData).toHaveBeenCalledWith(
      expect.anything(),
      "user-003",
      "0821234567",
    );
  });

  it("does not call mergeGuestData when phone number is missing", async () => {
    const req = createMockRequest(
      { role: "customer", firstName: "Jane", lastName: "Smith" },
      "user-003",
    );
    await (onboardUser as any)(req);
    expect(helpers.mergeGuestData).not.toHaveBeenCalled();
  });

  it("preserves existing role when user already exists", async () => {
    // Seed Firestore with an existing customer user
    mockDb.current = createMockFirestore({
      "users/user-existing": { role: "customer", email: "user-existing@test.com" },
    });

    // Attempt to onboard as merchant with the same uid
    const req = createMockRequest(
      { role: "merchant", businessName: "New Shop" },
      "user-existing",
    );
    const result = await (onboardUser as any)(req);

    // Should return the EXISTING role, not the requested one
    expect(result.success).toBe(true);
    expect(result.role).toBe("customer");

    // Claims should be set to the existing role
    expect(mockAuth.setCustomUserClaims).toHaveBeenCalledWith("user-existing", { role: "customer" });

    // Firestore set() should NOT have been called (no doc overwrite)
    const docMock = mockDb.current.collection("users").doc("user-existing");
    expect(docMock.set).not.toHaveBeenCalled();
  });
});

