import {
  createMockFirestore,
  createMockRequest,
  mockFieldValue,
  MockFirestore,
} from "./mocks";

// ── Module mocks ───────────────────────────────────────────────────
const mockDb: { current: MockFirestore } = { current: null as any };

jest.mock("firebase-admin/firestore", () => ({
  getFirestore: () => mockDb.current,
  FieldValue: {
    serverTimestamp: () => mockFieldValue.serverTimestamp(),
    increment: (n: number) => mockFieldValue.increment(n),
  },
}));

jest.mock("firebase-functions/v2", () => ({
  https: {
    onCall: (_opts: any, handler: any) => handler,
    HttpsError: class HttpsError extends Error {
      code: string;
      constructor(code: string, message: string) {
        super(message);
        this.code = code;
        this.name = "HttpsError";
      }
    },
  },
}));

import { markCelebrationSeen } from "../callable/markCelebrationSeen";

// ── Tests ──────────────────────────────────────────────────────────
describe("markCelebrationSeen", () => {
  beforeEach(() => {
    jest.clearAllMocks();
    mockDb.current = createMockFirestore();
  });

  it("rejects unauthenticated calls", async () => {
    const req = createMockRequest({ programId: "prog-1" });
    await expect((markCelebrationSeen as any)(req)).rejects.toThrow("authenticated");
  });

  it("rejects missing programId", async () => {
    const req = createMockRequest({}, "user-001");
    await expect((markCelebrationSeen as any)(req)).rejects.toThrow("programId is required");
  });

  it("rejects empty programId", async () => {
    const req = createMockRequest({ programId: "" }, "user-001");
    await expect((markCelebrationSeen as any)(req)).rejects.toThrow("programId is required");
  });

  it("marks celebration as seen for valid card", async () => {
    mockDb.current = createMockFirestore({
      "users/user-001/cards/prog-1": { celebrationSeen: false, programId: "prog-1" },
    });

    const req = createMockRequest({ programId: "prog-1" }, "user-001");
    const result = await (markCelebrationSeen as any)(req);
    expect(result).toEqual({ success: true });

    const cardDoc = mockDb.current.collection("users").doc("user-001").collection("cards").doc("prog-1");
    expect(cardDoc.update).toHaveBeenCalledWith(
      expect.objectContaining({ celebrationSeen: true }),
    );
  });

  it("throws internal error when card does not exist", async () => {
    const req = createMockRequest({ programId: "nonexistent" }, "user-001");
    await expect((markCelebrationSeen as any)(req)).rejects.toThrow("Unable to mark celebration as seen");
  });
});

