        this.code = code;
        this.name = "HttpsError";
      }
    },
  },
}));

import { updatePushToken } from "../callable/updatePushToken";

// ── Tests ──────────────────────────────────────────────────────────
describe("updatePushToken", () => {
  beforeEach(() => {
    jest.clearAllMocks();
    mockDb.current = createMockFirestore();
  });

  it("rejects unauthenticated calls", async () => {
    const req = createMockRequest({ token: "ExpoPushToken" });
    await expect((updatePushToken as any)(req)).rejects.toThrow("authenticated");
  });

  it("rejects missing token", async () => {
    const req = createMockRequest({}, "user-001");
    await expect((updatePushToken as any)(req)).rejects.toThrow("Missing push token");
  });

  it("rejects empty token", async () => {
    const req = createMockRequest({ token: "" }, "user-001");
    await expect((updatePushToken as any)(req)).rejects.toThrow("Missing push token");
  });

  it("saves push token to user document with merge", async () => {
    const req = createMockRequest({ token: "ExpoPushToken[abc123]" }, "user-001");
    const result = await (updatePushToken as any)(req);
    expect(result).toEqual({ success: true });

    // Verify set was called on the correct user doc
    const userDoc = mockDb.current.collection("users").doc("user-001");
    expect(userDoc.set).toHaveBeenCalledWith(
      expect.objectContaining({ expoPushToken: "ExpoPushToken[abc123]" }),
      { merge: true },
    );
  });

  it("includes server timestamp in the write", async () => {
    const req = createMockRequest({ token: "ExpoPushToken[xyz]" }, "user-002");
    await (updatePushToken as any)(req);

    const userDoc = mockDb.current.collection("users").doc("user-002");
    expect(userDoc.set).toHaveBeenCalledWith(
      expect.objectContaining({ updatedAt: "SERVER_TIMESTAMP" }),
      { merge: true },
    );
  });

  it("throws internal error when Firestore write fails", async () => {
    const userDoc = mockDb.current.collection("users").doc("user-fail");
    (userDoc.set as jest.Mock).mockRejectedValueOnce(new Error("Firestore error"));

    const req = createMockRequest({ token: "ExpoPushToken[fail]" }, "user-fail");
    await expect((updatePushToken as any)(req)).rejects.toThrow("Unable to update push token");
  });
});

