import { updateCardSettings } from "../callable/updateCardSettings";

// ── Tests ──────────────────────────────────────────────────────────
describe("updateCardSettings", () => {
  beforeEach(() => {
    jest.clearAllMocks();
    mockDb.current = createMockFirestore();
  });

  it("rejects unauthenticated calls", async () => {
    const req = createMockRequest({ programId: "prog-1", notificationsEnabled: true });
    await expect((updateCardSettings as any)(req)).rejects.toThrow("authenticated");
  });

  it("rejects missing programId", async () => {
    const req = createMockRequest({ notificationsEnabled: true }, "user-001");
    await expect((updateCardSettings as any)(req)).rejects.toThrow("Missing programId");
  });

  it("rejects empty programId", async () => {
    const req = createMockRequest({ programId: "", notificationsEnabled: true }, "user-001");
    await expect((updateCardSettings as any)(req)).rejects.toThrow("Missing programId");
  });

  it("throws not-found when card does not exist", async () => {
    const req = createMockRequest({ programId: "nonexistent", notificationsEnabled: true }, "user-001");
    await expect((updateCardSettings as any)(req)).rejects.toThrow("Loyalty card not found");
  });

  it("updates notificationsEnabled on existing card", async () => {
    mockDb.current = createMockFirestore({
      "users/user-001/cards/prog-1": { programId: "prog-1", notificationsEnabled: false },
    });

    const req = createMockRequest({ programId: "prog-1", notificationsEnabled: true }, "user-001");
    const result = await (updateCardSettings as any)(req);
    expect(result).toEqual({ success: true });

    const cardDoc = mockDb.current
      .collection("users")
      .doc("user-001")
      .collection("cards")
      .doc("prog-1");
    expect(cardDoc.update).toHaveBeenCalledWith(
      expect.objectContaining({
        notificationsEnabled: true,
        updatedAt: "SERVER_TIMESTAMP",
      }),
    );
  });

  it("does not call update when no settings are provided", async () => {
    mockDb.current = createMockFirestore({
      "users/user-001/cards/prog-1": { programId: "prog-1", notificationsEnabled: false },
    });

    const req = createMockRequest({ programId: "prog-1" }, "user-001");
    const result = await (updateCardSettings as any)(req);
    expect(result).toEqual({ success: true });

    // update should NOT have been called (no fields to update)
    const cardDoc = mockDb.current
      .collection("users")
      .doc("user-001")
      .collection("cards")
      .doc("prog-1");
    expect(cardDoc.update).not.toHaveBeenCalled();
  });

  it("can disable notifications", async () => {
    mockDb.current = createMockFirestore({
      "users/user-001/cards/prog-1": { programId: "prog-1", notificationsEnabled: true },
    });

    const req = createMockRequest({ programId: "prog-1", notificationsEnabled: false }, "user-001");
    await (updateCardSettings as any)(req);

    const cardDoc = mockDb.current
      .collection("users")
      .doc("user-001")
      .collection("cards")
      .doc("prog-1");
    expect(cardDoc.update).toHaveBeenCalledWith(
      expect.objectContaining({ notificationsEnabled: false }),
    );
  });

  it("throws internal error when Firestore update fails", async () => {
    mockDb.current = createMockFirestore({
      "users/user-fail/cards/prog-1": { programId: "prog-1", notificationsEnabled: false },
    });

    const cardDoc = mockDb.current
      .collection("users")
      .doc("user-fail")
      .collection("cards")
      .doc("prog-1");
    (cardDoc.update as jest.Mock).mockRejectedValueOnce(new Error("Firestore error"));

    const req = createMockRequest({ programId: "prog-1", notificationsEnabled: true }, "user-fail");
    await expect((updateCardSettings as any)(req)).rejects.toThrow("Unable to update card settings");
  });
});

