        super(message);
        this.code = code;
        this.name = "HttpsError";
      }
    },
  },
}));

import { getMyNotifications } from "../callable/getMyNotifications";

// ── Tests ──────────────────────────────────────────────────────────
describe("getMyNotifications", () => {
  beforeEach(() => {
    jest.clearAllMocks();
    mockDb.current = createMockFirestore();
  });

  it("rejects unauthenticated calls", async () => {
    const req = createMockRequest({});
    await expect((getMyNotifications as any)(req)).rejects.toThrow("authenticated");
  });

  it("returns empty notifications when none exist", async () => {
    mockDb.current = createMockFirestore({}, { notifications: [] });
    const req = createMockRequest({}, "user-001");
    const result = await (getMyNotifications as any)(req);

    expect(result.success).toBe(true);
    expect(result.notifications).toEqual([]);
  });

  it("returns notifications targeted at the user", async () => {
    const mockSnap = {
      exists: true,
      id: "notif-1",
      ref: { parent: { parent: null }, delete: jest.fn() },
       () => ({
        title: "Reward Earned",
        body: "You earned a stamp",
        targetUsers: ["user-001"],
        timestamp: { seconds: 1000, nanoseconds: 0 },
      }),
    };
    mockDb.current = createMockFirestore({}, { notifications: [mockSnap] });

    const req = createMockRequest({}, "user-001");
    const result = await (getMyNotifications as any)(req);

    expect(result.success).toBe(true);
    expect(result.notifications.length).toBe(1);
    expect(result.notifications[0].title).toBe("Reward Earned");
  });

  it("sorts notifications by timestamp descending", async () => {
    const older = {
      exists: true,
      id: "notif-old",
      ref: { parent: { parent: null }, delete: jest.fn() },
      data: () => ({
        title: "Old Notification",
        targetUsers: ["user-001"],
        timestamp: { seconds: 500, nanoseconds: 0 },
      }),
    };
    const newer = {
      exists: true,
      id: "notif-new",
      ref: { parent: { parent: null }, delete: jest.fn() },
       () => ({
        title: "New Notification",
        targetUsers: ["user-001"],
        timestamp: { seconds: 2000, nanoseconds: 0 },
      }),
    };
    mockDb.current = createMockFirestore({}, { notifications: [older, newer] });

    const req = createMockRequest({}, "user-001");
    const result = await (getMyNotifications as any)(req);

    expect(result.notifications[0].title).toBe("New Notification");
    expect(result.notifications[1].title).toBe("Old Notification");
  });

  it("clears unreadNotifications counter", async () => {
    mockDb.current = createMockFirestore({}, { notifications: [] });
    const req = createMockRequest({}, "user-001");
    await (getMyNotifications as any)(req);

    const userDoc = mockDb.current.collection("users").doc("user-001");
    expect(userDoc.update).toHaveBeenCalledWith({ unreadNotifications: 0 });
  });

  it("throws internal error when Firestore query fails", async () => {
    // Make the notifications collection query reject
    const notificationsCol = mockDb.current.collection("notifications");
    (notificationsCol.get as jest.Mock).mockRejectedValueOnce(new Error("Firestore error"));

    const req = createMockRequest({}, "user-001");
    await expect((getMyNotifications as any)(req)).rejects.toThrow("Unable to fetch notifications");
  });
});

