  createMockRequest,
  createDocSnap,
  mockFieldValue,
  MockFirestore,
} from "./mocks";

// ── Module mocks ───────────────────────────────────────────────────
const mockDb: { current: MockFirestore } = { current: null as any };

jest.mock("firebase-admin/firestore", () => ({
  getFirestore: () => mockDb.current,
  FieldValue: {
    serverTimestamp: () => mockFieldValue.serverTimestamp(),
    increment: (n: number) => mockFieldValue.increment(n),
  },
}));

jest.mock("firebase-functions/v2", () => ({
  https: {
    onCall: (_opts: any, handler: any) => handler,
    HttpsError: class HttpsError extends Error {
      code: string;
      constructor(code: string, message: string) {
        super(message);
        this.code = code;
        this.name = "HttpsError";
      }
    },
  },
}));

import { joinProgram } from "../callable/joinProgram";

// Helper: create a mock runTransaction that distinguishes program vs card
function mockTransactionWith(
  programSnap: ReturnType<typeof createDocSnap>,
  cardSnap: ReturnType<typeof createDocSnap>,
) {
  const txGet = jest.fn().mockImplementation((ref: any) => {
    // Distinguish by the ref path — program refs come from programs collection
    // card refs come from users/.../cards. We use the ref structure:
    // programRef = {id, _col: "programs"}, cardRef = {id, _col: "cards"}
    if (ref._col === "cards") return Promise.resolve(cardSnap);
    return Promise.resolve(programSnap);
  });
  const txSet = jest.fn();
  const txUpdate = jest.fn();
  const txDelete = jest.fn();

  const mockTransaction = { get: txGet, set: txSet, update: txUpdate, delete: txDelete };

  mockDb.current.runTransaction = jest
    .fn()
    .mockImplementation((fn: (t: typeof mockTransaction) => Promise<unknown>) => fn(mockTransaction));

  return { txGet, txSet, txUpdate, txDelete };
}

// ── Tests ──────────────────────────────────────────────────────────
describe("joinProgram", () => {
  beforeEach(() => {
    jest.clearAllMocks();
    mockDb.current = createMockFirestore();
  });

  it("rejects unauthenticated calls", async () => {
    const req = createMockRequest({ programId: "prog-1" });
    await expect((joinProgram as any)(req)).rejects.toThrow("authenticated");
  });

  it("rejects missing programId", async () => {
    const req = createMockRequest({}, "user-001");
    await expect((joinProgram as any)(req)).rejects.toThrow("Missing programId");
  });

  it("throws not-found when program does not exist", async () => {
    const programSnap = createDocSnap("nonexistent", undefined);
    const cardSnap = createDocSnap("nonexistent", undefined);
    mockTransactionWith(programSnap, cardSnap);

    const req = createMockRequest({ programId: "nonexistent" }, "user-001");
    await expect((joinProgram as any)(req)).rejects.toThrow("Loyalty program not found");
  });

  it("throws failed-precondition when program is cancelled", async () => {
    const programSnap = createDocSnap("prog-1", {
      merchantId: "merchant-1",
      subscriptionStatus: "cancelled",
    });
    const cardSnap = createDocSnap("prog-1", undefined);
    mockTransactionWith(programSnap, cardSnap);

    const req = createMockRequest({ programId: "prog-1" }, "user-001");
    await expect((joinProgram as any)(req)).rejects.toThrow("no longer active");
  });

  it("throws failed-precondition when program is expired", async () => {
    const programSnap = createDocSnap("prog-1", {
      merchantId: "merchant-1",
      subscriptionStatus: "expired",
    });
    const cardSnap = createDocSnap("prog-1", undefined);
    mockTransactionWith(programSnap, cardSnap);

    const req = createMockRequest({ programId: "prog-1" }, "user-001");
    await expect((joinProgram as any)(req)).rejects.toThrow("no longer active");
  });

  it("returns alreadyJoined when card already exists", async () => {
    const programSnap = createDocSnap("prog-1", {
      merchantId: "merchant-1",
      storeName: "Test Store",
      subscriptionStatus: "active",
      stampsToComplete: 10,
    });
    const cardSnap = createDocSnap("prog-1", { programId: "prog-1" });
    const { txSet } = mockTransactionWith(programSnap, cardSnap);

    const req = createMockRequest({ programId: "prog-1" }, "user-001");
    const result = await (joinProgram as any)(req);

    expect(result.success).toBe(true);
    expect(result.alreadyJoined).toBe(true);
    expect(txSet).not.toHaveBeenCalled();
  });

  it("creates card and increments activeUsers for new join", async () => {
    const programSnap = createDocSnap("prog-1", {
      merchantId: "merchant-1",
      storeName: "Test Store",
      subscriptionStatus: "active",
      stampsToComplete: 10,
      programType: "loyalty",
      selectedAccent: "#FF5733",
    });
    const cardSnap = createDocSnap("prog-1", undefined); // card doesn't exist
    const { txSet, txUpdate } = mockTransactionWith(programSnap, cardSnap);

    const req = createMockRequest({ programId: "prog-1" }, "user-001");
    const result = await (joinProgram as any)(req);

    expect(result.success).toBe(true);
    expect(result.alreadyJoined).toBe(false);
    expect(txSet).toHaveBeenCalled();
    expect(txUpdate).toHaveBeenCalledWith(
      expect.anything(),
      expect.objectContaining({ activeUsers: "INCREMENT(1)" }),
    );
  });

  it("includes streak fields in card when program has streak enabled", async () => {
    const programSnap = createDocSnap("prog-streak", {
      merchantId: "merchant-1",
      storeName: "Streak Store",
      subscriptionStatus: "active",
      stampsToComplete: 10,
      streakEnabled: true,
      streakTargetVisits: 5,
      streakTimeframeDays: 7,
    });
    const cardSnap = createDocSnap("prog-streak", undefined);
    const { txSet } = mockTransactionWith(programSnap, cardSnap);

    const req = createMockRequest({ programId: "prog-streak" }, "user-001");
    const result = await (joinProgram as any)(req);

    expect(result.success).toBe(true);
    // Verify the card payload includes streak fields
    const cardPayload = txSet.mock.calls[0][1];
    expect(cardPayload.streakEnabled).toBe(true);
    expect(cardPayload.streakTargetVisits).toBe(5);
    expect(cardPayload.streakTimeframeDays).toBe(7);
    expect(cardPayload.currentStreakVisits).toBe(0);
  });

  it("does not include streak fields when program has streak disabled", async () => {
    const programSnap = createDocSnap("prog-nostreak", {
      merchantId: "merchant-1",
      storeName: "No Streak Store",
      subscriptionStatus: "active",
      stampsToComplete: 10,
      streakEnabled: false,
    });
    const cardSnap = createDocSnap("prog-nostreak", undefined);
    const { txSet } = mockTransactionWith(programSnap, cardSnap);

    const req = createMockRequest({ programId: "prog-nostreak" }, "user-002");
    const result = await (joinProgram as any)(req);

    expect(result.success).toBe(true);
    const cardPayload = txSet.mock.calls[0][1];
    expect(cardPayload.streakEnabled).toBeUndefined();
    expect(cardPayload.streakTargetVisits).toBeUndefined();
  });
});

