/* eslint-disable @typescript-eslint/no-explicit-any */
import {
  createMockFirestore,
  createMockRequest,
  createDocSnap,
  createQuerySnap,
  mockFieldValue,
  MockFirestore,
} from "./mocks";

// ── Module mocks ───────────────────────────────────────────────────
const mockDb: { current: MockFirestore } = { current: null as any };

jest.mock("firebase-admin/firestore", () => ({
  getFirestore: () => mockDb.current,
  FieldValue: {
    serverTimestamp: () => mockFieldValue.serverTimestamp(),
    increment: (n: number) => mockFieldValue.increment(n),
  },
}));

jest.mock("firebase-functions/v2", () => ({
  https: {
    onCall: (_opts: any, handler: any) => handler,
    HttpsError: class HttpsError extends Error {
      code: string;
      constructor(code: string, message: string) {
        super(message);
        this.code = code;
        this.name = "HttpsError";
      }
    },
  },
}));

import { getAdminMerchants } from "../callable/getAdminMerchants";

const ADMIN_UID = "vi87NYSfdSZ8nZwEWN6GCqITJ8h1";
const ADMIN_EMAIL = "lekkerloyal@gmail.com";

// ── Tests ──────────────────────────────────────────────────────────
describe("getAdminMerchants", () => {
  beforeEach(() => {
    jest.clearAllMocks();
    mockDb.current = createMockFirestore();
  });

  it("rejects unauthenticated calls", async () => {
    const req = createMockRequest({});
    await expect((getAdminMerchants as any)(req)).rejects.toThrow("authenticated");
  });

  it("rejects non-admin users", async () => {
    const req = createMockRequest({}, "user-001", { email: "user@test.com" });
    await expect((getAdminMerchants as any)(req)).rejects.toThrow("Only admins");
  });

  it("allows access by admin UID", async () => {
    const merchantSnap = createQuerySnap([]);
    const storeSnap = createQuerySnap([]);
    const programSnap = createQuerySnap([]);

    mockDb.current = createMockFirestore({}, {
      users: [...merchantSnap.docs, ...storeSnap.docs],
      programs: programSnap.docs,
    });

    // Override the where/get chain for users collection
    const usersCol = mockDb.current.collection("users");
    (usersCol.where as jest.Mock)
      .mockReturnValueOnce({ get: jest.fn().mockResolvedValue(merchantSnap), forEach: merchantSnap.forEach })
      .mockReturnValueOnce({ get: jest.fn().mockResolvedValue(storeSnap), forEach: storeSnap.forEach });

    // Override programs collection
    const programsCol = mockDb.current.collection("programs");
    (programsCol.get as jest.Mock).mockResolvedValue(programSnap);

    const req = createMockRequest({}, ADMIN_UID, { email: "admin@test.com" });
    const result = await (getAdminMerchants as any)(req);

    expect(result.merchants).toEqual([]);
  });

  it("allows access by admin email", async () => {
    const merchantSnap = createQuerySnap([]);
    const storeSnap = createQuerySnap([]);
    const programSnap = createQuerySnap([]);

    const usersCol = mockDb.current.collection("users");
    (usersCol.where as jest.Mock)
      .mockReturnValueOnce({ get: jest.fn().mockResolvedValue(merchantSnap), forEach: merchantSnap.forEach })
      .mockReturnValueOnce({ get: jest.fn().mockResolvedValue(storeSnap), forEach: storeSnap.forEach });

    const programsCol = mockDb.current.collection("programs");
    (programsCol.get as jest.Mock).mockResolvedValue(programSnap);

    const req = createMockRequest({}, "other-user", { email: ADMIN_EMAIL });
    const result = await (getAdminMerchants as any)(req);

    expect(result.merchants).toEqual([]);
  });

  it("returns merchants with hasProgram flag", async () => {
    const merchantSnap = createQuerySnap([
      createDocSnap("merchant-1", { email: "m1@test.com", businessName: "Shop 1" }),
    ]);
    const storeSnap = createQuerySnap([]);
    const programSnap = createQuerySnap([
      createDocSnap("prog-1", { merchantId: "merchant-1" }),
    ]);

    const usersCol = mockDb.current.collection("users");
    (usersCol.where as jest.Mock)
      .mockReturnValueOnce({ get: jest.fn().mockResolvedValue(merchantSnap), forEach: merchantSnap.forEach })
      .mockReturnValueOnce({ get: jest.fn().mockResolvedValue(storeSnap), forEach: storeSnap.forEach });

    const programsCol = mockDb.current.collection("programs");
    (programsCol.get as jest.Mock).mockResolvedValue(programSnap);

    const req = createMockRequest({}, ADMIN_UID, { email: "admin@test.com" });
    const result = await (getAdminMerchants as any)(req);

    expect(result.merchants.length).toBe(1);
    expect(result.merchants[0].id).toBe("merchant-1");
    expect(result.merchants[0].hasProgram).toBe(true);
    expect(result.merchants[0].role).toBe("merchant");
  });

  it("marks merchants without programs as hasProgram false", async () => {
    const merchantSnap = createQuerySnap([
      createDocSnap("merchant-2", { email: "m2@test.com", businessName: "Shop 2" }),
    ]);
    const storeSnap = createQuerySnap([]);
    const programSnap = createQuerySnap([
      createDocSnap("prog-other", { merchantId: "other-merchant" }),
    ]);

    const usersCol = mockDb.current.collection("users");
    (usersCol.where as jest.Mock)
      .mockReturnValueOnce({ get: jest.fn().mockResolvedValue(merchantSnap), forEach: merchantSnap.forEach })
      .mockReturnValueOnce({ get: jest.fn().mockResolvedValue(storeSnap), forEach: storeSnap.forEach });

    const programsCol = mockDb.current.collection("programs");
    (programsCol.get as jest.Mock).mockResolvedValue(programSnap);

    const req = createMockRequest({}, ADMIN_UID, { email: "admin@test.com" });
    const result = await (getAdminMerchants as any)(req);

    expect(result.merchants[0].hasProgram).toBe(false);
  });

  it("includes store accounts in the list", async () => {
    const merchantSnap = createQuerySnap([]);
    const storeSnap = createQuerySnap([
      createDocSnap("store-1", { email: "s1@test.com", businessName: "Store 1" }),
    ]);
    const programSnap = createQuerySnap([
      createDocSnap("prog-1", { merchantId: "store-1" }),
    ]);

    const usersCol = mockDb.current.collection("users");
    (usersCol.where as jest.Mock)
      .mockReturnValueOnce({ get: jest.fn().mockResolvedValue(merchantSnap), forEach: merchantSnap.forEach })
      .mockReturnValueOnce({ get: jest.fn().mockResolvedValue(storeSnap), forEach: storeSnap.forEach });

    const programsCol = mockDb.current.collection("programs");
    (programsCol.get as jest.Mock).mockResolvedValue(programSnap);

    const req = createMockRequest({}, ADMIN_UID, { email: "admin@test.com" });
    const result = await (getAdminMerchants as any)(req);

    expect(result.merchants.length).toBe(1);
    expect(result.merchants[0].role).toBe("store");
    expect(result.merchants[0].hasProgram).toBe(true);
  });

  it("defaults email and businessName when missing", async () => {
    const merchantSnap = createQuerySnap([
      createDocSnap("merchant-noinfo", { role: "merchant" }),
    ]);
    const storeSnap = createQuerySnap([]);
    const programSnap = createQuerySnap([]);

    const usersCol = mockDb.current.collection("users");
    (usersCol.where as jest.Mock)
      .mockReturnValueOnce({ get: jest.fn().mockResolvedValue(merchantSnap), forEach: merchantSnap.forEach })
      .mockReturnValueOnce({ get: jest.fn().mockResolvedValue(storeSnap), forEach: storeSnap.forEach });

    const programsCol = mockDb.current.collection("programs");
    (programsCol.get as jest.Mock).mockResolvedValue(programSnap);

    const req = createMockRequest({}, ADMIN_UID, { email: "admin@test.com" });
    const result = await (getAdminMerchants as any)(req);

    expect(result.merchants[0].email).toBe("No email");
    expect(result.merchants[0].businessName).toBe("Unknown Business");
  });
});

