    // The mock shares update across all docs; override it temporarily
    const origMockUpdate = jest.fn();
    (mockDb.current.collection as jest.Mock).mockImplementationOnce((...args: any[]) => {
      const result = (originalUpdate as jest.Mock)(...args);
      const origDoc = result.doc;
      result.doc = (...docArgs: any[]) => {
